INSERT INTO subjects (name, name_ru, name_kk, description, description_ru, description_kk, icon) VALUES
('Қазақ тілі', 'Казахский язык', 'Қазақ тілі', '5-сыныпқа арналған қазақ тілі пәні. Тілдік нормалар, сөйлеу әрекеті және грамматика.', 'Предмет казахский язык для 5 класса. Языковые нормы, речевая деятельность и грамматика.', '5-сыныпқа арналған қазақ тілі пәні. Тілдік нормалар, сөйлеу әрекеті және грамматика.', 'bi-book'),
('Қазақ әдебиеті', 'Казахская литература', 'Қазақ әдебиеті', '5-сыныпқа арналған қазақ әдебиеті пәні. Ауыз әдебиеті және балалар әдебиеті.', 'Предмет казахская литература для 5 класса. Устное народное творчество и детская литература.', '5-сыныпқа арналған қазақ әдебиеті пәні. Ауыз әдебиеті және балалар әдебиеті.', 'bi-book'),
('Орыс тілі', 'Русский язык', 'Орыс тілі', '5-сыныпқа арналған орыс тілі пәні. Тілдік нормалар және сөйлеу әрекеті.', 'Предмет русский язык для 5 класса. Языковые нормы и речевая деятельность.', '5-сыныпқа арналған орыс тілі пәні. Тілдік нормалар және сөйлеу әрекеті.', 'bi-book'),
('Орыс әдебиеті', 'Русская литература', 'Орыс әдебиеті', '5-сыныпқа арналған орыс әдебиеті пәні. Орыс және әлем әдебиеті.', 'Предмет русская литература для 5 класса. Русская и мировая литература.', '5-сыныпқа арналған орыс әдебиеті пәні. Орыс және әлем әдебиеті.', 'bi-book'),
('Қазақ тілі мен әдебиеті', 'Казахский язык и литература', 'Қазақ тілі мен әдебиеті', 'Орыс мектептеріне арналған қазақ тілі мен әдебиеті пәні.', 'Предмет казахский язык и литература для русских школ.', 'Орыс мектептеріне арналған қазақ тілі мен әдебиеті пәні.', 'bi-book'),
('Ағылшын тілі', 'Английский язык', 'Ағылшын тілі', '5-сыныпқа арналған ағылшын тілі пәні. Қарым-қатынас, күнделікті өмір және грамматика.', 'Предмет английский язык для 5 класса. Общение, повседневная жизнь и грамматика.', '5-сыныпқа арналған ағылшын тілі пәні. Қарым-қатынас, күнделікті өмір және грамматика.', 'bi-globe'),
('Математика', 'Математика', 'Математика', '5-сыныпқа арналған математика пәні. Натурал сандар, бөлшектер, пайыздар.', 'Предмет математика для 5 класса. Натуральные числа, дроби, проценты.', '5-сыныпқа арналған математика пәні. Натурал сандар, бөлшектер, пайыздар.', 'bi-calculator'),
('Информатика', 'Информатика', 'Информатика', '5-сыныпқа арналған информатика пәні. Компьютер, алгоритмдер, қауіпсіздік.', 'Предмет информатика для 5 класса. Компьютер, алгоритмы, безопасность.', '5-сыныпқа арналған информатика пәні. Компьютер, алгоритмдер, қауіпсіздік.', 'bi-laptop'),
('Жаратылыстану', 'Естествознание', 'Жаратылыстану', '5-сыныпқа арналған жаратылыстану пәні. Ғылым, заттар, тірі табиғат.', 'Предмет естествознание для 5 класса. Наука, вещества, живая природа.', '5-сыныпқа арналған жаратылыстану пәні. Ғылым, заттар, тірі табиғат.', 'bi-flower1'),
('Қазақстан тарихы', 'История Казахстана', 'Қазақстан тарихы', '5-сыныпқа арналған қазақстан тарихы пәні. Ежелгі Қазақстан, көшпелілер мәдениеті.', 'Предмет история Казахстана для 5 класса. Древний Казахстан, культура кочевников.', '5-сыныпқа арналған қазақстан тарихы пәні. Ежелгі Қазақстан, көшпелілер мәдениеті.', 'bi-flag'),
('Дүниежүзі тарихы', 'Всемирная история', 'Дүниежүзі тарихы', '5-сыныпқа арналған дүниежүзі тарихы пәні. Ежелгі өркениеттер.', 'Предмет всемирная история для 5 класса. Древние цивилизации.', '5-сыныпқа арналған дүниежүзі тарихы пәні. Ежелгі өркениеттер.', 'bi-globe2'),
('Музыка', 'Музыка', 'Музыка', '5-сыныпқа арналған музыка пәні. Музыкалық жанрлар, қазақ және әлем музыкасы.', 'Предмет музыка для 5 класса. Музыкальные жанры, казахская и мировая музыка.', '5-сыныпқа арналған музыка пәні. Музыкалық жанрлар, қазақ және әлем музыкасы.', 'bi-music-note-beamed'),
('Көркем еңбек', 'Художественный труд', 'Көркем еңбек', '5-сыныпқа арналған көркем еңбек пәні. Бейнелеу өнері, қолөнер, дизайн.', 'Предмет художественный труд для 5 класса. ИЗО, рукоделие, дизайн.', '5-сыныпқа арналған көркем еңбек пәні. Бейнелеу өнері, қолөнер, дизайн.', 'bi-palette'),
('Дене шынықтыру', 'Физическая культура', 'Дене шынықтыру', '5-сыныпқа арналған дене шынықтыру пәні. Спорт, гимнастика, ойындар.', 'Предмет физическая культура для 5 класса. Спорт, гимнастика, игры.', '5-сыныпқа арналған дене шынықтыру пәні. Спорт, гимнастика, ойындар.', 'bi-activity');
