INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(1, 'Тыңдалым және сөйлеу', 'Аудирование и говорение', 'Тыңдалым және сөйлеу', 'Бұл тақырыпта оқушылар тыңдалым және сөйлеу дағдыларын дамытады. Мәтіндерді тыңдап, мазмұнын түсінуге және өз ойын ауызша жеткізуге үйренеді. Сұрақтарға жауап беру және диалог құру дағдылары қалыптасады.', 'В этой теме учащиеся развивают навыки аудирования и говорения. Учатся понимать содержание прослушанных текстов и устно выражать свои мысли. Формируются навыки ответов на вопросы и составления диалогов.', 'Бұл тақырыпта оқушылар тыңдалым және сөйлеу дағдыларын дамытады. Мәтіндерді тыңдап, мазмұнын түсінуге және өз ойын ауызша жеткізуге үйренеді. Сұрақтарға жауап беру және диалог құру дағдылары қалыптасады.', 'Мәтінді тыңдап, сұрақтарға жауап бер: «Балалар табиғатта не көрді?» Өз сөзіңмен 2-3 сөйлем құрап жаз.', 'Прослушайте текст и ответьте на вопросы: «Что дети увидели в природе?» Составьте 2-3 предложения своими словами.', 'Мәтінді тыңдап, сұрақтарға жауап бер: «Балалар табиғатта не көрді?» Өз сөзіңмен 2-3 сөйлем құрап жаз.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+тыңдалым+және+сөйлеу'),
(1, 'Оқылым', 'Чтение', 'Оқылым', 'Оқушылар мәтінді дауыстап және іштей оқу дағдыларын жетілдіреді. Мәтіннің негізгі идеясын анықтап, мазмұнын түсінуге үйренеді. Түрлі жанрдағы мәтіндермен жұмыс істеу дағдысы қалыптасады.', 'Учащиеся совершенствуют навыки чтения вслух и про себя. Учатся определять основную идею текста и понимать его содержание. Формируются навыки работы с текстами различных жанров.', 'Оқушылар мәтінді дауыстап және іштей оқу дағдыларын жетілдіреді. Мәтіннің негізгі идеясын анықтап, мазмұнын түсінуге үйренеді. Түрлі жанрдағы мәтіндермен жұмыс істеу дағдысы қалыптасады.', 'Мәтінді мәнерлеп оқы. Негізгі кейіпкерлерді ата. Мәтінге ат қой және не туралы екенін бір сөйлеммен жаз.', 'Прочитайте текст выразительно. Назовите главных героев. Озаглавьте текст и напишите одним предложением, о чем он.', 'Мәтінді мәнерлеп оқы. Негізгі кейіпкерлерді ата. Мәтінге ат қой және не туралы екенін бір сөйлеммен жаз.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+оқылым'),
(1, 'Жазылым', 'Письмо', 'Жазылым', 'Бұл тақырыпта оқушылар жазбаша сөйлеу дағдыларын дамытады. Сөйлемдерді дұрыс құрап, мәтіндерді жоспар бойынша жазуға үйренеді. Шығарма жазу элементтерімен танысады.', 'В этой теме учащиеся развивают навыки письменной речи. Учатся правильно строить предложения и писать тексты по плану. Знакомятся с элементами написания сочинений.', 'Бұл тақырыпта оқушылар жазбаша сөйлеу дағдыларын дамытады. Сөйлемдерді дұрыс құрап, мәтіндерді жоспар бойынша жазуға үйренеді. Шығарма жазу элементтерімен танысады.', '«Менің сүйікті ісім» тақырыбына 5-6 сөйлемнен тұратын мәтін жаз. Жоспарды қолдан: 1) Кіріспе, 2) Негізгі бөлім, 3) Қорытынды.', 'Напишите текст из 5-6 предложений на тему «Моё любимое занятие». Используйте план: 1) Вступление, 2) Основная часть, 3) Заключение.', '«Менің сүйікті ісім» тақырыбына 5-6 сөйлемнен тұратын мәтін жаз. Жоспарды қолдан: 1) Кіріспе, 2) Негізгі бөлім, 3) Қорытынды.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+жазылым');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(2, 'Фонетика. Дыбыс және әріп', 'Фонетика. Звук и буква', 'Фонетика. Дыбыс және әріп', 'Оқушылар дыбыс пен әріптің айырмашылығын түсінеді. Дауысты және дауыссыз дыбыстарды ажыратып, буын түрлерімен танысады. Фонетикалық талдау жасау дағдысы қалыптасады.', 'Учащиеся понимают различие между звуком и буквой. Различают гласные и согласные звуки, знакомятся с видами слогов. Формируется навык фонетического разбора.', 'Оқушылар дыбыс пен әріптің айырмашылығын түсінеді. Дауысты және дауыссыз дыбыстарды ажыратып, буын түрлерімен танысады. Фонетикалық талдау жасау дағдысы қалыптасады.', '«Мектеп» сөзіне фонетикалық талдау жаса: дыбыстар санын, дауысты/дауыссыз дыбыстарды анықта. Сөзде неше буын бар?', 'Сделайте фонетический разбор слова «Мектеп»: определите количество звуков, гласные/согласные звуки. Сколько слогов в слове?', '«Мектеп» сөзіне фонетикалық талдау жаса: дыбыстар санын, дауысты/дауыссыз дыбыстарды анықта. Сөзде неше буын бар?', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+фонетика+дыбыс+және+әріп'),
(2, 'Лексика. Сөздің лексикалық мағынасы', 'Лексика. Лексическое значение слова', 'Лексика. Сөздің лексикалық мағынасы', 'Бұл тақырыпта оқушылар сөздердің лексикалық мағынасын анықтауды үйренеді. Көп мағыналы сөздермен, синонимдермен және антонимдермен танысады. Сөздік қорын байыту дағдысы қалыптасады.', 'В этой теме учащиеся учатся определять лексическое значение слов. Знакомятся с многозначными словами, синонимами и антонимами. Формируется навык обогащения словарного запаса.', 'Бұл тақырыпта оқушылар сөздердің лексикалық мағынасын анықтауды үйренеді. Көп мағыналы сөздермен, синонимдермен және антонимдермен танысады. Сөздік қорын байыту дағдысы қалыптасады.', '«Жаңа» сөзіне синоним және антоним тап. «Тіл» сөзінің көп мағынасын түсіндіріп, екі сөйлем құра.', 'Подберите синоним и антоним к слову «жаңа» (новый). Объясните многозначность слова «тіл» (язык), составьте два предложения.', '«Жаңа» сөзіне синоним және антоним тап. «Тіл» сөзінің көп мағынасын түсіндіріп, екі сөйлем құра.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+лексика+сөз+мағынасы'),
(2, 'Сөз таптары: зат есім', 'Части речи: имя существительное', 'Сөз таптары: зат есім', 'Оқушылар зат есімнің мағынасын, оның жіктелуі мен септелуін үйренеді. Жалқы және жалпы есімдерді ажырата білу дағдысы қалыптасады. Зат есімнің түрлері мен грамматикалық категориялары меңгертіледі.', 'Учащиеся изучают значение имени существительного, его склонение и спряжение. Формируется навык различения собственных и нарицательных имен. Осваиваются виды и грамматические категории существительного.', 'Оқушылар зат есімнің мағынасын, оның жіктелуі мен септелуін үйренеді. Жалқы және жалпы есімдерді ажырата білу дағдысы қалыптасады. Зат есімнің түрлері мен грамматикалық категориялары меңгертіледі.', 'Берілген сөздердің ішінен жалқы және жалпы есімдерді теріп жаз: Астана, мектеп, Асан, кітап, Қазақстан, қала. Зат есімдерді септе.', 'Выпишите из данных слов собственные и нарицательные имена существительные: Астана, мектеп, Асан, кітап, Қазақстан, қала. Просклоняйте существительные.', 'Берілген сөздердің ішінен жалқы және жалпы есімдерді теріп жаз: Астана, мектеп, Асан, кітап, Қазақстан, қала. Зат есімдерді септе.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+зат+есім'),
(2, 'Сөз таптары: сын есім', 'Части речи: имя прилагательное', 'Сөз таптары: сын есім', 'Бұл тақырыпта оқушылар сын есімнің мағынасы мен түрлерін үйренеді. Сын есімдердің зат есіммен байланысын түсініп, сапалық және қатыстық сын есімдерді ажыратады.', 'В этой теме учащиеся изучают значение и виды имени прилагательного. Понимают связь прилагательного с существительным, различают качественные и относительные прилагательные.', 'Бұл тақырыпта оқушылар сын есімнің мағынасы мен түрлерін үйренеді. Сын есімдердің зат есіммен байланысын түсініп, сапалық және қатыстық сын есімдерді ажыратады.', 'Суреттегі заттарға сипаттама бер: үлкен үй, кішкентай доп, қызыл гүл, биік ағаш. Әр затқа 2-3 сын есім таңда.', 'Дайте описание предметов на картинке: большой дом, маленький мяч, красный цветок, высокое дерево. Подберите к каждому предмету 2-3 прилагательных.', 'Суреттегі заттарға сипаттама бер: үлкен үй, кішкентай доп, қызыл гүл, биік ағаш. Әр затқа 2-3 сын есім таңда.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+сын+есім'),
(2, 'Сөз таптары: етістік', 'Части речи: глагол', 'Сөз таптары: етістік', 'Оқушылар етістік және оның шақтарымен танысады. Етістіктің болымды және болымсыз түрлерін ажыратып, сөйлемде дұрыс қолдануға үйренеді. Етістіктің жасалу жолдары меңгертіледі.', 'Учащиеся знакомятся с глаголом и его временами. Учатся различать утвердительную и отрицательную формы глагола, правильно употреблять их в предложении. Изучают способы образования глаголов.', 'Оқушылар етістік және оның шақтарымен танысады. Етістіктің болымды және болымсыз түрлерін ажыратып, сөйлемде дұрыс қолдануға үйренеді. Етістіктің жасалу жолдары меңгертіледі.', '«Оқу» етістігін үш шақта жаз: өткен шақ (оқыды), осы шақ (оқып отыр), келер шақ (оқиды). Әр шақпен сөйлем құра.', 'Запишите глагол «оқу» (читать) в трех временах: прошедшее (читал), настоящее (читает), будущее (будет читать). Составьте предложение с каждым временем.', '«Оқу» етістігін үш шақта жаз: өткен шақ (оқыды), осы шақ (оқып отыр), келер шақ (оқиды). Әр шақпен сөйлем құра.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+етістік+шақтары'),
(2, 'Сөз таптары: сан есім', 'Части речи: имя числительное', 'Сөз таптары: сан есім', 'Бұл тақырыпта сан есімнің мағыналық түрлері қарастырылады. Есептік және реттік сан есімдерді ажыратуға, оларды сөйлемде дұрыс қолдануға үйренеді. Сан есімнің септелуі меңгертіледі.', 'В этой теме рассматриваются смысловые виды имени числительного. Учатся различать количественные и порядковые числительные, правильно употреблять их в предложении. Изучается склонение числительных.', 'Бұл тақырыпта сан есімнің мағыналық түрлері қарастырылады. Есептік және реттік сан есімдерді ажыратуға, оларды сөйлемде дұрыс қолдануға үйренеді. Сан есімнің септелуі меңгертіледі.', 'Берілген сандарды сөзбен жаз: 5, 12, 25, 100. Есептік және реттік сан есімдерге үш мысалдан келтір.', 'Запишите словами числа: 5, 12, 25, 100. Приведите по три примера количественных и порядковых числительных.', 'Берілген сандарды сөзбен жаз: 5, 12, 25, 100. Есептік және реттік сан есімдерге үш мысалдан келтір.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+сан+есім'),
(2, 'Сөз таптары: үстеу', 'Части речи: наречие', 'Сөз таптары: үстеу', 'Оқушылар үстеудің мағыналық түрлерімен танысады. Үстеулердің сөйлемдегі қызметін түсініп, мезгіл, мекен, сын-қимыл және басқа үстеу түрлерін ажыратады.', 'Учащиеся знакомятся со смысловыми видами наречий. Понимают роль наречий в предложении, различают наречия времени, места, образа действия и другие виды.', 'Оқушылар үстеудің мағыналық түрлерімен танысады. Үстеулердің сөйлемдегі қызметін түсініп, мезгіл, мекен, сын-қимыл және басқа үстеу түрлерін ажыратады.', 'Сөйлемдегі үстеулерді тап: «Біз ертең саяхатқа барамыз. Ол тез жүгірді. Ағаштар жоғары өсіп тұр.» Үстеулердің түрін анықта.', 'Найдите наречия в предложениях: «Мы завтра поедем в путешествие. Он быстро побежал. Деревья растут высоко.» Определите вид наречий.', 'Сөйлемдегі үстеулерді тап: «Біз ертең саяхатқа барамыз. Ол тез жүгірді. Ағаштар жоғары өсіп тұр.» Үстеулердің түрін анықта.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+үстеу'),
(2, 'Сөз тіркесі және сөйлем', 'Словосочетание и предложение', 'Сөз тіркесі және сөйлем', 'Бұл тақырыпта сөз тіркесі мен сөйлемнің құрылымы қарастырылады. Оқушылар сөз тіркестерін сөйлемнен ажыратып, сөйлемнің бас және толықтауыш мүшелерін анықтауға үйренеді.', 'В этой теме рассматривается структура словосочетания и предложения. Учатся выделять словосочетания из предложения, определять главные и второстепенные члены предложения.', 'Бұл тақырыпта сөз тіркесі мен сөйлемнің құрылымы қарастырылады. Оқушылар сөз тіркестерін сөйлемнен ажыратып, сөйлемнің бас және толықтауыш мүшелерін анықтауға үйренеді.', 'Сөйлемдегі сөз тіркестерін теріп жаз: «Күн жарқырап тұр. Балалар әдемі бақта ойнап жүр.» Бастауыш пен баяндауышты ата.', 'Выпишите словосочетания из предложения: «Солнце ярко светит. Дети играют в красивом саду.» Назовите подлежащее и сказуемое.', 'Сөйлемдегі сөз тіркестерін теріп жаз: «Күн жарқырап тұр. Балалар әдемі бақта ойнап жүр.» Бастауыш пен баяндауышты ата.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+сөз+тіркесі+және+сөйлем'),
(2, 'Мәтін және оның түрлері', 'Текст и его виды', 'Мәтін және оның түрлері', 'Оқушылар мәтін түрлерімен және олардың құрылымымен танысады. Әңгімелеу, сипаттау және пайымдау мәтіндерін ажыратуға үйренеді. Мәтіннің құрылымдық бөліктерін анықтайды.', 'Учащиеся знакомятся с видами текста и их структурой. Учатся различать повествование, описание и рассуждение. Определяют структурные части текста.', 'Оқушылар мәтін түрлерімен және олардың құрылымымен танысады. Әңгімелеу, сипаттау және пайымдау мәтіндерін ажыратуға үйренеді. Мәтіннің құрылымдық бөліктерін анықтайды.', 'Берілген мәтіннің түрін анықта: «Бүгін мен мектепке бардым. Сабақ қызықты өтті. Үйге келіп, үй тапсырмасын орындадым.» Мәтіннің кіріспе, негізгі және қорытынды бөлімін тап.', 'Определите вид текста: «Сегодня я пошел в школу. Урок прошел интересно. Пришел домой и выполнил домашнее задание.» Найдите вступление, основную часть и заключение.', 'Берілген мәтіннің түрін анықта: «Бүгін мен мектепке бардым. Сабақ қызықты өтті. Үйге келіп, үй тапсырмасын орындадым.» Мәтіннің кіріспе, негізгі және қорытынды бөлімін тап.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+тілі+мәтін+және+оның+түрлері');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(3, 'Ертегілер', 'Сказки', 'Ертегілер', 'Оқушылар қазақ халық ертегілерінің түрлерімен танысады. Ертегілердің құрылымын, кейіпкерлерін және тәрбиелік мәнін түсінеді. Халық даналығы мен қиял-ғажайып әлеміне саяхат жасайды.', 'Учащиеся знакомятся с видами казахских народных сказок. Понимают структуру сказок, их героев и воспитательное значение. Совершают путешествие в мир народной мудрости и фантазии.', 'Оқушылар қазақ халық ертегілерінің түрлерімен танысады. Ертегілердің құрылымын, кейіпкерлерін және тәрбиелік мәнін түсінеді. Халық даналығы мен қиял-ғажайып әлеміне саяхат жасайды.', '«Ер Төстік» ертегісін оқы. Ертегінің басы, ортасы және соңы қалай басталып, аяқталады? Басты кейіпкерлерді сипаттап жаз.', 'Прочитайте сказку «Ер Төстік». Как начинается и заканчивается сказка? Опишите главных героев.', '«Ер Төстік» ертегісін оқы. Ертегінің басы, ортасы және соңы қалай басталып, аяқталады? Басты кейіпкерлерді сипаттап жаз.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+ертегілері'),
(3, 'Мақал-мәтелдер', 'Пословицы и поговорки', 'Мақал-мәтелдер', 'Бұл тақырыпта мақал-мәтелдердің мағынасы мен қолданылу аясы қарастырылады. Оқушылар халықтың тәлім-тәрбиелік мәні бар қанатты сөздерін түсініп, орынды қолдануға үйренеді.', 'В этой теме рассматривается значение и сфера употребления пословиц и поговорок. Учащиеся понимают воспитательное значение народных изречений и учатся уместно их использовать.', 'Бұл тақырыпта мақал-мәтелдердің мағынасы мен қолданылу аясы қарастырылады. Оқушылар халықтың тәлім-тәрбиелік мәні бар қанатты сөздерін түсініп, орынды қолдануға үйренеді.', '«Еңбек түбі – береке» мақалының мағынасын түсіндір. Осы мақалға ұқсас тағы екі мақал жаз және оларды сөйлемде қолдан.', 'Объясните смысл пословицы «Еңбек түбі – береке» (В основе труда — благополучие). Напишите еще две похожие пословицы и употребите их в предложениях.', '«Еңбек түбі – береке» мақалының мағынасын түсіндір. Осы мақалға ұқсас тағы екі мақал жаз және оларды сөйлемде қолдан.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+мақал-мәтелдер'),
(3, 'Жұмбақтар', 'Загадки', 'Жұмбақтар', 'Оқушылар жұмбақтардың түрлері мен құрылымымен танысады. Жұмбақтарды шешіп, өздері жұмбақ құрастыруға үйренеді. Халық ауыз әдебиетінің осы жанрының ерекшелігін түсінеді.', 'Учащиеся знакомятся с видами и структурой загадок. Учатся отгадывать и самостоятельно составлять загадки. Понимают особенности этого жанра устного народного творчества.', 'Оқушылар жұмбақтардың түрлері мен құрылымымен танысады. Жұмбақтарды шешіп, өздері жұмбақ құрастыруға үйренеді. Халық ауыз әдебиетінің осы жанрының ерекшелігін түсінеді.', 'Берілген жұмбақты шеш: «Алтын таяқ, басы жоқ, ортасында оты бар?» (Күнбағыс). Өзің бір жұмбақ құрастырып жаз.', 'Отгадайте загадку: «Золотая палка без головы, а в середине огонь?» (Подсолнух). Составьте свою загадку.', 'Берілген жұмбақты шеш: «Алтын таяқ, басы жоқ, ортасында оты бар?» (Күнбағыс). Өзің бір жұмбақ құрастырып жаз.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+жұмбақтар'),
(3, 'Аңыздар мен мифтер', 'Легенды и мифы', 'Аңыздар мен мифтер', 'Бұл тақырыпта қазақ халқының аңыздары мен мифтері қарастырылады. Оқушылар ежелгі наным-сенімдер мен аңыздық кейіпкерлермен танысады. Аңыздардың шығу тарихын түсінеді.', 'В этой теме рассматриваются легенды и мифы казахского народа. Учащиеся знакомятся с древними верованиями и легендарными героями. Понимают историю возникновения легенд.', 'Бұл тақырыпта қазақ халқының аңыздары мен мифтері қарастырылады. Оқушылар ежелгі наным-сенімдер мен аңыздық кейіпкерлермен танысады. Аңыздардың шығу тарихын түсінеді.', '«Қорқыт ата туралы аңызды» оқы. Қорқыт ата кім болған? Аңызда не туралы айтылады? Аңыздың басты идеясын бір сөйлеммен жаз.', 'Прочитайте легенду о Коркыт ата. Кем был Коркыт ата? О чем рассказывается в легенде? Напишите главную идею легенды одним предложением.', '«Қорқыт ата туралы аңызды» оқы. Қорқыт ата кім болған? Аңызда не туралы айтылады? Аңыздың басты идеясын бір сөйлеммен жаз.', 'https://www.youtube.com/results?search_query=5+сынып+қазақ+аңыздары+мен+мифтері');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(4, 'Ы. Алтынсарин шығармалары', 'Произведения Ы. Алтынсарина', 'Ы. Алтынсарин шығармалары', 'Оқушылар Ыбырай Алтынсариннің өмірі мен шығармашылығымен танысады. Оның балаларға арналған әңгімелері мен мысалдарын оқып, тәрбиелік мәнін түсінеді.', 'Учащиеся знакомятся с жизнью и творчеством Ыбырая Алтынсарина. Читают его рассказы и притчи для детей, понимают их воспитательное значение.', 'Оқушылар Ыбырай Алтынсариннің өмірі мен шығармашылығымен танысады. Оның балаларға арналған әңгімелері мен мысалдарын оқып, тәрбиелік мәнін түсінеді.', 'Ы. Алтынсариннің «Әке мен бала» әңгімесін оқы. Әңгіменің негізгі идеясын анықта. «Балаға еңбектен артық мұра жоқ» деген сөзді қалай түсінесің?', 'Прочитайте рассказ Ы. Алтынсарина «Отец и сын». Определите основную идею рассказа. Как вы понимаете слова «Нет лучшего наследства для ребенка, чем труд»?', 'Ы. Алтынсариннің «Әке мен бала» әңгімесін оқы. Әңгіменің негізгі идеясын анықта. «Балаға еңбектен артық мұра жоқ» деген сөзді қалай түсінесің?', 'https://www.youtube.com/results?search_query=Ыбырай+Алтынсарин+5+сынып'),
(4, 'А. Байтұрсынұлы шығармалары', 'Произведения А. Байтурсынулы', 'А. Байтұрсынұлы шығармалары', 'Бұл тақырыпта оқушылар Ахмет Байтұрсынұлының балаларға арналған шығармаларымен танысады. Ақынның өлеңдері мен әңгімелерін оқып, тіл тазалығы мен ұлттық тәрбие туралы түсінеді.', 'В этой теме учащиеся знакомятся с произведениями Ахмета Байтурсынулы для детей. Читают стихи и рассказы поэта, понимают ценность языковой чистоты и национального воспитания.', 'Бұл тақырыпта оқушылар Ахмет Байтұрсынұлының балаларға арналған шығармаларымен танысады. Ақынның өлеңдері мен әңгімелерін оқып, тіл тазалығы мен ұлттық тәрбие туралы түсінеді.', 'А. Байтұрсынұлының «Оқу» өлеңін оқы. Өлеңде оқудың қандай пайдасы туралы айтылған? Өлеңнен 3 маңызды ойды көшіріп жаз.', 'Прочитайте стихотворение А. Байтурсынулы «Оқу» (Учеба). О какой пользе учебы говорится в стихотворении? Выпишите 3 важные мысли из стихотворения.', 'А. Байтұрсынұлының «Оқу» өлеңін оқы. Өлеңде оқудың қандай пайдасы туралы айтылған? Өлеңнен 3 маңызды ойды көшіріп жаз.', 'https://www.youtube.com/results?search_query=Ахмет+Байтұрсынұлы+5+сынып'),
(4, 'М. Әуезов шығармалары', 'Произведения М. Ауэзова', 'М. Әуезов шығармалары', 'Оқушылар Мұхтар Әуезовтің балаларға арналған әңгімелерімен танысады. Жазушының шығармалары арқылы достық, адалдық және еңбексүйгіштік құндылықтарын түсінеді.', 'Учащиеся знакомятся с рассказами Мухтара Ауэзова для детей. Через произведения писателя понимают ценности дружбы, честности и трудолюбия.', 'Оқушылар Мұхтар Әуезовтің балаларға арналған әңгімелерімен танысады. Жазушының шығармалары арқылы достық, адалдық және еңбексүйгіштік құндылықтарын түсінеді.', 'М. Әуезовтің «Көксерек» әңгімесінің үзіндісін оқы. Қасқыр мен Ержан арасындағы қарым-қатынасты сипатта. Әңгімедегі табиғат суреттерін тап.', 'Прочитайте отрывок из рассказа М. Ауэзова «Көксерек». Опишите отношения между волком и Ержаном. Найдите в рассказе описания природы.', 'М. Әуезовтің «Көксерек» әңгімесінің үзіндісін оқы. Қасқыр мен Ержан арасындағы қарым-қатынасты сипатта. Әңгімедегі табиғат суреттерін тап.', 'https://www.youtube.com/results?search_query=Мұхтар+Әуезов+5+сынып'),
(4, 'Қазіргі қазақ балалар ақындары', 'Современные казахские детские поэты', 'Қазіргі қазақ балалар ақындары', 'Бұл тақырыпта қазіргі қазақ балалар ақындарының шығармалары қарастырылады. Оқушылар заманауи балалар поэзиясымен танысып, өлеңдерді мәнерлеп оқу дағдысын дамытады.', 'В этой теме рассматриваются произведения современных казахских детских поэтов. Учащиеся знакомятся с современной детской поэзией, развивают навыки выразительного чтения стихов.', 'Бұл тақырыпта қазіргі қазақ балалар ақындарының шығармалары қарастырылады. Оқушылар заманауи балалар поэзиясымен танысып, өлеңдерді мәнерлеп оқу дағдысын дамытады.', 'М. Жаманбалиновтың «Балалар әлемі» өлеңін оқы. Өлеңнің ырғағы мен ұйқасын анықта. Өлеңдегі ең ұнаған шумақты жаттап ал.', 'Прочитайте стихотворение М. Жаманбалинова «Мир детей». Определите ритм и рифму стихотворения. Выучите понравившееся четверостишие.', 'М. Жаманбалиновтың «Балалар әлемі» өлеңін оқы. Өлеңнің ырғағы мен ұйқасын анықта. Өлеңдегі ең ұнаған шумақты жаттап ал.', 'https://www.youtube.com/results?search_query=қазіргі+қазақ+балалар+ақындары+5+сынып');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(5, 'Әдебиеттің негізгі жанрлары', 'Основные жанры литературы', 'Әдебиеттің негізгі жанрлары', 'Оқушылар әдебиеттің негізгі жанрларымен танысады: ертегі, поэма, роман, повесть, әңгіме және мысал. Әр жанрдың ерекшеліктерін ажыратып, шығармаларды жанрлық талдау дағдысын дамытады.', 'Учащиеся знакомятся с основными жанрами литературы: сказка, поэма, роман, повесть, рассказ и басня. Учатся различать особенности каждого жанра, развивают навыки жанрового анализа произведений.', 'Оқушылар әдебиеттің негізгі жанрларымен танысады: ертегі, поэма, роман, повесть, әңгіме және мысал. Әр жанрдың ерекшеліктерін ажыратып, шығармаларды жанрлық талдау дағдысын дамытады.', 'Берілген шығармалардың жанрын анықта: «Қобыланды батыр» (жыр), «Алтын сақа» (ертегі), «Көксерек» (әңгіме). Әр жанрға бір-бір сипаттама бер.', 'Определите жанр произведений: «Қобыланды батыр» (поэма), «Золотое кольцо» (сказка), «Көксерек» (рассказ). Дайте по одному определению для каждого жанра.', 'Берілген шығармалардың жанрын анықта: «Қобыланды батыр» (жыр), «Алтын сақа» (ертегі), «Көксерек» (әңгіме). Әр жанрға бір-бір сипаттама бер.', 'https://www.youtube.com/results?search_query=5+сынып+әдебиет+жанрлары'),
(5, 'Көркемдегіш құралдар', 'Изобразительные средства', 'Көркемдегіш құралдар', 'Бұл тақырыпта көркемдегіш құралдар: теңеу, эпитет, метафора қарастырылады. Оқушылар бейнелі сөздер мен тіркестерді мәтіннен тауып, олардың қолданылу мақсатын түсінеді.', 'В этой теме рассматриваются изобразительные средства: сравнение, эпитет, метафора. Учащиеся находят образные слова и выражения в тексте, понимают цель их использования.', 'Бұл тақырыпта көркемдегіш құралдар: теңеу, эпитет, метафора қарастырылады. Оқушылар бейнелі сөздер мен тіркестерді мәтіннен тауып, олардың қолданылу мақсатын түсінеді.', '«Ай бетінде бұлттар жүзіп жүр» сөйлемінен эпитет пен метафораны тап. Өзің 2 сөйлем құрап, теңеу мен эпитетті қолдан.', 'Найдите эпитет и метафору в предложении «По лицу луны плывут облака». Составьте 2 своих предложения, используя сравнение и эпитет.', '«Ай бетінде бұлттар жүзіп жүр» сөйлемінен эпитет пен метафораны тап. Өзің 2 сөйлем құрап, теңеу мен эпитетті қолдан.', 'https://www.youtube.com/results?search_query=5+сынып+көркемдегіш+құралдар');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(6, 'Аудирование и говорение', 'Аудирование и говорение', 'Тыңдалым және сөйлеу', 'В этой теме учащиеся развивают навыки аудирования и говорения на русском языке. Учатся понимать содержание прослушанных текстов, отвечать на вопросы и составлять устные высказывания.', 'В этой теме учащиеся развивают навыки аудирования и говорения на русском языке. Учатся понимать содержание прослушанных текстов, отвечать на вопросы и составлять устные высказывания.', 'Бұл тақырыпта оқушылар орыс тілінде тыңдалым және сөйлеу дағдыларын дамытады. Тыңдалған мәтіндердің мазмұнын түсінуге, сұрақтарға жауап беруге және ауызша мәтін құрауға үйренеді.', 'Прослушайте текст «Осень в лесу». Ответьте на вопросы: Какое время года описано? Какие изменения происходят в природе? Перескажите текст в 3-4 предложениях.', 'Прослушайте текст «Осень в лесу». Ответьте на вопросы: Какое время года описано? Какие изменения происходят в природе? Перескажите текст в 3-4 предложениях.', '«Ормандағы күз» мәтінін тыңда. Сұрақтарға жауап бер: Қандай жыл мезгілі сипатталған? Табиғатта қандай өзгерістер болады? Мәтінді 3-4 сөйлеммен баянда.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+аудирование+и+говорение'),
(6, 'Чтение', 'Чтение', 'Оқылым', 'Учащиеся совершенствуют навыки чтения на русском языке. Учатся понимать содержание текста, определять главную мысль, отвечать на вопросы по прочитанному. Развивают технику чтения.', 'Учащиеся совершенствуют навыки чтения на русском языке. Учатся понимать содержание текста, определять главную мысль, отвечать на вопросы по прочитанному. Развивают технику чтения.', 'Оқушылар орыс тілінде оқу дағдыларын жетілдіреді. Мәтін мазмұнын түсінуге, негізгі ойды анықтауға, оқылған бойынша сұрақтарға жауап беруге үйренеді. Оқу техникасын дамытады.', 'Прочитайте текст «Мой любимый город». Определите основную мысль текста. Выпишите 3 незнакомых слова и объясните их значение. Придумайте заголовок к тексту.', 'Прочитайте текст «Мой любимый город». Определите основную мысль текста. Выпишите 3 незнакомых слова и объясните их значение. Придумайте заголовок к тексту.', '«Менің сүйікті қалам» мәтінін оқы. Мәтіннің негізгі ойын анықта. 3 таныс емес сөзді теріп, мағынасын түсіндір. Мәтінге ат қой.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+чтение'),
(6, 'Письмо', 'Письмо', 'Жазылым', 'В этой теме учащиеся развивают навыки письменной речи на русском языке. Учатся правильно писать слова, составлять предложения и небольшие тексты на заданные темы.', 'В этой теме учащиеся развивают навыки письменной речи на русском языке. Учатся правильно писать слова, составлять предложения и небольшие тексты на заданные темы.', 'Бұл тақырыпта оқушылар орыс тілінде жазбаша сөйлеу дағдыларын дамытады. Сөздерді дұрыс жазуға, сөйлемдер мен шағын мәтіндер құрауға үйренеді.', 'Напишите сочинение из 5-6 предложений на тему «Моя семья». Используйте план: 1) Состав семьи, 2) Обязанности каждого, 3) Наши традиции.', 'Напишите сочинение из 5-6 предложений на тему «Моя семья». Используйте план: 1) Состав семьи, 2) Обязанности каждого, 3) Наши традиции.', '«Менің отбасым» тақырыбына 5-6 сөйлемнен тұратын шығарма жаз. Жоспарды қолдан: 1) Отбасы құрамы, 2) Әрқайсысының міндеті, 3) Біздің дәстүрлер.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+письмо');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(7, 'Лексика. Слово и его значение', 'Лексика. Слово и его значение', 'Лексика. Сөз және оның мағынасы', 'Учащиеся изучают лексическое значение слов, однозначные и многозначные слова. Знакомятся с синонимами, антонимами и омонимами. Учатся пользоваться толковым словарем.', 'Учащиеся изучают лексическое значение слов, однозначные и многозначные слова. Знакомятся с синонимами, антонимами и омонимами. Учатся пользоваться толковым словарем.', 'Оқушылар сөздердің лексикалық мағынасын, бір мағыналы және көп мағыналы сөздерді үйренеді. Синонимдер, антонимдер және омонимдермен танысады. Түсіндірме сөздікті пайдалануға үйренеді.', 'Подберите синонимы к словам: красивый, большой, идти. Подберите антонимы: светлый, начало, радость. Составьте предложение с каждым антонимом.', 'Подберите синонимы к словам: красивый, большой, идти. Подберите антонимы: светлый, начало, радость. Составьте предложение с каждым антонимом.', 'Сөздерге синонимдер тап: әдемі, үлкен, бару. Антонимдер тап: жарық, басы, қуаныш. Әр антониммен сөйлем құра.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+лексика+слово+и+его+значение'),
(7, 'Состав слова и словообразование', 'Состав слова и словообразование', 'Сөз құрамы және сөзжасам', 'Учащиеся изучают состав слова: корень, приставка, суффикс, окончание. Учатся разбирать слова по составу и образовывать новые слова с помощью приставок и суффиксов.', 'Учащиеся изучают состав слова: корень, приставка, суффикс, окончание. Учатся разбирать слова по составу и образовывать новые слова с помощью приставок и суффиксов.', 'Оқушылар сөз құрамын: түбір, қосымша, жұрнақ, жалғауды үйренеді. Сөздерді құрамына қарай талдауға және қосымшалар арқылы жаңа сөздер жасауға үйренеді.', 'Разберите слова по составу: подберёзовик, перелесок, придорожный. Выделите корень, приставку, суффикс и окончание. Образуйте 2 новых слова с приставкой при-.', 'Разберите слова по составу: подберёзовик, перелесок, придорожный. Выделите корень, приставку, суффикс и окончание. Образуйте 2 новых слова с приставкой при-.', 'Сөздерді құрамына қарай талда: подберёзовик, перелесок, придорожный. Түбір, қосымша, жұрнақ, жалғауды ажырат. «При-» қосымшасымен 2 жаңа сөз жаса.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+состав+слова'),
(7, 'Имя существительное', 'Имя существительное', 'Зат есім', 'Учащиеся изучают имя существительное: род, число, падеж. Учатся определять склонение существительных, правильно употреблять падежные окончания. Различают собственные и нарицательные имена.', 'Учащиеся изучают имя существительное: род, число, падеж. Учатся определять склонение существительных, правильно употреблять падежные окончания. Различают собственные и нарицательные имена.', 'Оқушылар зат есімді үйренеді: род, число, септік. Зат есімдердің септелуін анықтап, септік жалғауларын дұрыс қолдануға үйренеді. Жалқы және жалпы есімдерді ажыратады.', 'Определите род, число и падеж существительных: на столе, у реки, под окном. Просклоняйте слово «зима». Составьте предложение с этим словом в родительном падеже.', 'Определите род, число и падеж существительных: на столе, у реки, под окном. Просклоняйте слово «зима». Составьте предложение с этим словом в родительном падеже.', 'Зат есімдердің родын, санын, септігін анықта: на столе, у реки, под окном. «Зима» сөзін септе. Осы сөзбен ілік септігінде сөйлем құра.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+имя+существительное'),
(7, 'Имя прилагательное', 'Имя прилагательное', 'Сын есім', 'Учащиеся изучают имя прилагательное: разряды (качественные, относительные, притяжательные). Учатся согласовывать прилагательные с существительными в роде, числе и падеже.', 'Учащиеся изучают имя прилагательное: разряды (качественные, относительные, притяжательные). Учатся согласовывать прилагательные с существительными в роде, числе и падеже.', 'Оқушылар сын есімді үйренеді: сапалық, қатыстық, тәуелдік. Сын есімдерді зат есімдермен род, число, септікте сәйкестендіруге үйренеді.', 'Определите разряд прилагательных: красивый цветок, деревянный дом, мамин платок. Составьте словосочетания, согласуя прилагательные с существительными: летний (ночь), свежий (молоко).', 'Определите разряд прилагательных: красивый цветок, деревянный дом, мамин платок. Составьте словосочетания, согласуя прилагательные с существительными: летний (ночь), свежий (молоко).', 'Сын есімдердің түрін анықта: красивый цветок, деревянный дом, мамин платок. Сын есімдерді зат есімдермен сәйкестендіріп тіркес құра: летний (ночь), свежий (молоко).', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+имя+прилагательное'),
(7, 'Глагол', 'Глагол', 'Етістік', 'Учащиеся изучают глагол: время, лицо, число, спряжение. Учатся определять спряжение глаголов, правильно писать личные окончания. Знакомятся с неопределенной формой глагола.', 'Учащиеся изучают глагол: время, лицо, число, спряжение. Учатся определять спряжение глаголов, правильно писать личные окончания. Знакомятся с неопределенной формой глагола.', 'Оқушылар етістікті үйренеді: шақ, жақ, сан, жіктелу. Етістіктердің жіктелуін анықтап, жіктік жалғауларын дұрыс жазуға үйренеді. Етістіктің болымсыз түрімен танысады.', 'Определите время глаголов: читает, написал, будет играть. Поставьте глагол «идти» в 1, 2, 3 лицо единственного числа. Определите спряжение.', 'Определите время глаголов: читает, написал, будет играть. Поставьте глагол «идти» в 1, 2, 3 лицо единственного числа. Определите спряжение.', 'Етістіктердің шағын анықта: читает, написал, будет играть. «Идти» етістігін жекеше 1, 2, 3 жаққа қой. Жіктелуін анықта.', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+глагол'),
(7, 'Синтаксис и пунктуация', 'Синтаксис и пунктуация', 'Синтаксис және тыныс белгілері', 'Учащиеся изучают основные правила синтаксиса и пунктуации. Учатся различать главные и второстепенные члены предложения, правильно расставлять знаки препинания в простых и сложных предложениях.', 'Учащиеся изучают основные правила синтаксиса и пунктуации. Учатся различать главные и второстепенные члены предложения, правильно расставлять знаки препинания в простых и сложных предложениях.', 'Оқушылар синтаксис және пунктуацияның негізгі ережелерін үйренеді. Сөйлемнің бас және толықтауыш мүшелерін ажыратып, жай және құрмалас сөйлемдерде тыныс белгілерін дұрыс қоюға үйренеді.', 'Подчеркните главные члены предложения: «Солнце ярко светит над городом. Птицы поют в саду.» Расставьте знаки препинания: «Наступила осень и листья пожелтели».', 'Подчеркните главные члены предложения: «Солнце ярко светит над городом. Птицы поют в саду.» Расставьте знаки препинания: «Наступила осень и листья пожелтели».', 'Сөйлемнің бас мүшелерін астын сызу арқылы көрсет: «Солнце ярко светит над городом. Птицы поют в саду.» Тыныс белгілерін қой: «Наступила осень и листья пожелтели».', 'https://www.youtube.com/results?search_query=5+класс+русский+язык+синтаксис+и+пунктуация');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(8, 'Русские народные сказки', 'Русские народные сказки', 'Орыс халық ертегілері', 'Учащиеся знакомятся с русскими народными сказками, их видами (волшебные, бытовые, о животных). Понимают структуру сказки, учатся анализировать поступки героев и определять мораль.', 'Учащиеся знакомятся с русскими народными сказками, их видами (волшебные, бытовые, о животных). Понимают структуру сказки, учатся анализировать поступки героев и определять мораль.', 'Оқушылар орыс халық ертегілерімен, олардың түрлерімен (ғажайып, тұрмыстық, хайуанаттар туралы) танысады. Ертегі құрылымын түсініп, кейіпкерлердің іс-әрекетін талдауға және моральды анықтауға үйренеді.', 'Прочитайте русскую народную сказку «Царевна-лягушка». Определите вид сказки. Назовите главных героев. Какая главная мысль сказки? Найдите волшебные предметы и превращения.', 'Прочитайте русскую народную сказку «Царевна-лягушка». Определите вид сказки. Назовите главных героев. Какая главная мысль сказки? Найдите волшебные предметы и превращения.', '«Царевна-лягушка» орыс халық ертегісін оқы. Ертегінің түрін анықта. Басты кейіпкерлерді ата. Ертегінің негізгі ойы қандай? Сиқырлы заттар мен түрленулерді тап.', 'https://www.youtube.com/results?search_query=5+класс+русские+народные+сказки'),
(8, 'Малые жанры фольклора', 'Малые жанры фольклора', 'Фольклордың шағын жанрлары', 'Учащиеся знакомятся с малыми жанрами русского фольклора: пословицы, поговорки, загадки, скороговорки, считалки. Учатся понимать их значение и уместно использовать в речи.', 'Учащиеся знакомятся с малыми жанрами русского фольклора: пословицы, поговорки, загадки, скороговорки, считалки. Учатся понимать их значение и уместно использовать в речи.', 'Оқушылар орыс фольклорының шағын жанрларымен: мақал, мәтел, жұмбақ, жаңылтпаш, санамақтармен танысады. Олардың мағынасын түсініп, сөйлеуде орынды қолдануға үйренеді.', 'Объясните смысл пословицы «Без труда не выловишь и рыбку из пруда». Приведите 2-3 пословицы о труде. Отгадайте загадку: «Зимой и летом одним цветом» (ель).', 'Объясните смысл пословицы «Без труда не выловишь и рыбку из пруда». Приведите 2-3 пословицы о труде. Отгадайте загадку: «Зимой и летом одним цветом» (ель).', '«Без труда не выловишь и рыбку из пруда» мақалының мағынасын түсіндір. Еңбек туралы 2-3 мақал келтір. Жұмбақты шеш: «Зимой и летом одним цветом» (шырша).', 'https://www.youtube.com/results?search_query=5+класс+малые+жанры+фольклора');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(9, 'А.С. Пушкин. Сказки', 'А.С. Пушкин. Сказки', 'А.С. Пушкин. Ертегілер', 'Учащиеся знакомятся со сказками А.С. Пушкина. Читают и анализируют «Сказку о мертвой царевне и о семи богатырях» или «Сказку о царе Салтане». Учатся понимать язык и художественные особенности пушкинских сказок.', 'Учащиеся знакомятся со сказками А.С. Пушкина. Читают и анализируют «Сказку о мертвой царевне и о семи богатырях» или «Сказку о царе Салтане». Учатся понимать язык и художественные особенности пушкинских сказок.', 'Оқушылар А.С. Пушкиннің ертегілерімен танысады. «Өлі ханшайым мен жеті батыр туралы ертегіні» немесе «Салтан патша туралы ертегіні» оқып, талдайды. Пушкин ертегілерінің тілі мен көркемдік ерекшелігін түсінеді.', 'Прочитайте отрывок из «Сказки о мертвой царевне». Найдите описание царевны. Какие эпитеты использует автор? Выпишите 3 устаревших слова и объясните их значение.', 'Прочитайте отрывок из «Сказки о мертвой царевне». Найдите описание царевны. Какие эпитеты использует автор? Выпишите 3 устаревших слова и объясните их значение.', '«Өлі ханшайым туралы ертегіден» үзінді оқы. Ханшайымның сипаттамасын тап. Автор қандай эпитеттер қолданады? 3 ескірген сөзді теріп, мағынасын түсіндір.', 'https://www.youtube.com/results?search_query=5+класс+Пушкин+сказки'),
(9, 'И.А. Крылов. Басни', 'И.А. Крылов. Басни', 'И.А. Крылов. Мысалдар', 'Учащиеся знакомятся с баснями И.А. Крылова. Читают и анализируют басни «Ворона и Лисица», «Волк и Ягненок». Учатся определять мораль басни и понимать аллегорию.', 'Учащиеся знакомятся с баснями И.А. Крылова. Читают и анализируют басни «Ворона и Лисица», «Волк и Ягненок». Учатся определять мораль басни и понимать аллегорию.', 'Оқушылар И.А. Крыловтың мысалдарымен танысады. «Қарға мен түлкі», «Қасқыр мен қозы» мысалдарын оқып, талдайды. Мысалдың моральін анықтауға және астарлы мағынаны түсінуге үйренеді.', 'Прочитайте басню «Ворона и Лисица». Какие человеческие пороки высмеивает автор? Выучите наизусть мораль басни. Придумайте свою ситуацию, где проявляется лесть.', 'Прочитайте басню «Ворона и Лисица». Какие человеческие пороки высмеивает автор? Выучите наизусть мораль басни. Придумайте свою ситуацию, где проявляется лесть.', '«Қарға мен түлкі» мысалын оқы. Автор қандай адамдық кемшіліктерді әжуа етеді? Мысалдың моральін жаттап ал. Еліктеу көрінетін өз жағдайыңды ойлап тап.', 'https://www.youtube.com/results?search_query=5+класс+Крылов+басни');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(10, 'К. Паустовский. Рассказы', 'К. Паустовский. Рассказы', 'К. Паустовский. Әңгімелер', 'Учащиеся знакомятся с рассказами К.Г. Паустовского. Читают произведения «Заячьи лапы», «Корзина с еловыми шишками» или «Растрепанный воробей». Учатся понимать красоту природы и человеческих отношений.', 'Учащиеся знакомятся с рассказами К.Г. Паустовского. Читают произведения «Заячьи лапы», «Корзина с еловыми шишками» или «Растрепанный воробей». Учатся понимать красоту природы и человеческих отношений.', 'Оқушылар К.Г. Паустовскийдің әңгімелерімен танысады. «Қоян табандары», «Шырша бүрлерінің себеті» немесе «Тозған торғай» шығармаларын оқиды. Табиғаттың сұлулығы мен адамдар арасындағы қарым-қатынасты түсінуге үйренеді.', 'Прочитайте рассказ «Заячьи лапы». Почему рассказ так называется? Как автор описывает природу? Найдите эпизод, который вас особенно тронул, и объясните почему.', 'Прочитайте рассказ «Заячьи лапы». Почему рассказ так называется? Как автор описывает природу? Найдите эпизод, который вас особенно тронул, и объясните почему.', '«Қоян табандары» әңгімесін оқы. Әңгіме неге осылай аталады? Автор табиғатты қалай сипаттайды? Сізді ерекше әсерлендірген эпизодты тауып, неге екенін түсіндір.', 'https://www.youtube.com/results?search_query=5+класс+Паустовский+рассказы'),
(10, 'М. Пришвин. Рассказы о природе', 'М. Пришвин. Рассказы о природе', 'М. Пришвин. Табиғат туралы әңгімелер', 'Учащиеся знакомятся с рассказами М.М. Пришвина о природе. Читают произведения «Кладовая солнца», «Лисичкин хлеб» или «Золотой луг». Учатся видеть красоту родной природы через художественное слово.', 'Учащиеся знакомятся с рассказами М.М. Пришвина о природе. Читают произведения «Кладовая солнца», «Лисичкин хлеб» или «Золотой луг». Учатся видеть красоту родной природы через художественное слово.', 'Оқушылар М.М. Пришвиннің табиғат туралы әңгімелерімен танысады. «Күннің қоймасы», «Түлкінің наны» немесе «Алтын шалғын» шығармаларын оқиды. Көркем сөз арқылы туған табиғаттың сұлулығын көруге үйренеді.', 'Прочитайте рассказ «Золотой луг». Как автор описывает одуванчики? Почему луг назван золотым? Найдите в тексте сравнения. Нарисуйте словесную иллюстрацию к этому рассказу.', 'Прочитайте рассказ «Золотой луг». Как автор описывает одуванчики? Почему луг назван золотым? Найдите в тексте сравнения. Нарисуйте словесную иллюстрацию к этому рассказу.', '«Алтын шалғын» әңгімесін оқы. Автор бақбақтарды қалай сипаттайды? Шалғын неге алтын деп аталған? Мәтіннен теңеулерді тап. Осы әңгімеге ауызша сурет сал.', 'https://www.youtube.com/results?search_query=5+класс+Пришвин+рассказы+о+природе');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(11, 'Аудирование и говорение', 'Аудирование и говорение', 'Тыңдалым және айтылым', 'На данном занятии учащиеся развивают навыки аудирования и говорения на казахском языке. Учатся понимать простые тексты на казахском языке, задавать вопросы и отвечать на них в диалогической форме.', 'На данном занятии учащиеся развивают навыки аудирования и говорения на казахском языке. Учатся понимать простые тексты на казахском языке, задавать вопросы и отвечать на них в диалогической форме.', 'Осы сабақта оқушылар қазақ тілінде тыңдалым және сөйлеу дағдыларын дамытады. Қазақ тіліндегі қарапайым мәтіндерді түсінуге, сұрақтар қоюға және диалог түрінде жауап беруге үйренеді.', 'Прослушайте диалог о школе. Ответьте на вопросы: Как зовут героев? В каком классе они учатся? Составьте свой диалог на тему «Знакомство» на казахском языке, используя фразы приветствия.', 'Прослушайте диалог о школе. Ответьте на вопросы: Как зовут героев? В каком классе они учатся? Составьте свой диалог на тему «Знакомство» на казахском языке, используя фразы приветствия.', 'Мектеп туралы диалогты тыңда. Сұрақтарға жауап бер: Кейіпкерлердің есімі кім? Олар нешінші сыныпта оқиды? «Танысу» тақырыбына қазақ тілінде өз диалогіңді құра, сәлемдесу сөздерін қолдан.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+тыңдалым+және+айтылым'),
(11, 'Чтение', 'Чтение', 'Оқылым', 'Учащиеся совершенствуют навыки чтения на казахском языке. Учатся читать простые тексты, понимать их содержание, отвечать на вопросы и выделять основную мысль прочитанного текста.', 'Учащиеся совершенствуют навыки чтения на казахском языке. Учатся читать простые тексты, понимать их содержание, отвечать на вопросы и выделять основную мысль прочитанного текста.', 'Оқушылар қазақ тілінде оқу дағдыларын жетілдіреді. Қарапайым мәтіндерді оқып, мазмұнын түсінуге, сұрақтарға жауап беруге және мәтіннің негізгі ойын анықтауға үйренеді.', 'Прочитайте текст «Менің отбасым» на казахском языке. Сколько человек в семье? Как зовут каждого члена семьи? Выпишите незнакомые слова и переведите их на русский язык.', 'Прочитайте текст «Менің отбасым» (Моя семья) на казахском языке. Сколько человек в семье? Как зовут каждого члена семьи? Выпишите незнакомые слова и переведите их на русский язык.', '«Менің отбасым» мәтінін қазақ тілінде оқы. Отбасында неше адам бар? Әр отбасы мүшесінің есімі кім? Таныс емес сөздерді теріп, орыс тіліне аудар.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+оқылым'),
(11, 'Письмо', 'Письмо', 'Жазылым', 'В этой теме учащиеся развивают навыки письма на казахском языке. Учатся правильно писать слова, составлять простые предложения и короткие тексты на знакомые темы.', 'В этой теме учащиеся развивают навыки письма на казахском языке. Учатся правильно писать слова, составлять простые предложения и короткие тексты на знакомые темы.', 'Бұл тақырыпта оқушылар қазақ тілінде жазу дағдыларын дамытады. Сөздерді дұрыс жазуға, қарапайым сөйлемдер мен таныс тақырыптарға қысқа мәтіндер құрауға үйренеді.', 'Напишите на казахском языке письмо другу (5-6 предложений). Расскажите о своей школе. Используйте слова: мектеп, сынып, мұғалім, сабақ, достар. Проверьте правильность написания окончаний.', 'Напишите на казахском языке письмо другу (5-6 предложений). Расскажите о своей школе. Используйте слова: мектеп, сынып, мұғалім, сабақ, достар. Проверьте правильность написания окончаний.', 'Қазақ тілінде досыңа хат жаз (5-6 сөйлем). Өз мектебің туралы айтып бер. Сөздерді қолдан: мектеп, сынып, мұғалім, сабақ, достар. Жалғаулардың дұрыс жазылуын тексер.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+жазылым');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(12, 'Словарный запас. Тематическая лексика', 'Словарный запас. Тематическая лексика', 'Сөздік қор. Тақырыптық лексика', 'Учащиеся расширяют словарный запас на казахском языке по темам «Школа», «Семья», «Еда», «Одежда». Учатся правильно использовать новые слова в речи и составлять тематические мини-диалоги.', 'Учащиеся расширяют словарный запас на казахском языке по темам «Школа», «Семья», «Еда», «Одежда». Учатся правильно использовать новые слова в речи и составлять тематические мини-диалоги.', 'Оқушылар «Мектеп», «Отбасы», «Тамақ», «Киім» тақырыптары бойынша қазақ тіліндегі сөздік қорын кеңейтеді. Жаңа сөздерді сөйлеуде дұрыс қолдануға және тақырыптық мини-диалогтар құрауға үйренеді.', 'Составьте словарик из 10 слов на тему «Тағамдар» (Еда) на казахском языке: нан, сүт, ет, шай, қант, т.б. Составьте 3 предложения с этими словами. Спросите у соседа по парте: «Сен не жейсің?»', 'Составьте словарик из 10 слов на тему «Тағамдар» (Еда) на казахском языке: нан, сүт, ет, шай, қант, т.б. Составьте 3 предложения с этими словами. Спросите у соседа по парте: «Сен не жейсің?»', '«Тағамдар» тақырыбына қазақ тілінде 10 сөзден тұратын сөздік құра: нан, сүт, ет, шай, қант, т.б. Осы сөздермен 3 сөйлем құра. Көршіңнен: «Сен не жейсің?» деп сұра.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+лексика'),
(12, 'Имя существительное', 'Имя существительное', 'Зат есім', 'Учащиеся изучают имя существительное в казахском языке: его падежи, принадлежность (тәуелдік категориясы). Учатся правильно употреблять падежные окончания и притяжательные формы.', 'Учащиеся изучают имя существительное в казахском языке: его падежи, принадлежность (тәуелдік категориясы). Учатся правильно употреблять падежные окончания и притяжательные формы.', 'Оқушылар қазақ тіліндегі зат есімді үйренеді: септіктер, тәуелдік категориясы. Септік жалғаулары мен тәуелдік жалғауларын дұрыс қолдануға үйренеді.', 'Просклоняйте слово «мектеп» по падежам. Образуйте притяжательные формы: менің мектебім, сенің мектебің, оның мектебі. Составьте предложение в барыс септік (дательный падеж).', 'Просклоняйте слово «мектеп» по падежам. Образуйте притяжательные формы: менің мектебім, сенің мектебің, оның мектебі. Составьте предложение в барыс септік (дательный падеж).', '«Мектеп» сөзін септе. Тәуелдік формаларды жаз: менің мектебім, сенің мектебің, оның мектебі. Барыс септігінде сөйлем құра.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+зат+есім+септіктер'),
(12, 'Имя прилагательное', 'Имя прилагательное', 'Сын есім', 'Учащиеся изучают имя прилагательное в казахском языке: образование прилагательных, степени сравнения. Учатся согласовывать прилагательные с существительными.', 'Учащиеся изучают имя прилагательное в казахском языке: образование прилагательных, степени сравнения. Учатся согласовывать прилагательные с существительными.', 'Оқушылар қазақ тіліндегі сын есімді үйренеді: сын есімнің жасалуы, шырай түрлері. Сын есімдерді зат есімдермен сәйкестендіруге үйренеді.', 'Образуйте прилагательные от слов: қала → қалалық, тау → ..., көл → ..., ағаш → .... Переведите на казахский: высокий дом, красивая природа, вкусный хлеб. Составьте 2 предложения.', 'Образуйте прилагательные от слов: қала → қалалық (городской), тау → ..., көл → ..., ағаш → .... Переведите на казахский: высокий дом, красивая природа, вкусный хлеб. Составьте 2 предложения.', 'Сөздерден сын есім жаса: қала → қалалық, тау → ..., көл → ..., ағаш → .... Қазақ тіліне аудар: биік үй, әдемі табиғат, дәмді нан. 2 сөйлем құра.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+сын+есім'),
(12, 'Глагол', 'Глагол', 'Етістік', 'Учащиеся изучают глагол в казахском языке: времена глагола (өткен шақ, осы шақ, келер шақ), спряжение, утвердительная и отрицательная формы. Учатся правильно строить предложения с глаголами.', 'Учащиеся изучают глагол в казахском языке: времена глагола (өткен шақ, осы шақ, келер шақ), спряжение, утвердительная и отрицательная формы. Учатся правильно строить предложения с глаголами.', 'Оқушылар қазақ тіліндегі етістікті үйренеді: шақтар (өткен шақ, осы шақ, келер шақ), жіктелу, болымды және болымсыз формалар. Етістіктермен сөйлемдерді дұрыс құрауға үйренеді.', 'Поставьте глагол «жазу» (писать) в трех временах: өткен шақ (жаздым), осы шақ (жазып отырмын), келер шақ (жазамын). Образуйте отрицательную форму: жазбадым, жазып отырған жоқпын, жазбаймын. Составьте предложение в будущем времени.', 'Поставьте глагол «жазу» (писать) в трех временах: өткен шақ (жаздым), осы шақ (жазып отырмын), келер шақ (жазамын). Образуйте отрицательную форму: жазбадым, жазып отырған жоқпын, жазбаймын. Составьте предложение в будущем времени.', '«Жазу» етістігін үш шақта жаз: өткен шақ (жаздым), осы шақ (жазып отырмын), келер шақ (жазамын). Болымсыз формасын жаз: жазбадым, жазып отырған жоқпын, жазбаймын. Келер шақта сөйлем құра.', 'https://www.youtube.com/results?search_query=қазақ+тілі+5+сынып+етістік+шақтары');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(13, 'Казахские сказки', 'Казахские сказки', 'Қазақ ертегілері', 'Учащиеся знакомятся с казахскими народными сказками на русском языке. Читают и анализируют сказки «Алдар-Косе», «Ер-Тостик». Сравнивают их с русскими народными сказками.', 'Учащиеся знакомятся с казахскими народными сказками на русском языке. Читают и анализируют сказки «Алдар-Косе», «Ер-Тостик». Сравнивают их с русскими народными сказками.', 'Оқушылар орыс тіліндегі қазақ халық ертегілерімен танысады. «Алдар-Көсе», «Ер Төстік» ертегілерін оқып, талдайды. Оларды орыс халық ертегілерімен салыстырады.', 'Прочитайте казахскую народную сказку «Алдар-Косе». Опишите характер главного героя. Чем Алдар-Косе похож на героев русских народных сказок? Чем отличается? Нарисуйте иллюстрацию к сказке.', 'Прочитайте казахскую народную сказку «Алдар-Косе». Опишите характер главного героя. Чем Алдар-Косе похож на героев русских народных сказок? Чем отличается? Нарисуйте иллюстрацию к сказке.', '«Алдар-Көсе» қазақ халық ертегісін оқы. Басты кейіпкердің мінезін сипатта. Алдар-Көсе орыс халық ертегілерінің кейіпкерлеріне қалай ұқсайды? Неге ұқсамайды? Ертегіге сурет сал.', 'https://www.youtube.com/results?search_query=қазақ+ертегілері+5+сынып'),
(13, 'Пословицы и поговорки', 'Пословицы и поговорки', 'Мақал-мәтелдер', 'Учащиеся знакомятся с казахскими пословицами и поговорками в переводе на русский язык. Понимают их смысл, учатся сравнивать с русскими пословицами и использовать в речи.', 'Учащиеся знакомятся с казахскими пословицами и поговорками в переводе на русский язык. Понимают их смысл, учатся сравнивать с русскими пословицами и использовать в речи.', 'Оқушылар орыс тіліне аударылған қазақ мақал-мәтелдерімен танысады. Олардың мағынасын түсініп, орыс мақалдарымен салыстыруға және сөйлеуде қолдануға үйренеді.', 'Объясните смысл казахской пословицы «Бірлік бар жерде — тірлік бар» (Где единство — там и жизнь). Найдите русскую пословицу, близкую по смыслу. Составьте рассказ по этой пословице.', 'Объясните смысл казахской пословицы «Бірлік бар жерде — тірлік бар» (Где единство — там и жизнь). Найдите русскую пословицу, близкую по смыслу. Составьте рассказ по этой пословице.', '«Бірлік бар жерде — тірлік бар» мақалының мағынасын түсіндір. Мағынасы жақын орыс мақалын тап. Осы мақал бойынша әңгіме құра.', 'https://www.youtube.com/results?search_query=қазақ+мақал-мәтелдер+5+сынып'),
(13, 'Рассказы Ы. Алтынсарина', 'Рассказы Ы. Алтынсарина', 'Ы. Алтынсарин әңгімелері', 'Учащиеся знакомятся с рассказами Ыбырая Алтынсарина в переводе на русский язык. Читают и анализируют произведения, понимают их воспитательное значение. Сравнивают с произведениями русских писателей.', 'Учащиеся знакомятся с рассказами Ыбырая Алтынсарина в переводе на русский язык. Читают и анализируют произведения, понимают их воспитательное значение. Сравнивают с произведениями русских писателей.', 'Оқушылар орыс тіліне аударылған Ыбырай Алтынсариннің әңгімелерімен танысады. Шығармаларды оқып, талдайды, олардың тәрбиелік мәнін түсінеді. Орыс жазушыларының шығармаларымен салыстырады.', 'Прочитайте рассказ Ы. Алтынсарина «Паук и муравей» (Өрмекші мен құмырсқа). Какую черту характера осуждает автор? Чему учит эта история? Перескажите от имени муравья.', 'Прочитайте рассказ Ы. Алтынсарина «Паук и муравей» (Өрмекші мен құмырсқа). Какую черту характера осуждает автор? Чему учит эта история? Перескажите от имени муравья.', 'Ы. Алтынсариннің «Өрмекші мен құмырсқа» әңгімесін оқы. Автор қандай мінезді айыптайды? Бұл әңгіме неге үйретеді? Құмырсқаның атынан баяндап бер.', 'https://www.youtube.com/results?search_query=Ыбырай+Алтынсарин+әңгімелері+5+сынып'),
(13, 'Рассказы М. Ауэзова', 'Рассказы М. Ауэзова', 'М. Әуезов әңгімелері', 'Учащиеся знакомятся с рассказами Мухтара Ауэзова в переводе на русский язык. Читают отрывки из произведений, учатся понимать характеры героев и красоту казахской природы.', 'Учащиеся знакомятся с рассказами Мухтара Ауэзова в переводе на русский язык. Читают отрывки из произведений, учатся понимать характеры героев и красоту казахской природы.', 'Оқушылар орыс тіліне аударылған Мұхтар Әуезовтің әңгімелерімен танысады. Шығармалардан үзінділер оқып, кейіпкерлердің мінезін және қазақ табиғатының сұлулығын түсінуге үйренеді.', 'Прочитайте отрывок из рассказа М. Ауэзова «Сирога» (Көксерек). Как автор описывает волчонка? Какие чувства вызывает у вас этот отрывок? Выпишите 5 прилагательных, описывающих природу.', 'Прочитайте отрывок из рассказа М. Ауэзова «Сирога» (Көксерек). Как автор описывает волчонка? Какие чувства вызывает у вас этот отрывок? Выпишите 5 прилагательных, описывающих природу.', 'М. Әуезовтің «Көксерек» әңгімесінен үзінді оқы. Автор бөлтірікті қалай сипаттайды? Бұл үзінді сізде қандай сезім тудырады? Табиғатты сипаттайтын 5 сын есім теріп жаз.', 'https://www.youtube.com/results?search_query=Мұхтар+Әуезов+5+сынып+әңгімелері');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(14, 'Greetings and Introductions', 'Greetings and Introductions', 'Сәлемдесу және танысу', 'In this topic students learn basic greetings and introductions in English. They practice saying hello, goodbye, introducing themselves, and asking simple questions about names and feelings.', 'В этой теме учащиеся изучают базовые приветствия и представление на английском языке. Они практикуют приветствия, прощание, представление себя и простые вопросы об имени и настроении.', 'Бұл тақырыпта оқушылар ағылшын тілінде сәлемдесу мен танысудың негіздерін үйренеді. Сәлемдесу, қоштасу, өзін таныстыру және есім мен көңіл-күй туралы қарапайым сұрақтар қоюды жаттықтырады.', 'Complete the dialogue: A: «Hello! What is your name?» B: «____! My name is ____.» A: «How are you?» B: «I am ____, thank you.» Practice with a partner. Write 3 new greetings.', 'Заполните диалог: A: «Hello! What is your name?» B: «____! My name is ____.» A: «How are you?» B: «I am ____, thank you.» Разыграйте с партнером. Напишите 3 новых приветствия.', 'Диалогты толтыр: A: «Hello! What is your name?» B: «____! My name is ____.» A: «How are you?» B: «I am ____, thank you.» Жұптасып сөйлесіңдер. 3 жаңа амандасу сөзін жаз.', 'https://www.youtube.com/results?search_query=5+grade+english+greetings+and+introductions'),
(14, 'My Family and Friends', 'My Family and Friends', 'Менің отбасым және достарым', 'Students learn to describe family members and friends in English. They study vocabulary for family relations, use possessive adjectives and form simple sentences about people close to them.', 'Учащиеся учатся описывать членов семьи и друзей на английском языке. Изучают лексику родственных отношений, используют притяжательные прилагательные и составляют простые предложения о близких людях.', 'Оқушылар ағылшын тілінде отбасы мүшелері мен достарын сипаттауды үйренеді. Туыстық қатынас лексикасын, тәуелдік сын есімдерді үйреніп, жақын адамдар туралы қарапайым сөйлемдер құрайды.', 'Write 5 sentences about your family: «My mother is a doctor. She is kind. My father is tall. My brother is 10 years old.» Draw your family tree and label it in English.', 'Напишите 5 предложений о своей семье: «My mother is a doctor. She is kind. My father is tall. My brother is 10 years old.» Нарисуйте семейное дерево и подпишите его на английском.', 'Отбасың туралы 5 сөйлем жаз: «My mother is a doctor. She is kind. My father is tall. My brother is 10 years old.» Отбасыңның ағашын салып, ағылшынша белгіле.', 'https://www.youtube.com/results?search_query=5+grade+english+my+family+and+friends'),
(14, 'My School', 'My School', 'Менің мектебім', 'Students learn to talk about their school, subjects, and daily routine at school in English. They study school-related vocabulary and practice asking and answering questions about school life.', 'Учащиеся учатся рассказывать о своей школе, предметах и распорядке дня в школе на английском языке. Изучают школьную лексику и практикуют вопросы и ответы о школьной жизни.', 'Оқушылар ағылшын тілінде мектеп, пәндер және мектептегі күн тәртібі туралы айтуды үйренеді. Мектеп лексикасын үйреніп, мектеп өмірі туралы сұрақтар мен жауаптарды жаттықтырады.', 'Answer the questions: «What is your favourite subject?» «When do you have Math?» «Who is your English teacher?» Write your school timetable in English for Monday.', 'Ответьте на вопросы: «What is your favourite subject?» «When do you have Math?» «Who is your English teacher?» Напишите свое школьное расписание на английском на понедельник.', 'Сұрақтарға жауап бер: «What is your favourite subject?» «When do you have Math?» «Who is your English teacher?» Дүйсенбіге өз мектеп кестеңді ағылшынша жаз.', 'https://www.youtube.com/results?search_query=5+grade+english+my+school');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(15, 'Daily Routine', 'Daily Routine', 'Күн тәртібі', 'Students learn to describe their daily routine in English using Present Simple tense. They study time expressions and sequence adverbs to talk about what they do every day.', 'Учащиеся учатся описывать свой распорядок дня на английском, используя настоящее простое время. Изучают выражения времени и наречия последовательности для рассказа о повседневных делах.', 'Оқушылар ағылшын тілінде Present Simple шағын қолданып күн тәртібін сипаттауды үйренеді. Уақыт көрсеткіштері мен іс-әрекет ретін білдіретін үстеулерді үйреніп, күнделікті істері туралы айтады.', 'Write your daily routine: «I wake up at 7 o''clock. I have breakfast at 7:30. I go to school at 8 o''clock.» Answer: What do you do in the morning? Use: first, then, after that.', 'Напишите свой распорядок дня: «Я просыпаюсь в 7 часов. Завтракаю в 7:30. Иду в школу в 8 часов.» Ответьте: Что ты делаешь утром? Используйте: сначала, затем, после этого.', 'Өз күн тәртібіңді жаз: «I wake up at 7 o''clock. I have breakfast at 7:30. I go to school at 8 o''clock.» Таңертең не істейсің? Сөздерді қолдан: first, then, after that.', 'https://www.youtube.com/results?search_query=5+grade+english+daily+routine'),
(15, 'Food and Drinks', 'Food and Drinks', 'Тағамдар мен сусындар', 'Students learn vocabulary for food, drinks, and ordering in English. They study countable and uncountable nouns, practice ordering food in a restaurant and expressing likes and dislikes.', 'Учащиеся изучают лексику еды, напитков и заказа на английском. Знакомятся с исчисляемыми и неисчисляемыми существительными, практикуют заказ еды в ресторане и выражение предпочтений.', 'Оқушылар ағылшын тілінде тағамдар, сусындар және тапсырыс беру лексикасын үйренеді. Саналатын және саналмайтын зат есімдермен танысып, мейрамханада тамаққа тапсырыс беруді және қалауын білдіруді жаттықтырады.', 'Make a menu for your restaurant: 3 starters, 3 main courses, 3 drinks. Write a dialogue: «Can I have a pizza, please?» «Yes, here you are.» «How much is it?» «It is 5 dollars.»', 'Составьте меню для своего ресторана: 3 закуски, 3 основных блюда, 3 напитка. Напишите диалог: «Можно мне пиццу?» «Да, пожалуйста.» «Сколько стоит?» «5 долларов.»', 'Өз мейрамханаңа мәзір жаса: 3 тағам, 3 негізгі тағам, 3 сусын. Диалог жаз: «Can I have a pizza, please?» «Yes, here you are.» «How much is it?» «It is 5 dollars.»', 'https://www.youtube.com/results?search_query=5+grade+english+food+and+drinks'),
(15, 'Clothes and Fashion', 'Clothes and Fashion', 'Киімдер мен сән', 'Students learn vocabulary for clothes and appearance in English. They practice describing what people are wearing using Present Continuous and adjectives for size, colour and style.', 'Учащиеся изучают лексику одежды и внешности на английском. Практикуют описание одежды, используя настоящее продолженное время и прилагательные размера, цвета и стиля.', 'Оқушылар ағылшын тілінде киімдер мен сыртқы келбет лексикасын үйренеді. Present Continuous шағын және көлем, түс, стиль сын есімдерін қолданып киімдерді сипаттауды жаттықтырады.', 'Describe what your friend is wearing today: «She is wearing a red dress and white shoes. He is wearing a blue T-shirt and black jeans.» Draw and label 5 items of clothing.', 'Опишите, что сегодня носит ваш друг: «На ней красное платье и белые туфли. На нем синяя футболка и черные джинсы.» Нарисуйте и подпишите 5 предметов одежды.', 'Досыңның бүгінгі киімін сипатта: «She is wearing a red dress and white shoes. He is wearing a blue T-shirt and black jeans.» 5 киімнің суретін салып, ағылшынша жаз.', 'https://www.youtube.com/results?search_query=5+grade+english+clothes');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(16, 'Animals', 'Animals', 'Жануарлар', 'Students learn animal names and their habitats in English. They study vocabulary for domestic and wild animals, describe where animals live and what they eat using Present Simple.', 'Учащиеся изучают названия животных и их среду обитания на английском. Изучают лексику домашних и диких животных, описывают места обитания и питание, используя настоящее простое время.', 'Оқушылар ағылшын тілінде жануарлардың атауларын және олардың мекендейтін ортасын үйренеді. Үй және жабайы жануарлар лексикасын үйреніп, мекені мен қорегі туралы Present Simple шағын қолданып сипаттайды.', 'Choose an animal and describe it: «A tiger is a wild animal. It is orange and black. It lives in the jungle. It eats meat.» Answer: What is your favourite animal? Why?', 'Выберите животное и опишите его: «Тигр — дикое животное. Он оранжевый с черным. Живет в джунглях. Ест мясо.» Ответьте: Какое твое любимое животное? Почему?', 'Бір жануарды таңдап сипатта: «A tiger is a wild animal. It is orange and black. It lives in the jungle. It eats meat.» Сенің сүйікті жануарың қандай? Неге?', 'https://www.youtube.com/results?search_query=5+grade+english+animals'),
(16, 'Seasons and Weather', 'Seasons and Weather', 'Жыл мезгілдері және ауа райы', 'Students learn to describe seasons and weather conditions in English. They study weather vocabulary and practice talking about the four seasons, temperature, and typical weather activities.', 'Учащиеся учатся описывать времена года и погоду на английском. Изучают погодную лексику и практикуют рассказы о четырех сезонах, температуре и типичных занятиях в разную погоду.', 'Оқушылар ағылшын тілінде жыл мезгілдері мен ауа райын сипаттауды үйренеді. Ауа райы лексикасын үйреніп, төрт мезгіл, температура және әртүрлі ауа райындағы іс-әрекеттер туралы айтуды жаттықтырады.', 'Answer: «What is your favourite season?» «What is the weather like in spring?» Write 4 sentences: «In summer it is hot and sunny. I go swimming. In winter it is cold and snowy...»', 'Ответьте: «Какое твое любимое время года?» «Какая погода весной?» Напишите 4 предложения: «Летом жарко и солнечно. Я купаюсь. Зимой холодно и снежно...»', 'Сұрақтарға жауап бер: «What is your favourite season?» «What is the weather like in spring?» 4 сөйлем жаз: «In summer it is hot and sunny. I go swimming. In winter it is cold and snowy...»', 'https://www.youtube.com/results?search_query=5+grade+english+seasons+and+weather');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(17, 'Hobbies and Leisure Activities', 'Hobbies and Leisure Activities', 'Хобби және бос уақыт', 'Students learn to talk about hobbies and free time activities in English. They study hobby-related vocabulary, practice using like/love/don''t like with gerunds and discuss their interests.', 'Учащиеся учатся рассказывать о хобби и занятиях в свободное время на английском. Изучают лексику хобби, практикуют использование like/love/don''t like с герундием и обсуждают свои интересы.', 'Оқушылар ағылшын тілінде хобби және бос уақыт іс-әрекеттері туралы айтуды үйренеді. Хобби лексикасын үйреніп, like/love/don''t like қолданып, өз қызығушылықтары туралы айтады.', 'Ask your partner: «What do you like doing in your free time?» Answer: «I like playing football / reading books / drawing / swimming.» Write 3 things you love and 3 things you don''t like doing.', 'Спросите партнера: «Что ты любишь делать в свободное время?» Ответьте: «Я люблю играть в футбол / читать книги / рисовать / плавать.» Напишите 3 любимых и 3 нелюбимых занятия.', 'Көршіңнен сұра: «What do you like doing in your free time?» Жауап бер: «I like playing football / reading books / drawing / swimming.» Сүйікті 3 ісіңді және ұнатпайтын 3 ісіңді жаз.', 'https://www.youtube.com/results?search_query=5+grade+english+hobbies+and+leisure'),
(17, 'Holidays and Traditions', 'Holidays and Traditions', 'Мерекелер мен дәстүрлер', 'Students learn to discuss holidays and cultural traditions in English. They study vocabulary related to celebrations, compare Kazakh and British holidays, and practice inviting and responding.', 'Учащиеся учатся обсуждать праздники и культурные традиции на английском. Изучают лексику праздников, сравнивают казахские и британские праздники, практикуют приглашение и ответы.', 'Оқушылар ағылшын тілінде мерекелер мен мәдени дәстүрлерді талқылауды үйренеді. Мереке лексикасын үйреніп, қазақ және британ мерекелерін салыстырады, шақыру мен жауап беруді жаттықтырады.', 'Write about your favourite holiday: «My favourite holiday is Nauryz. It is in March. We wear traditional clothes and eat nauryz kozhe...» Ask a friend: «How do you celebrate your birthday?»', 'Напишите о своем любимом празднике: «Мой любимый праздник — Наурыз. Он в марте. Мы надеваем традиционную одежду и едим наурыз коже...» Спросите друга: «Как ты празднуешь день рождения?»', 'Өзіңнің сүйікті мерекең туралы жаз: «My favourite holiday is Nauryz. It is in March. We wear traditional clothes and eat nauryz kozhe...» Досыңнан сұра: «How do you celebrate your birthday?»', 'https://www.youtube.com/results?search_query=5+grade+english+holidays+and+traditions');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(18, 'Present Simple Tense', 'Present Simple Tense', 'Present Simple шағы', 'Students study the Present Simple tense: formation, usage, and spelling rules. They learn to form affirmative, negative and interrogative sentences, and use adverbs of frequency.', 'Учащиеся изучают настоящее простое время: образование, употребление и правила правописания. Учатся строить утвердительные, отрицательные и вопросительные предложения, используют наречия частоты.', 'Оқушылар Present Simple шағын үйренеді: жасалуы, қолданылуы және емле ережелері. Болымды, болымсыз және сұраулы сөйлемдер құрауға, frequency adverbs қолдануды үйренеді.', 'Put the verbs in Present Simple: «She (go) to school every day. They (play) tennis. He (not/watch) TV.» Make questions: «you / like / pizza?» Write 3 true sentences about yourself using always, sometimes, never.', 'Поставьте глаголы в Present Simple: «Она ходит в школу каждый день. Они играют в теннис. Он не смотрит TV.» Составьте вопросы: «Ты любишь пиццу?» Напишите 3 предложения о себе с always, sometimes, never.', 'Етістіктерді Present Simple шағында жаз: «She (go) to school every day. They (play) tennis. He (not/watch) TV.» Сұрақ құра: «you / like / pizza?» Өзің туралы always, sometimes, never сөздерін қолданып 3 сөйлем жаз.', 'https://www.youtube.com/results?search_query=5+grade+english+present+simple'),
(18, 'Present Continuous Tense', 'Present Continuous Tense', 'Present Continuous шағы', 'Students study the Present Continuous tense: formation and usage for actions happening now. They learn to distinguish between Present Simple and Present Continuous.', 'Учащиеся изучают настоящее продолженное время: образование и использование для действий, происходящих сейчас. Учатся различать Present Simple и Present Continuous.', 'Оқушылар Present Continuous шағын үйренеді: қазір болып жатқан іс-әрекеттерге қолданылуы мен жасалуы. Present Simple және Present Continuous шақтарын ажыратуды үйренеді.', 'Describe what is happening in the classroom: «The teacher (write) on the board. The students (listen). I (sit) at my desk.» Make negative: «He is not sleeping.» Form a question: «What are you doing?»', 'Опишите, что происходит в классе: «Учитель пишет на доске. Ученики слушают. Я сижу за партой.» Составьте отрицание: «Он не спит.» Вопрос: «Что ты делаешь?»', 'Сыныпта не болып жатқанын сипатта: «The teacher (write) on the board. The students (listen). I (sit) at my desk.» Болымсыз сөйлем жаз: «He is not sleeping.» Сұрақ құра: «What are you doing?»', 'https://www.youtube.com/results?search_query=5+grade+english+present+continuous'),
(18, 'Plural Nouns', 'Plural Nouns', 'Зат есімдердің көпше түрі', 'Students study regular and irregular plural forms of nouns in English. They learn spelling rules for regular plurals and memorize common irregular plural forms.', 'Учащиеся изучают правильные и неправильные формы множественного числа существительных в английском. Запоминают правила правописания для правильных форм и часто используемые неправильные формы.', 'Оқушылар ағылшын тіліндегі зат есімдердің дұрыс және бұрыс көпше түрлерін үйренеді. Дұрыс көпше формалардың емле ережелерін және жиі қолданылатын бұрыс формаларды жаттайды.', 'Write the plurals: cat - cats, box - boxes, baby - babies, knife - knives, tooth - teeth, child - children, sheep - sheep, foot - feet. Complete: «I have two (foot). There are three (mouse) in the house.»', 'Напишите множественное число: cat - cats, box - boxes, baby - babies, knife - knives, tooth - teeth, child - children, sheep - sheep, foot - feet. Заполните: «У меня две (ступни). В доме три (мыши).»', 'Көпше түрін жаз: cat - cats, box - boxes, baby - babies, knife - knives, tooth - teeth, child - children, sheep - sheep, foot - feet. Толтыр: «I have two (foot). There are three (mouse) in the house.»', 'https://www.youtube.com/results?search_query=5+grade+english+plural+nouns'),
(18, 'Prepositions of Place and Time', 'Prepositions of Place and Time', 'Орын және уақыт демеуліктері', 'Students study prepositions of place (in, on, at, under, next to, behind, in front of) and time (in, on, at). They learn to use them correctly in sentences and questions.', 'Учащиеся изучают предлоги места (в, на, у, под, рядом, за, перед) и времени (в, на, в). Учатся правильно использовать их в предложениях и вопросах.', 'Оқушылар орын демеуліктерін (in, on, at, under, next to, behind, in front of) және уақыт демеуліктерін (in, on, at) үйренеді. Оларды сөйлемдер мен сұрақтарда дұрыс қолдануға үйренеді.', 'Look at the picture and fill in: «The cat is ___ the table. The book is ___ the shelf. The school starts ___ 8 o''clock. My birthday is ___ June.» Describe your room using 3 prepositions of place.', 'Посмотрите на картинку и заполните: «Кот ___ столом. Книга ___ полке. Школа начинается ___ 8 часов. Мой день рождения ___ июне.» Опишите свою комнату, используя 3 предлога места.', 'Суретке қарап толтыр: «The cat is ___ the table. The book is ___ the shelf. The school starts ___ 8 o''clock. My birthday is ___ June.» Өз бөлмеңді 3 орын демеулігін қолданып сипатта.', 'https://www.youtube.com/results?search_query=5+grade+english+prepositions+of+place');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(19, 'Натуральные числа. Координатный луч', 'Натуральные числа. Координатный луч', 'Натурал сандар. Координаттық сәуле', 'Бұл тақырыпта оқушылар натурал сандар ұғымымен және координаттық сәулемен танысады. Сандарды координаттық сәуледе кескіндеуді үйренеді. Натурал сандардың қасиеттерін зерттейді.', 'В этой теме учащиеся знакомятся с понятием натурального числа и координатным лучом. Учатся изображать числа на координатном луче. Изучают свойства натуральных чисел.', 'Бұл тақырыпта оқушылар натурал сандар ұғымымен және координаттық сәулемен танысады. Сандарды координаттық сәуледе кескіндеуді үйренеді. Натурал сандардың қасиеттерін зерттейді.', 'Координаттық сәуледе 2, 5, 8, 10 сандарын белгіле. Әр санның координатасын ата. 5 санының көрші сандарын тап: қандай сан 5-тен кейін, қандай сан 5-ке дейін тұр?', 'Отметьте на координатном луче числа 2, 5, 8, 10. Назовите координату каждого числа. Найдите соседей числа 5: какое число стоит после 5, а какое перед 5?', 'Координаттық сәуледе 2, 5, 8, 10 сандарын белгіле. Әр санның координатасын ата. 5 санының көрші сандарын тап: қандай сан 5-тен кейін, қандай сан 5-ке дейін тұр?', 'https://www.youtube.com/results?search_query=5+сынып+математика+натурал+сандар+координаттық+сәуле'),
(19, 'Сравнение натуральных чисел', 'Сравнение натуральных чисел', 'Натурал сандарды салыстыру', 'Оқушылар натурал сандарды салыстыруды және қос теңсіздікті құруды үйренеді. Сандарды салыстыру белгілерін (>, <, =) дұрыс қолданып, сандар тізбегін өсу және кему ретімен жазады.', 'Учащиеся учатся сравнивать натуральные числа и составлять двойные неравенства. Правильно используют знаки сравнения (>, <, =), записывают числовые последовательности в порядке возрастания и убывания.', 'Оқушылар натурал сандарды салыстыруды және қос теңсіздікті құруды үйренеді. Сандарды салыстыру белгілерін (>, <, =) дұрыс қолданып, сандар тізбегін өсу және кему ретімен жазады.', 'Салыстыр: 25 және 32, 107 және 98, 1000 және 999. Қос теңсіздік түрінде жаз: 15 < x < 20. Сандарды өсу ретімен жаз: 45, 12, 67, 8, 34, 90.', 'Сравните: 25 и 32, 107 и 98, 1000 и 999. Запишите в виде двойного неравенства: 15 < x < 20. Запишите числа в порядке возрастания: 45, 12, 67, 8, 34, 90.', 'Салыстыр: 25 және 32, 107 және 98, 1000 және 999. Қос теңсіздік түрінде жаз: 15 < x < 20. Сандарды өсу ретімен жаз: 45, 12, 67, 8, 34, 90.', 'https://www.youtube.com/results?search_query=5+сынып+математика+натурал+сандарды+салыстыру'),
(19, 'Сложение и вычитание', 'Сложение и вычитание', 'Қосу және азайту', 'Оқушылар натурал сандарды қосу және азайту амалдарын, олардың қасиеттерін меңгереді. Қосудың ауыстырымдылық және терімділік қасиеттерін қолданып, тиімді есептеу тәсілдерін үйренеді.', 'Учащиеся осваивают сложение и вычитание натуральных чисел и их свойства. Изучают переместительное и сочетательное свойства сложения, учатся применять рациональные способы вычислений.', 'Оқушылар натурал сандарды қосу және азайту амалдарын, олардың қасиеттерін меңгереді. Қосудың ауыстырымдылық және терімділік қасиеттерін қолданып, тиімді есептеу тәсілдерін үйренеді.', 'Есепте: 345 + 287; 903 - 456; 127 + 85 + 73 (тиімді тәсілмен). Мектепте 450 оқушы бар. Оның 238-і қыз. Мектепте неше ұл бала бар?', 'Вычислите: 345 + 287; 903 - 456; 127 + 85 + 73 (удобным способом). В школе 450 учащихся. Из них 238 девочек. Сколько мальчиков в школе?', 'Есепте: 345 + 287; 903 - 456; 127 + 85 + 73 (тиімді тәсілмен). Мектепте 450 оқушы бар. Оның 238-і қыз. Мектепте неше ұл бала бар?', 'https://www.youtube.com/results?search_query=5+сынып+математика+қосу+және+азайту'),
(19, 'Умножение и деление', 'Умножение и деление', 'Көбейту және бөлу', 'Бұл тақырыпта оқушылар натурал сандарды көбейту және бөлу амалдарын, олардың қасиеттерін меңгереді. Көбейту кестесін бекітіп, көбейтудің үлестірімділік қасиетін қолданады.', 'В этой теме учащиеся осваивают умножение и деление натуральных чисел, их свойства. Закрепляют таблицу умножения, применяют распределительное свойство умножения.', 'Бұл тақырыпта оқушылар натурал сандарды көбейту және бөлу амалдарын, олардың қасиеттерін меңгереді. Көбейту кестесін бекітіп, көбейтудің үлестірімділік қасиетін қолданады.', 'Есепте: 25 * 48; 756 : 6; 125 * 37 * 8 (тиімді тәсіл). Ойын алаңында 5 қатарға әрқайсысында 27 көшеттен отырғызылды. Барлығы неше көшет отырғызылды?', 'Вычислите: 25 * 48; 756 : 6; 125 * 37 * 8 (удобным способом). На игровой площадке высадили 5 рядов по 27 саженцев. Сколько всего саженцев высадили?', 'Есепте: 25 * 48; 756 : 6; 125 * 37 * 8 (тиімді тәсіл). Ойын алаңында 5 қатарға әрқайсысында 27 көшеттен отырғызылды. Барлығы неше көшет отырғызылды?', 'https://www.youtube.com/results?search_query=5+сынып+математика+көбейту+және+бөлу'),
(19, 'Числовые и буквенные выражения', 'Числовые и буквенные выражения', 'Санды және әріпті өрнектер', 'Оқушылар санды және әріпті өрнектер құруды және олардың мәнін есептеуді үйренеді. Айнымалысы бар өрнектермен танысып, өрнектерді ықшамдауды меңгереді.', 'Учащиеся учатся составлять числовые и буквенные выражения и вычислять их значения. Знакомятся с выражениями с переменной, осваивают упрощение выражений.', 'Оқушылар санды және әріпті өрнектер құруды және олардың мәнін есептеуді үйренеді. Айнымалысы бар өрнектермен танысып, өрнектерді ықшамдауды меңгереді.', 'Өрнектің мәнін тап: (45 + 27) : 8; 34 + 5 * (72 : 9).  a = 15 болғанда 2a + 7 өрнегінің мәнін есепте. «Бір санға 25-ті қосып, 13-ті азайт» өрнегін әріппен жаз.', 'Найдите значение выражения: (45 + 27) : 8; 34 + 5 * (72 : 9). Вычислите значение выражения 2a + 7 при a = 15. Запишите с помощью букв выражение: «К числу прибавить 25 и вычесть 13».', 'Өрнектің мәнін тап: (45 + 27) : 8; 34 + 5 * (72 : 9).  a = 15 болғанда 2a + 7 өрнегінің мәнін есепте. «Бір санға 25-ті қосып, 13-ті азайт» өрнегін әріппен жаз.', 'https://www.youtube.com/results?search_query=5+сынып+математика+санды+және+әріпті+өрнектер'),
(19, 'Уравнение', 'Уравнение', 'Теңдеу', 'Бұл тақырыпта оқушылар теңдеу ұғымымен танысып, оның түбірін табуды үйренеді. Қосу, азайту, көбейту және бөлу амалдарының компоненттерін пайдаланып, қарапайым теңдеулерді шешеді.', 'В этой теме учащиеся знакомятся с понятием уравнения и находят его корень. Используя компоненты сложения, вычитания, умножения и деления, решают простые уравнения.', 'Бұл тақырыпта оқушылар теңдеу ұғымымен танысып, оның түбірін табуды үйренеді. Қосу, азайту, көбейту және бөлу амалдарының компоненттерін пайдаланып, қарапайым теңдеулерді шешеді.', 'Теңдеуді шеш: x + 35 = 82; y - 17 = 48; 5x = 125; x : 8 = 12. Есепті теңдеу құру арқылы шығар: «Балалар әткеншекке 12 бала келді, содан кейін 7 бала кетті. Әткеншекте неше бала қалды?»', 'Решите уравнение: x + 35 = 82; y - 17 = 48; 5x = 125; x : 8 = 12. Решите задачу с помощью уравнения: «На качели пришли 12 детей, потом ушли 7 детей. Сколько детей осталось на качелях?»', 'Теңдеуді шеш: x + 35 = 82; y - 17 = 48; 5x = 125; x : 8 = 12. Есепті теңдеу құру арқылы шығар: «Балалар әткеншекке 12 бала келді, содан кейін 7 бала кетті. Әткеншекте неше бала қалды?»', 'https://www.youtube.com/results?search_query=5+сынып+математика+теңдеу');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(20, 'Делители и кратные', 'Делители и кратные', 'Бөлгіштер мен еселіктер', 'Оқушылар бөлгіш және еселік ұғымдарымен танысады. Берілген санның бөлгіштерін және еселіктерін табуды үйренеді. Сандардың ең кіші ортақ еселігі және ең үлкен ортақ бөлгіші туралы түсінік алады.', 'Учащиеся знакомятся с понятиями делителя и кратного. Учатся находить делители и кратные данного числа. Получают представление о наименьшем общем кратном и наибольшем общем делителе.', 'Оқушылар бөлгіш және еселік ұғымдарымен танысады. Берілген санның бөлгіштерін және еселіктерін табуды үйренеді. Сандардың ең кіші ортақ еселігі және ең үлкен ортақ бөлгіші туралы түсінік алады.', '24 санының барлық бөлгіштерін жаз. 6 санына еселік болатын 5 санды жаз. 12 және 18 сандарының ортақ бөлгіштерін тап.', 'Запишите все делители числа 24. Запишите 5 чисел, кратных числу 6. Найдите общие делители чисел 12 и 18.', '24 санының барлық бөлгіштерін жаз. 6 санына еселік болатын 5 санды жаз. 12 және 18 сандарының ортақ бөлгіштерін тап.', 'https://www.youtube.com/results?search_query=5+сынып+математика+бөлгіштер+мен+еселіктер'),
(20, 'Простые и составные числа', 'Простые и составные числа', 'Жай және құрама сандар', 'Оқушылар жай және құрама сандарды ажыратуды үйренеді. Жай сандар кестесімен танысып, санды жай көбейткіштерге жіктеу дағдысын меңгереді.', 'Учащиеся учатся различать простые и составные числа. Знакомятся с таблицей простых чисел, осваивают навык разложения числа на простые множители.', 'Оқушылар жай және құрама сандарды ажыратуды үйренеді. Жай сандар кестесімен танысып, санды жай көбейткіштерге жіктеу дағдысын меңгереді.', 'Берілген сандардың қайсысы жай, қайсысы құрама екенін анықта: 7, 15, 23, 28, 31, 42. 60 санын жай көбейткіштерге жікте.', 'Определите, какие из чисел являются простыми, а какие составными: 7, 15, 23, 28, 31, 42. Разложите число 60 на простые множители.', 'Берілген сандардың қайсысы жай, қайсысы құрама екенін анықта: 7, 15, 23, 28, 31, 42. 60 санын жай көбейткіштерге жікте.', 'https://www.youtube.com/results?search_query=5+сынып+математика+жай+және+құрама+сандар'),
(20, 'Признаки делимости', 'Признаки делимости', 'Бөлінгіштік белгілері', 'Оқушылар сандардың 2, 3, 5, 9 және 10-ға бөлінгіштік белгілерін үйренеді. Бөлінгіштік белгілерін қолданып, сандардың қалдықсыз бөлінетінін анықтайды.', 'Учащиеся изучают признаки делимости на 2, 3, 5, 9 и 10. Используя признаки делимости, определяют, делится ли число без остатка.', 'Оқушылар сандардың 2, 3, 5, 9 және 10-ға бөлінгіштік белгілерін үйренеді. Бөлінгіштік белгілерін қолданып, сандардың қалдықсыз бөлінетінін анықтайды.', '2-ге, 5-ке, 10-ға бөлінетін 3 саннан жаз. 3-ке және 9-ға бөлінгіштік белгісін қолданып, 345, 729, 8142 сандарын тексер.', 'Запишите по 3 числа, которые делятся на 2, на 5, на 10. Используя признаки делимости на 3 и 9, проверьте числа: 345, 729, 8142.', '2-ге, 5-ке, 10-ға бөлінетін 3 саннан жаз. 3-ке және 9-ға бөлінгіштік белгісін қолданып, 345, 729, 8142 сандарын тексер.', 'https://www.youtube.com/results?search_query=5+сынып+математика+бөлінгіштік+белгілері'),
(20, 'НОД и НОК', 'НОД и НОК', 'ЕҮОБ және ЕКОЕ', 'Оқушылар ең үлкен ортақ бөлгішті (ЕҮОБ) және ең кіші ортақ еселікті (ЕКОЕ) табуды үйренеді. Сандарды жай көбейткіштерге жіктеу арқылы ЕҮОБ пен ЕКОЕ-ны есептейді.', 'Учащиеся учатся находить наибольший общий делитель (НОД) и наименьшее общее кратное (НОК). Вычисляют НОД и НОК с помощью разложения чисел на простые множители.', 'Оқушылар ең үлкен ортақ бөлгішті (ЕҮОБ) және ең кіші ортақ еселікті (ЕКОЕ) табуды үйренеді. Сандарды жай көбейткіштерге жіктеу арқылы ЕҮОБ пен ЕКОЕ-ны есептейді.', 'ЕҮОБ(12, 18) және ЕКОЕ(12, 18) тап. 24 және 36 сандарының ЕҮОБ-ын және ЕКОЕ-ын есепте. 6 санының 3-ке тең ЕҮОБ-ы және 30-ға тең ЕКОЕ-ы бар санды тап.', 'Найдите НОД(12, 18) и НОК(12, 18). Вычислите НОД и НОК чисел 24 и 36. Найдите число, у которого НОД с 6 равен 3, а НОК равен 30.', 'ЕҮОБ(12, 18) және ЕКОЕ(12, 18) тап. 24 және 36 сандарының ЕҮОБ-ын және ЕКОЕ-ын есепте. 6 санының 3-ке тең ЕҮОБ-ы және 30-ға тең ЕКОЕ-ы бар санды тап.', 'https://www.youtube.com/results?search_query=5+сынып+математика+ЕҮОБ+және+ЕКОЕ');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(21, 'Обыкновенные дроби. Основное свойство', 'Обыкновенные дроби. Основное свойство', 'Жай бөлшек. Негізгі қасиеті', 'Оқушылар жай бөлшек ұғымымен танысып, бөлшектің негізгі қасиетін меңгереді. Бөлшектің алымы мен бөлімін анықтап, бөлшектерді қысқартуды үйренеді.', 'Учащиеся знакомятся с понятием обыкновенной дроби, осваивают основное свойство дроби. Определяют числитель и знаменатель дроби, учатся сокращать дроби.', 'Оқушылар жай бөлшек ұғымымен танысып, бөлшектің негізгі қасиетін меңгереді. Бөлшектің алымы мен бөлімін анықтап, бөлшектерді қысқартуды үйренеді.', 'Дөңгелектің 3/4 бөлігін боя. Бөлшектерді қысқарт: 6/9, 8/12, 15/20. Бөлшектердің негізгі қасиетін қолданып, 3/7 бөлшегіне тең 3 бөлшек жаз.', 'Закрасьте 3/4 круга. Сократите дроби: 6/9, 8/12, 15/20. Используя основное свойство дроби, запишите 3 дроби, равные 3/7.', 'Дөңгелектің 3/4 бөлігін боя. Бөлшектерді қысқарт: 6/9, 8/12, 15/20. Бөлшектердің негізгі қасиетін қолданып, 3/7 бөлшегіне тең 3 бөлшек жаз.', 'https://www.youtube.com/results?search_query=5+сынып+математика+жай+бөлшек+негізгі+қасиет'),
(21, 'Правильные и неправильные дроби', 'Правильные и неправильные дроби', 'Дұрыс және бұрыс бөлшектер', 'Бұл тақырыпта оқушылар дұрыс және бұрыс бөлшектерді ажыратуды үйренеді. Дұрыс бөлшек (бөлімі үлкен) пен бұрыс бөлшекті (алымы үлкен) салыстырады және координаттық сәуледе кескіндейді.', 'В этой теме учащиеся учатся различать правильные и неправильные дроби. Сравнивают правильную дробь (знаменатель больше) с неправильной (числитель больше) и изображают их на координатном луче.', 'Бұл тақырыпта оқушылар дұрыс және бұрыс бөлшектерді ажыратуды үйренеді. Дұрыс бөлшек (бөлімі үлкен) пен бұрыс бөлшекті (алымы үлкен) салыстырады және координаттық сәуледе кескіндейді.', 'Бөлшектерді дұрыс және бұрыс деп топта: 3/5, 7/4, 2/3, 9/8, 5/5. 1-ден үлкен бөлшектерді теріп жаз. Неге 5/5 = 1 екенін түсіндір.', 'Разделите дроби на правильные и неправильные: 3/5, 7/4, 2/3, 9/8, 5/5. Выпишите дроби больше 1. Объясните, почему 5/5 = 1.', 'Бөлшектерді дұрыс және бұрыс деп топта: 3/5, 7/4, 2/3, 9/8, 5/5. 1-ден үлкен бөлшектерді теріп жаз. Неге 5/5 = 1 екенін түсіндір.', 'https://www.youtube.com/results?search_query=5+сынып+математика+дұрыс+және+бұрыс+бөлшектер'),
(21, 'Смешанные числа', 'Смешанные числа', 'Аралас сандар', 'Оқушылар аралас сандармен танысып, оларды бұрыс бөлшекке айналдыруды және керісінше бұрыс бөлшекті аралас санға айналдыруды үйренеді. Аралас сандарды салыстырады.', 'Учащиеся знакомятся со смешанными числами, учатся преобразовывать их в неправильную дробь и обратно — неправильную дробь в смешанное число. Сравнивают смешанные числа.', 'Оқушылар аралас сандармен танысып, оларды бұрыс бөлшекке айналдыруды және керісінше бұрыс бөлшекті аралас санға айналдыруды үйренеді. Аралас сандарды салыстырады.', 'Аралас санды бұрыс бөлшекке айналдыр: 2 3/5; 5 1/4; 7 2/3. Бұрыс бөлшекті аралас санға айналдыр: 11/4; 23/5; 17/3. Салыстыр: 3 1/2 және 4 1/5.', 'Преобразуйте смешанные числа в неправильные дроби: 2 3/5; 5 1/4; 7 2/3. Преобразуйте неправильные дроби в смешанные числа: 11/4; 23/5; 17/3. Сравните: 3 1/2 и 4 1/5.', 'Аралас санды бұрыс бөлшекке айналдыр: 2 3/5; 5 1/4; 7 2/3. Бұрыс бөлшекті аралас санға айналдыр: 11/4; 23/5; 17/3. Салыстыр: 3 1/2 және 4 1/5.', 'https://www.youtube.com/results?search_query=5+сынып+математика+аралас+сандар'),
(21, 'Сложение и вычитание дробей', 'Сложение и вычитание дробей', 'Бөлшектерді қосу және азайту', 'Оқушылар жай бөлшектерді және аралас сандарды қосу мен азайтуды үйренеді. Ортақ бөлімге келтіру арқылы бөлшектерді қосып, азайтады.', 'Учащиеся учатся складывать и вычитать обыкновенные дроби и смешанные числа. Выполняют сложение и вычитание дробей путем приведения к общему знаменателю.', 'Оқушылар жай бөлшектерді және аралас сандарды қосу мен азайтуды үйренеді. Ортақ бөлімге келтіру арқылы бөлшектерді қосып, азайтады.', 'Есепте: 2/5 + 1/5; 7/9 - 4/9; 1/3 + 1/4; 5/6 - 1/3. «Біз 3/8 пирог жедік, содан кейін тағы 1/4 пирог жедік. Барлығы қанша пирог желінді?»', 'Вычислите: 2/5 + 1/5; 7/9 - 4/9; 1/3 + 1/4; 5/6 - 1/3. «Мы съели 3/8 пирога, потом еще 1/4 пирога. Сколько всего пирога съедено?»', 'Есепте: 2/5 + 1/5; 7/9 - 4/9; 1/3 + 1/4; 5/6 - 1/3. «Біз 3/8 пирог жедік, содан кейін тағы 1/4 пирог жедік. Барлығы қанша пирог желінді?»', 'https://www.youtube.com/results?search_query=5+сынып+математика+жай+бөлшектерді+қосу+және+азайту'),
(21, 'Умножение и деление дробей', 'Умножение и деление дробей', 'Бөлшектерді көбейту және бөлу', 'Бұл тақырыпта оқушылар жай бөлшектерді көбейту және бөлу амалдарын меңгереді. Бөлшекті бөлшекке және натурал санға көбейту мен бөлуді үйренеді.', 'В этой теме учащиеся осваивают умножение и деление обыкновенных дробей. Учатся умножать и делить дробь на дробь и на натуральное число.', 'Бұл тақырыпта оқушылар жай бөлшектерді көбейту және бөлу амалдарын меңгереді. Бөлшекті бөлшекке және натурал санға көбейту мен бөлуді үйренеді.', 'Есепте: 2/3 * 4/5; 3/4 * 8; 6/7 : 3; 2/3 : 5/6. Тіктөртбұрыштың ұзындығы 5/6 м, ені 2/3 м. Ауданын тап.', 'Вычислите: 2/3 * 4/5; 3/4 * 8; 6/7 : 3; 2/3 : 5/6. Длина прямоугольника 5/6 м, ширина 2/3 м. Найдите площадь.', 'Есепте: 2/3 * 4/5; 3/4 * 8; 6/7 : 3; 2/3 : 5/6. Тіктөртбұрыштың ұзындығы 5/6 м, ені 2/3 м. Ауданын тап.', 'https://www.youtube.com/results?search_query=5+сынып+математика+жай+бөлшектерді+көбейту+және+бөлу');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(22, 'Десятичные дроби. Чтение и запись', 'Десятичные дроби. Чтение и запись', 'Ондық бөлшек. Оқу және жазу', 'Оқушылар ондық бөлшек ұғымымен танысады. Ондық бөлшектерді оқуды, жазуды және олардың разрядтарын анықтауды үйренеді. Жай бөлшектерді ондық бөлшекке айналдырады.', 'Учащиеся знакомятся с понятием десятичной дроби. Учатся читать, записывать десятичные дроби и определять их разряды. Преобразуют обыкновенные дроби в десятичные.', 'Оқушылар ондық бөлшек ұғымымен танысады. Ондық бөлшектерді оқуды, жазуды және олардың разрядтарын анықтауды үйренеді. Жай бөлшектерді ондық бөлшекке айналдырады.', 'Ондық бөлшек түрінде жаз: 3/10; 25/100; 7/1000; 5 3/10. Ондық бөлшектерді оқы: 0,5; 3,25; 12,007. Разрядтары бойынша жаз: 7 бүтін 3 ондық 2 жүздік = ...', 'Запишите в виде десятичной дроби: 3/10; 25/100; 7/1000; 5 3/10. Прочитайте десятичные дроби: 0,5; 3,25; 12,007. Запишите по разрядам: 7 целых 3 десятых 2 сотых = ...', 'Ондық бөлшек түрінде жаз: 3/10; 25/100; 7/1000; 5 3/10. Ондық бөлшектерді оқы: 0,5; 3,25; 12,007. Разрядтары бойынша жаз: 7 бүтін 3 ондық 2 жүздік = ...', 'https://www.youtube.com/results?search_query=5+сынып+математика+ондық+бөлшектер'),
(22, 'Сравнение десятичных дробей', 'Сравнение десятичных дробей', 'Ондық бөлшектерді салыстыру', 'Оқушылар ондық бөлшектерді салыстыру ережелерін меңгереді. Бөлшектерді разрядтары бойынша салыстырып, өсу және кему ретімен орналастырады.', 'Учащиеся осваивают правила сравнения десятичных дробей. Сравнивают дроби по разрядам, располагают в порядке возрастания и убывания.', 'Оқушылар ондық бөлшектерді салыстыру ережелерін меңгереді. Бөлшектерді разрядтары бойынша салыстырып, өсу және кему ретімен орналастырады.', 'Салыстыр: 0,5 және 0,7; 2,15 және 2,3; 0,125 және 0,13. Сандарды өсу ретімен жаз: 0,3; 1,25; 0,08; 2,1; 0,9. Қай сан үлкен: 0,7 немесе 0,70? Неге?', 'Сравните: 0,5 и 0,7; 2,15 и 2,3; 0,125 и 0,13. Запишите числа в порядке возрастания: 0,3; 1,25; 0,08; 2,1; 0,9. Какое число больше: 0,7 или 0,70? Почему?', 'Салыстыр: 0,5 және 0,7; 2,15 және 2,3; 0,125 және 0,13. Сандарды өсу ретімен жаз: 0,3; 1,25; 0,08; 2,1; 0,9. Қай сан үлкен: 0,7 немесе 0,70? Неге?', 'https://www.youtube.com/results?search_query=5+сынып+математика+ондық+бөлшектерді+салыстыру'),
(22, 'Действия с десятичными дробями', 'Действия с десятичными дробями', 'Ондық бөлшектермен амалдар', 'Оқушылар ондық бөлшектермен арифметикалық амалдарды (қосу, азайту, көбейту, бөлу) меңгереді. Ондық бөлшектерді баған түрінде қосып, азайтуды және көбейтіп, бөлуді үйренеді.', 'Учащиеся осваивают арифметические действия с десятичными дробями (сложение, вычитание, умножение, деление). Учатся складывать, вычитать, умножать и делить десятичные дроби столбиком.', 'Оқушылар ондық бөлшектермен арифметикалық амалдарды (қосу, азайту, көбейту, бөлу) меңгереді. Ондық бөлшектерді баған түрінде қосып, азайтуды және көбейтіп, бөлуді үйренеді.', 'Есепте: 3,5 + 2,7; 10,3 - 4,8; 2,5 * 4; 7,2 : 3; 0,25 * 0,4. 1 кесек сабын 1,25 теңге тұрады. 6 кесек сабын қанша тұрады?', 'Вычислите: 3,5 + 2,7; 10,3 - 4,8; 2,5 * 4; 7,2 : 3; 0,25 * 0,4. Один кусок мыла стоит 1,25 тенге. Сколько стоят 6 кусков мыла?', 'Есепте: 3,5 + 2,7; 10,3 - 4,8; 2,5 * 4; 7,2 : 3; 0,25 * 0,4. 1 кесек сабын 1,25 теңге тұрады. 6 кесек сабын қанша тұрады?', 'https://www.youtube.com/results?search_query=5+сынып+математика+ондық+бөлшектермен+амалдар'),
(22, 'Округление десятичных дробей', 'Округление десятичных дробей', 'Ондық бөлшектерді дөңгелектеу', 'Оқушылар ондық бөлшектерді дөңгелектеу ережелерін үйренеді. Сандарды ондыққа, жүздікке және т.б. разрядтарға дейін дөңгелектейді. Дөңгелектеудің практикалық маңызын түсінеді.', 'Учащиеся изучают правила округления десятичных дробей. Округляют числа до десятых, сотых и других разрядов. Понимают практическое значение округления.', 'Оқушылар ондық бөлшектерді дөңгелектеу ережелерін үйренеді. Сандарды ондыққа, жүздікке және т.б. разрядтарға дейін дөңгелектейді. Дөңгелектеудің практикалық маңызын түсінеді.', 'Дөңгелекте: 5,138 ондық үлеске дейін; 12,647 жүздік үлеске дейін; 0,859 бүтінге дейін. Массасы 4,285 грамм болатын алманың массасын ондық үлеске дейін дөңгелекте.', 'Округлите: 5,138 до десятых; 12,647 до сотых; 0,859 до целых. Яблоко весит 4,285 грамма. Округлите массу яблока до десятых.', 'Дөңгелекте: 5,138 ондық үлеске дейін; 12,647 жүздік үлеске дейін; 0,859 бүтінге дейін. Массасы 4,285 грамм болатын алманың массасын ондық үлеске дейін дөңгелекте.', 'https://www.youtube.com/results?search_query=5+сынып+математика+ондық+бөлшектерді+дөңгелектеу');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(23, 'Понятие процента', 'Понятие процента', 'Пайыз ұғымы', 'Оқушылар пайыз ұғымымен танысады. Пайыздың бүтіннің жүздік үлесі екенін түсініп, пайызды бөлшекке және бөлшекті пайызға айналдыруды үйренеді.', 'Учащиеся знакомятся с понятием процента. Понимают, что процент — это сотая часть целого, учатся переводить проценты в дроби и дроби в проценты.', 'Оқушылар пайыз ұғымымен танысады. Пайыздың бүтіннің жүздік үлесі екенін түсініп, пайызды бөлшекке және бөлшекті пайызға айналдыруды үйренеді.', 'Пайызды бөлшекпен және ондық бөлшекпен жаз: 25%; 50%; 75%; 10%; 100%. Бөлшектерді пайызбен жаз: 0,3; 1/4; 3/5; 0,08.', 'Запишите проценты в виде дроби и десятичной дроби: 25%; 50%; 75%; 10%; 100%. Запишите дроби в процентах: 0,3; 1/4; 3/5; 0,08.', 'Пайызды бөлшекпен және ондық бөлшекпен жаз: 25%; 50%; 75%; 10%; 100%. Бөлшектерді пайызбен жаз: 0,3; 1/4; 3/5; 0,08.', 'https://www.youtube.com/results?search_query=5+сынып+математика+пайыз+ұғымы'),
(23, 'Нахождение процентов от числа', 'Нахождение процентов от числа', 'Санның пайызын табу', 'Оқушылар санның пайызын табуды және пайызы бойынша санды табуды үйренеді. Пайыздық есептерді шығару дағдысын дамытады.', 'Учащиеся учатся находить процент от числа и число по его проценту. Развивают навыки решения процентных задач.', 'Оқушылар санның пайызын табуды және пайызы бойынша санды табуды үйренеді. Пайыздық есептерді шығару дағдысын дамытады.', 'Санның пайызын тап: 200-дің 15% - ?; 80-нің 25% - ?; 120-ның 10% - ?. Егер санның 20% - 50 болса, санды тап. Мектептің 60% - 300 оқушы болса, барлық оқушы саны қанша?', 'Найдите процент от числа: 15% от 200; 25% от 80; 10% от 120. Найдите число, если 20% от него равны 50. Если 60% учащихся школы — 300 человек, сколько всего учащихся?', 'Санның пайызын тап: 200-дің 15% - ?; 80-нің 25% - ?; 120-ның 10% - ?. Егер санның 20% - 50 болса, санды тап. Мектептің 60% - 300 оқушы болса, барлық оқушы саны қанша?', 'https://www.youtube.com/results?search_query=5+сынып+математика+санның+пайызын+табу');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(24, 'Множество. Элементы множества', 'Множество. Элементы множества', 'Жиын. Жиын элементтері', 'Оқушылар жиын және оның элементтері ұғымымен танысады. Жиындарды цифрлық белгілеумен және сипаттау арқылы беруді үйренеді. Жиындардың бөліктері мен элементтерін анықтайды.', 'Учащиеся знакомятся с понятием множества и его элементов. Учатся задавать множества цифровым обозначением и описанием. Определяют части и элементы множества.', 'Оқушылар жиын және оның элементтері ұғымымен танысады. Жиындарды цифрлық белгілеумен және сипаттау арқылы беруді үйренеді. Жиындардың бөліктері мен элементтерін анықтайды.', 'A = {1, 3, 5, 7, 9} жиынының элементтерін жаз. B = {х | х - 5-тен кіші натурал сан} жиынын цифрлармен көрсет. Қай сан A жиынына кіреді: 2? 5? 10?', 'Запишите элементы множества A = {1, 3, 5, 7, 9}. Изобразите цифрами множество B = {х | х — натуральное число меньше 5}. Какие числа входят в множество A: 2? 5? 10?', 'A = {1, 3, 5, 7, 9} жиынының элементтерін жаз. B = {х | х - 5-тен кіші натурал сан} жиынын цифрлармен көрсет. Қай сан A жиынына кіреді: 2? 5? 10?', 'https://www.youtube.com/results?search_query=5+сынып+математика+жиын+және+оның+элементтері'),
(24, 'Объединение и пересечение множеств', 'Объединение и пересечение множеств', 'Жиындардың бірігуі мен қиылысуы', 'Оқушылар жиындардың бірігуі мен қиылысуы амалдарымен танысады. Эйлер-Венн диаграммасын пайдаланып, жиындармен амалдарды көрнекі түрде бейнелейді.', 'Учащиеся знакомятся с операциями объединения и пересечения множеств. Используя диаграммы Эйлера-Венна, наглядно изображают операции над множествами.', 'Оқушылар жиындардың бірігуі мен қиылысуы амалдарымен танысады. Эйлер-Венн диаграммасын пайдаланып, жиындармен амалдарды көрнекі түрде бейнелейді.', 'A = {1, 2, 3, 4, 5}, B = {4, 5, 6, 7, 8}. A∪B (бірігу) және A∩B (қиылысу) тап. Сыныпта 20 оқушы: 12-сі футболды, 10-ы баскетболды жақсы көреді. 5-еуі екі спортты да ұнатады. Неше оқушы тек футболды ұнатады?', 'Даны множества A = {1, 2, 3, 4, 5}, B = {4, 5, 6, 7, 8}. Найдите A∪B (объединение) и A∩B (пересечение). В классе 20 учеников: 12 любят футбол, 10 — баскетбол. 5 любят оба вида спорта. Сколько учеников любят только футбол?', 'A = {1, 2, 3, 4, 5}, B = {4, 5, 6, 7, 8}. A∪B (бірігу) және A∩B (қиылысу) тап. Сыныпта 20 оқушы: 12-сі футболды, 10-ы баскетболды жақсы көреді. 5-еуі екі спортты да ұнатады. Неше оқушы тек футболды ұнатады?', 'https://www.youtube.com/results?search_query=5+сынып+математика+жиындардың+бірігуі+мен+қиылысуы'),
(25, 'Угол. Градусная мера угла', 'Угол. Градусная мера угла', 'Бұрыш. Бұрыштың градустық өлшемі', 'Оқушылар бұрыш ұғымымен, оның градустық өлшемімен танысады. Бұрыштардың түрлерін (сүйір, тік, доғал, жазыңқы) ажыратып, транспортирмен бұрыштарды өлшеуді үйренеді.', 'Учащиеся знакомятся с понятием угла и его градусной мерой. Различают виды углов (острый, прямой, тупой, развернутый), учатся измерять углы транспортиром.', 'Оқушылар бұрыш ұғымымен, оның градустық өлшемімен танысады. Бұрыштардың түрлерін (сүйір, тік, доғал, жазыңқы) ажыратып, транспортирмен бұрыштарды өлшеуді үйренеді.', 'Бұрыштың түрін анықта: 30°, 90°, 120°, 180°. Транспортирді қолданып, 45°, 75°, 150° бұрыштарын сыз. Тік бұрыш неше градус? 45° бұрыш қандай бұрыш?', 'Определите вид угла: 30°, 90°, 120°, 180°. Используя транспортир, постройте углы 45°, 75°, 150°. Сколько градусов в прямом угле? Каким является угол 45°?', 'Бұрыштың түрін анықта: 30°, 90°, 120°, 180°. Транспортирді қолданып, 45°, 75°, 150° бұрыштарын сыз. Тік бұрыш неше градус? 45° бұрыш қандай бұрыш?', 'https://www.youtube.com/results?search_query=5+сынып+математика+бұрыш+градустық+өлшем'),
(25, 'Многоугольник. Периметр', 'Многоугольник. Периметр', 'Көпбұрыш. Периметр', 'Оқушылар көпбұрыштардың түрлерімен және олардың қасиеттерімен танысады. Көпбұрыштың периметрін табуды үйренеді. Үшбұрыш, төртбұрыш және олардың элементтерін анықтайды.', 'Учащиеся знакомятся с видами многоугольников и их свойствами. Учатся находить периметр многоугольника. Определяют треугольники, четырехугольники и их элементы.', 'Оқушылар көпбұрыштардың түрлерімен және олардың қасиеттерімен танысады. Көпбұрыштың периметрін табуды үйренеді. Үшбұрыш, төртбұрыш және олардың элементтерін анықтайды.', 'Периметрді тап: қабырғалары 5 см, 7 см және 9 см болатын үшбұрыш; қабырғалары 4 см және 6 см болатын тіктөртбұрыш. Қабырғасы 8 см квадраттың периметрі неге тең?', 'Найдите периметр: треугольника со сторонами 5 см, 7 см и 9 см; прямоугольника со сторонами 4 см и 6 см. Чему равен периметр квадрата со стороной 8 см?', 'Периметрді тап: қабырғалары 5 см, 7 см және 9 см болатын үшбұрыш; қабырғалары 4 см және 6 см болатын тіктөртбұрыш. Қабырғасы 8 см квадраттың периметрі неге тең?', 'https://www.youtube.com/results?search_query=5+сынып+математика+көпбұрыш+периметр'),
(26, 'Окружность. Круг. Диаграмма', 'Окружность. Круг. Диаграмма', 'Шеңбер. Дөңгелек. Диаграмма', 'Оқушылар шеңбер, дөңгелек ұғымдарымен және дөңгелек диаграммалармен танысады. Шеңбер мен дөңгелектің айырмашылығын түсініп, дөңгелек диаграмманы оқу мен салу дағдыларын дамытады.', 'Учащиеся знакомятся с понятиями окружности, круга и круговых диаграмм. Понимают разницу между окружностью и кругом, развивают навыки чтения и построения круговых диаграмм.', 'Оқушылар шеңбер, дөңгелек ұғымдарымен және дөңгелек диаграммалармен танысады. Шеңбер мен дөңгелектің айырмашылығын түсініп, дөңгелек диаграмманы оқу мен салу дағдыларын дамытады.', 'Циркуль көмегімен радиусы 3 см шеңбер сыз. Класта 30 оқушы: 12-сі математиканы, 8-і қазақ тілін, 6-ы жаратылыстануды, 4-і ағылшын тілін ұнатады. Дөңгелек диаграмма сал.', 'Начертите окружность радиусом 3 см с помощью циркуля. В классе 30 учеников: 12 любят математику, 8 — казахский, 6 — естествознание, 4 — английский. Постройте круговую диаграмму.', 'Циркуль көмегімен радиусы 3 см шеңбер сыз. Класта 30 оқушы: 12-сі математиканы, 8-і қазақ тілін, 6-ы жаратылыстануды, 4-і ағылшын тілін ұнатады. Дөңгелек диаграмма сал.', 'https://www.youtube.com/results?search_query=5+сынып+математика+дөңгелек+диаграмма'),
(27, 'Прямоугольный параллелепипед (куб). Развертка', 'Прямоугольный параллелепипед (куб). Развертка', 'Тік бұрышты параллелепипед (куб). Жазба', 'Оқушылар тік бұрышты параллелепипед және куб ұғымдарымен танысады. Олардың жазбаларын салуды және осы фигуралардың қырлары, төбелері мен жақтарын анықтауды үйренеді.', 'Учащиеся знакомятся с понятиями прямоугольного параллелепипеда и куба. Учатся строить их развертки, определять ребра, вершины и грани этих фигур.', 'Оқушылар тік бұрышты параллелепипед және куб ұғымдарымен танысады. Олардың жазбаларын салуды және осы фигуралардың қырлары, төбелері мен жақтарын анықтауды үйренеді.', 'Өлшемдері 5 см, 4 см, 3 см болатын тік бұрышты параллелепипедтің жазбасын сал. Кубтың жазбасын сал (қабырғасы 4 см). Кубтың неше қыры, неше төбесі, неше жағы бар?', 'Начертите развертку прямоугольного параллелепипеда с измерениями 5 см, 4 см, 3 см. Начертите развертку куба (ребро 4 см). Сколько ребер, вершин и граней у куба?', 'Өлшемдері 5 см, 4 см, 3 см болатын тік бұрышты параллелепипедтің жазбасын сал. Кубтың жазбасын сал (қабырғасы 4 см). Кубтың неше қыры, неше төбесі, неше жағы бар?', 'https://www.youtube.com/results?search_query=5+сынып+математика+параллелепипед+жазбасы');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(28, 'Устройства компьютера', 'Устройства компьютера', 'Компьютердің құрылғылары', 'Компьютер негізгі құрылғылардан тұрады: жүйелік блок, монитор, пернетақта және тінтуір. Оқушылар әр құрылғының қызметімен танысады.', 'Компьютер состоит из основных устройств: системный блок, монитор, клавиатура и мышь. Учащиеся знакомятся с назначением каждого устройства.', 'Компьютер негізгі құрылғылардан тұрады: жүйелік блок, монитор, пернетақта және тінтуір. Оқушылар әр құрылғының қызметімен танысады.', 'Компьютердің қандай негізгі құрылғыларын білесің? Әрқайсысының қызметін түсіндір.', 'Какие основные устройства компьютера ты знаешь? Объясни назначение каждого.', 'Компьютердің қандай негізгі құрылғыларын білесің? Әрқайсысының қызметін түсіндір.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+компьютер+құрылғылары'),
(28, 'Информация и информационные процессы', 'Информация и информационные процессы', 'Ақпарат және ақпараттық процестер', 'Ақпарат дегеніміз — бізді қоршаған әлем туралы мәліметтер. Оқушылар ақпарат түрлерін (мәтіндік, сандық, графикалық, дыбыстық) және оны өңдеу жолдарын үйренеді.', 'Информация — это сведения об окружающем нас мире. Учащиеся изучают виды информации (текстовая, числовая, графическая, звуковая) и способы её обработки.', 'Ақпарат дегеніміз — бізді қоршаған әлем туралы мәліметтер. Оқушылар ақпарат түрлерін (мәтіндік, сандық, графикалық, дыбыстық) және оны өңдеу жолдарын үйренеді.', 'Ақпараттың қандай түрлерін білесің? Әр түріне мысал келтір.', 'Какие виды информации ты знаешь? Приведи пример каждого вида.', 'Ақпараттың қандай түрлерін білесің? Әр түріне мысал келтір.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+ақпарат+түрлері');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(29, 'Работа с файлами', 'Работа с файлами', 'Файлдармен жұмыс', 'Файл — бұл ақпарат сақталатын объект, ал бума (папка) — файлдарды реттеуге арналған құрал. Оқушылар файлдарды құру, көшіру, жылжыту және жою әрекеттерін үйренеді.', 'Файл — это объект, хранящий информацию, а папка — инструмент для упорядочивания файлов. Учащиеся осваивают создание, копирование, перемещение и удаление файлов.', 'Файл — бұл ақпарат сақталатын объект, ал бума (папка) — файлдарды реттеуге арналған құрал. Оқушылар файлдарды құру, көшіру, жылжыту және жою әрекеттерін үйренеді.', 'Жұмыс үстелінде ''Менің мектебім'' деген жаңа бума жасап, оған мәтіндік файл сал.', 'Создай на рабочем столе новую папку ''Моя школа'' и помести в неё текстовый файл.', 'Жұмыс үстелінде ''Менің мектебім'' деген жаңа бума жасап, оған мәтіндік файл сал.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+файл+және+бума'),
(30, 'Создание и форматирование текстового документа', 'Создание и форматирование текстового документа', 'Мәтіндік құжатты құру және пішімдеу', 'Мәтіндік редактор — мәтіндерді теріп, өңдеуге арналған бағдарлама. Оқушылар мәтінді теру, әріп қарпін, түсін және өлшемін өзгертуді үйренеді.', 'Текстовый редактор — программа для набора и редактирования текста. Учащиеся учатся набирать текст, изменять шрифт, цвет и размер букв.', 'Мәтіндік редактор — мәтіндерді теріп, өңдеуге арналған бағдарлама. Оқушылар мәтінді теру, әріп қарпін, түсін және өлшемін өзгертуді үйренеді.', '''Менің отбасым'' туралы 5 сөйлемнен тұратын мәтін теріп, тақырыпты қою әріппен және қызыл түспен безендір.', 'Набери текст из 5 предложений ''Моя семья'', оформи заголовок жирным шрифтом красного цвета.', '''Менің отбасым'' туралы 5 сөйлемнен тұратын мәтін теріп, тақырыпты қою әріппен және қызыл түспен безендір.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+мәтіндік+редактор+Word'),
(31, 'Рисование и редактирование изображений', 'Рисование и редактирование изображений', 'Сурет салу және өңдеу', 'Графикалық редакторда сурет салуға және оны өңдеуге болады. Оқушылар құралдар тақтасын пайдаланып, қарапайым суреттер салуды және түстермен жұмыс істеуді үйренеді.', 'В графическом редакторе можно рисовать и редактировать изображения. Учащиеся учатся пользоваться панелью инструментов, рисовать простые рисунки и работать с цветами.', 'Графикалық редакторда сурет салуға және оны өңдеуге болады. Оқушылар құралдар тақтасын пайдаланып, қарапайым суреттер салуды және түстермен жұмыс істеуді үйренеді.', 'Графикалық редакторда ''Менің үйім'' деген тақырыпта сурет салып, оны әртүрлі түстермен боя.', 'В графическом редакторе нарисуй рисунок на тему ''Мой дом'' и раскрась его разными цветами.', 'Графикалық редакторда ''Менің үйім'' деген тақырыпта сурет салып, оны әртүрлі түстермен боя.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+графикалық+редактор'),
(32, 'Создание слайдов', 'Создание слайдов', 'Слайдтар құру', 'Презентация — ақпаратты көрнекі түрде ұсыну тәсілі. Оқушылар слайдтар құруды, мәтін мен сурет қосуды және дизайн таңдауды меңгереді.', 'Презентация — способ наглядного представления информации. Учащиеся осваивают создание слайдов, добавление текста и изображений, выбор дизайна.', 'Презентация — ақпаратты көрнекі түрде ұсыну тәсілі. Оқушылар слайдтар құруды, мәтін мен сурет қосуды және дизайн таңдауды меңгереді.', '''Менің хоббиім'' тақырыбында 3 слайдтан тұратын презентация жаса.', 'Создай презентацию из 3 слайдов на тему ''Моё хобби''.', '''Менің хоббиім'' тақырыбында 3 слайдтан тұратын презентация жаса.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+презентация+құру'),
(33, 'Понятие алгоритма. Линейный алгоритм', 'Понятие алгоритма. Линейный алгоритм', 'Алгоритм ұғымы. Сызықтық алгоритм', 'Алгоритм — бір ізбен орындалатын әрекеттер тізбегі. Оқушылар сызықтық алгоритмдер құруды және оларды блок-схема түрінде көрсетуді үйренеді.', 'Алгоритм — последовательность действий, выполняемых по порядку. Учащиеся учатся составлять линейные алгоритмы и изображать их в виде блок-схем.', 'Алгоритм — бір ізбен орындалатын әрекеттер тізбегі. Оқушылар сызықтық алгоритмдер құруды және оларды блок-схема түрінде көрсетуді үйренеді.', '''Таңертеңгілік дайындық'' алгоритмін құрастыр: тіс тазалау, жуыну, таңғы ас ішу, мектепке бару.', 'Составь алгоритм ''Утренняя подготовка'': почистить зубы, умыться, позавтракать, пойти в школу.', '''Таңертеңгілік дайындық'' алгоритмін құрастыр: тіс тазалау, жуыну, таңғы ас ішу, мектепке бару.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+алгоритм+блок+схема'),
(34, 'Правила безопасности в интернете', 'Правила безопасности в интернете', 'Интернеттегі қауіпсіздік ережелері', 'Интернетте қауіпсіз жүру ережелерін білу маңызды. Оқушылар жеке деректерді қорғау, күдікті сілтемелерден сақтану және виртуалды қарым-қатынас мәдениеті туралы біледі.', 'Важно знать правила безопасного поведения в интернете. Учащиеся узнают о защите личных данных, осторожности с подозрительными ссылками и культуре виртуального общения.', 'Интернетте қауіпсіз жүру ережелерін білу маңызды. Оқушылар жеке деректерді қорғау, күдікті сілтемелерден сақтану және виртуалды қарым-қатынас мәдениеті туралы біледі.', 'Интернетте бейтаныс адамнан хат келсе, не істейсің? Қауіпсіздіктің үш ережесін жаз.', 'Что ты сделаешь, если получишь письмо от незнакомца в интернете? Напиши три правила безопасности.', 'Интернетте бейтаныс адамнан хат келсе, не істейсің? Қауіпсіздіктің үш ережесін жаз.', 'https://www.youtube.com/results?search_query=5+сынып+информатика+интернет+қауіпсіздігі');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(35, 'Роль науки', 'Роль науки', 'Ғылымның рөлі', 'Ғылым адамзатқа табиғат құбылыстарын түсінуге және жаңа технологиялар жасауға көмектеседі. Оқушылар ғылымның адам өміріндегі маңызымен танысады.', 'Наука помогает человечеству понимать явления природы и создавать новые технологии. Учащиеся знакомятся со значением науки в жизни человека.', 'Ғылым адамзатқа табиғат құбылыстарын түсінуге және жаңа технологиялар жасауға көмектеседі. Оқушылар ғылымның адам өміріндегі маңызымен танысады.', 'Ғылымның адам өміріндегі рөлі туралы 3 мысал келтір. Мысалы, медицина, техника, экология.', 'Приведи 3 примера роли науки в жизни человека. Например: медицина, техника, экология.', 'Ғылымның адам өміріндегі рөлі туралы 3 мысал келтір. Мысалы, медицина, техника, экология.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+ғылым+рөлі'),
(35, 'Вопрос исследования и предположение', 'Вопрос исследования и предположение', 'Зерттеу сұрағы және болжау', 'Зерттеу сұрағы — біз білгіміз келетін нәрсе, ал болжам — оның жауабы туралы жорамал. Оқушылар зерттеу сұрағын құрастыруды және болжам жасауды үйренеді.', 'Вопрос исследования — то, что мы хотим узнать, а гипотеза — предположение об ответе. Учащиеся учатся формулировать вопрос исследования и выдвигать гипотезу.', 'Зерттеу сұрағы — біз білгіміз келетін нәрсе, ал болжам — оның жауабы туралы жорамал. Оқушылар зерттеу сұрағын құрастыруды және болжам жасауды үйренеді.', 'Өсімдіктердің өсуіне жарық қалай әсер етеді? Осы сұраққа болжам жасап жаз.', 'Как свет влияет на рост растений? Сформулируй гипотезу по этому вопросу.', 'Өсімдіктердің өсуіне жарық қалай әсер етеді? Осы сұраққа болжам жасап жаз.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+зерттеу+сұрағы'),
(35, 'Планирование исследования', 'Планирование исследования', 'Зерттеуді жоспарлау', 'Зерттеуді жоспарлау — эксперименттің мақсатын, қадамдарын және қажетті материалдарын анықтау. Оқушылар қарапайым зерттеу жоспарын құруды үйренеді.', 'Планирование исследования — определение цели, шагов и необходимых материалов эксперимента. Учащиеся учатся составлять простой план исследования.', 'Зерттеуді жоспарлау — эксперименттің мақсатын, қадамдарын және қажетті материалдарын анықтау. Оқушылар қарапайым зерттеу жоспарын құруды үйренеді.', '''Тұз бен қанттың суда еруі'' тақырыбында зерттеу жоспарын құрастыр.', 'Составь план исследования на тему ''Растворение соли и сахара в воде''.', '''Тұз бен қанттың суда еруі'' тақырыбында зерттеу жоспарын құрастыр.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+зерттеу+жоспар'),
(35, 'Сбор и запись данных', 'Сбор и запись данных', 'Мәліметтерді жинау және жазу', 'Мәліметтерді жинау — бақылау немесе эксперимент нәтижелерін тіркеу. Оқушылар кестелер мен диаграммаларды пайдаланып деректерді жазып алуды үйренеді.', 'Сбор данных — регистрация результатов наблюдения или эксперимента. Учащиеся учатся записывать данные с помощью таблиц и диаграмм.', 'Мәліметтерді жинау — бақылау немесе эксперимент нәтижелерін тіркеу. Оқушылар кестелер мен диаграммаларды пайдаланып деректерді жазып алуды үйренеді.', 'Апта бойы ауа температурасын өлшеп, нәтижелерді кестеге түсір.', 'Измеряй температуру воздуха в течение недели и запиши результаты в таблицу.', 'Апта бойы ауа температурасын өлшеп, нәтижелерді кестеге түсір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+мәлімет+жинау'),
(35, 'Анализ данных', 'Анализ данных', 'Мәліметтерді талдау', 'Мәліметтерді талдау — жиналған деректерді салыстыру және заңдылықтарды анықтау. Оқушылар бақылау نәтижелерін қорытындылауды үйренеді.', 'Анализ данных — сравнение собранных данных и выявление закономерностей. Учащиеся учатся обобщать результаты наблюдений.', 'Мәліметтерді талдау — жиналған деректерді салыстыру және заңдылықтарды анықтау. Оқушылар бақылау нәтижелерін қорытындылауды үйренеді.', 'Апталық температура кестесін қарап: ең жылы және ең суық күнді анықта.', 'Посмотри на таблицу недельной температуры: определи самый тёплый и самый холодный день.', 'Апталық температура кестесін қарап: ең жылы және ең суық күнді анықта.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+мәлімет+талдау'),
(35, 'Вывод и обсуждение', 'Вывод и обсуждение', 'Қорытынды және талқылау', 'Қорытынды — зерттеу нәтижелері бойынша жасалған тұжырым. Оқушылар бастапқы болжамды нәтижемен салыстырып, қорытынды жазуға машықтанады.', 'Вывод — заключение по результатам исследования. Учащиеся тренируются сравнивать гипотезу с результатами и формулировать вывод.', 'Қорытынды — зерттеу нәтижелері бойынша жасалған тұжырым. Оқушылар бастапқы болжамды нәтижемен салыстырып, қорытынды жазуға машықтанады.', 'Тұз бен қанттың суда еруі туралы зерттеуіңнің қорытындысын жаз. Болжамың расталды ма?', 'Напиши вывод своего исследования о растворении соли и сахара. Подтвердилась ли твоя гипотеза?', 'Тұз бен қанттың суда еруі туралы зерттеуіңнің қорытындысын жаз. Болжамың расталды ма?', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+қорытынды+жазу');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(36, 'Макро- и микромир', 'Макро- и микромир', 'Макро- және микроәлем', 'Макроәлем — бізді қоршаған үлкен нысандар, микроәлем — көзге көрінбейтін ұсақ бөлшектер. Оқушылар бұл екі әлемнің айырмашылығын біледі.', 'Макромир — окружающие нас крупные объекты, микромир — невидимые глазом частицы. Учащиеся узнают различие между этими мирами.', 'Макроәлем — бізді қоршаған үлкен нысандар, микроәлем — көзге көрінбейтін ұсақ бөлшектер. Оқушылар бұл екі әлемнің айырмашылығын біледі.', 'Макроәлем мен микроәлемге 3-тен мысал келтір. Мысалы, макро: планета, үй; микро: атом, бактерия.', 'Приведи по 3 примера макромира и микромира. Например, макро: планета, дом; микро: атом, бактерия.', 'Макроәлем мен микроәлемге 3-тен мысал келтір. Мысалы, макро: планета, үй; микро: атом, бактерия.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+макро+микроәлем'),
(36, 'Происхождение планеты Земля', 'Происхождение планеты Земля', 'Жер планетасының пайда болуы', 'Жер шары шамамен 4,6 миллиард жыл бұрын ғарыштық тозаң мен газдан пайда болды. Оқушылар Жердің пайда болуы туралы ғылыми теориямен танысады.', 'Земля образовалась около 4,6 миллиарда лет назад из космической пыли и газа. Учащиеся знакомятся с научной теорией происхождения Земли.', 'Жер шары шамамен 4,6 миллиард жыл бұрын ғарыштық тозаң мен газдан пайда болды. Оқушылар Жердің пайда болуы туралы ғылыми теориямен танысады.', 'Жер қалай пайда болды? Оның пайда болуы туралы 3 негізгі факті жаз.', 'Как образовалась Земля? Напиши 3 основных факта о её происхождении.', 'Жер қалай пайда болды? Оның пайда болуы туралы 3 негізгі факті жаз.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+жер+пайда+болуы'),
(36, 'Строение и состав Земли', 'Строение и состав Земли', 'Жер құрылысы мен құрамы', 'Жер үш қабаттан тұрады: қыртыс, мантия және ядро. Оқушылар әр қабаттың ерекшеліктерімен және құрамымен танысады.', 'Земля состоит из трёх слоёв: земная кора, мантия и ядро. Учащиеся знакомятся с особенностями и составом каждого слоя.', 'Жер үш қабаттан тұрады: қыртыс, мантия және ядро. Оқушылар әр қабаттың ерекшеліктерімен және құрамымен танысады.', 'Жердің ішкі құрылысын суреттеп, әр қабатын ата.', 'Изобрази внутреннее строение Земли и назови каждый слой.', 'Жердің ішкі құрылысын суреттеп, әр қабатын ата.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+жер+құрылысы'),
(36, 'Сферы Земли', 'Сферы Земли', 'Жер сфералары', 'Жердің төрт сферасы бар: литосфера (қатты қабық), гидросфера (су), атмосфера (ауа) және биосфера (тіршілік). Оқушылар әр сфераның сипаттамасын біледі.', 'У Земли четыре сферы: литосфера (твёрдая оболочка), гидросфера (вода), атмосфера (воздух) и биосфера (жизнь). Учащиеся узнают характеристику каждой сферы.', 'Жердің төрт сферасы бар: литосфера (қатты қабық), гидросфера (су), атмосфера (ауа) және биосфера (тіршілік). Оқушылар әр сфераның сипаттамасын біледі.', 'Жер сфераларын атап, әрқайсысына бір-бір мысал келтір.', 'Назови сферы Земли и приведи по одному примеру к каждой.', 'Жер сфераларын атап, әрқайсысына бір-бір мысал келтір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+жер+сфералары');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(37, 'Тела и вещества', 'Тела и вещества', 'Денелер және заттар', 'Физикалық дене — бізді қоршаған заттар, ал зат — дененің құралған материалы. Оқушылар дене мен заттың айырмашылығын үйренеді.', 'Физическое тело — окружающие нас предметы, а вещество — материал, из которого состоит тело. Учащиеся учатся различать тело и вещество.', 'Физикалық дене — бізді қоршаған заттар, ал зат — дененің құралған материалы. Оқушылар дене мен заттың айырмашылығын үйренеді.', '3 дене және олардың қандай заттан жасалғанын жаз. Мысалы: қасық — темір, кітап — қағаз.', 'Напиши 3 тела и из какого вещества они сделаны. Например: ложка — железо, книга — бумага.', '3 дене және олардың қандай заттан жасалғанын жаз. Мысалы: қасық — темір, кітап — қағаз.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+дене+зат'),
(37, 'Классификация веществ', 'Классификация веществ', 'Заттардың классификациясы', 'Заттар қатты, сұйық және газ тәрізді күйде болады. Оқушылар заттарды агрегаттық күйі бойынша жіктеуді үйренеді.', 'Вещества бывают в твёрдом, жидком и газообразном состоянии. Учащиеся учатся классифицировать вещества по агрегатному состоянию.', 'Заттар қатты, сұйық және газ тәрізді күйде болады. Оқушылар заттарды агрегаттық күйі бойынша жіктеуді үйренеді.', 'Әр агрегаттық күйге 2 мысалдан келтір: қатты, сұйық, газ.', 'Приведи по 2 примера каждого агрегатного состояния: твёрдое, жидкое, газообразное.', 'Әр агрегаттық күйге 2 мысалдан келтір: қатты, сұйық, газ.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+зат+классификациясы'),
(37, 'Свойства веществ', 'Свойства веществ', 'Заттардың қасиеттері', 'Заттардың физикалық (түсі, иісі, қаттылығы, балқу температурасы) және химиялық қасиеттері болады. Оқушылар заттарды сипаттауға үйренеді.', 'Вещества обладают физическими (цвет, запах, твёрдость, температура плавления) и химическими свойствами. Учащиеся учатся описывать вещества.', 'Заттардың физикалық (түсі, иісі, қаттылығы, балқу температурасы) және химиялық қасиеттері болады. Оқушылар заттарды сипаттауға үйренеді.', 'Судың физикалық қасиеттерін сипатта: түсі, иісі, дәмі, қайнау температурасы.', 'Опиши физические свойства воды: цвет, запах, вкус, температура кипения.', 'Судың физикалық қасиеттерін сипатта: түсі, иісі, дәмі, қайнау температурасы.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+зат+қасиеті'),
(37, 'Физические и химические явления', 'Физические и химические явления', 'Физикалық және химиялық құбылыстар', 'Физикалық құбылыста заттың құрамы өзгермейді, ал химиялық құбылыста жаңа зат пайда болады. Оқушылар бұл құбылыстарды ажыратуды үйренеді.', 'При физическом явлении состав вещества не меняется, а при химическом образуется новое вещество. Учащиеся учатся различать эти явления.', 'Физикалық құбылыста заттың құрамы өзгермейді, ал химиялық құбылыста жаңа зат пайда болады. Оқушылар бұл құбылыстарды ажыратуды үйренеді.', 'Берілген құбылыстардың қайсысы физикалық, қайсысы химиялық: судың қайнауы, темірдің тот басуы, шамның жануы.', 'Определи, какие явления физические, а какие химические: кипение воды, ржавление железа, горение свечи.', 'Берілген құбылыстардың қайсысы физикалық, қайсысы химиялық: судың қайнауы, темірдің тот басуы, шамның жануы.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+физикалық+химиялық+құбылыс'),
(37, 'Вода. Свойства воды', 'Вода. Свойства воды', 'Су. Судың қасиеттері', 'Су — тіршілік көзі. Оның үш күйі бар: қатты (мұз), сұйық (су), газ (бу). Оқушылар судың физикалық қасиеттері мен маңыздылығын зерттейді.', 'Вода — источник жизни. У неё три состояния: твёрдое (лёд), жидкое (вода), газообразное (пар). Учащиеся изучают физические свойства и значение воды.', 'Су — тіршілік көзі. Оның үш күйі бар: қатты (мұз), сұйық (су), газ (бу). Оқушылар судың физикалық қасиеттері мен маңыздылығын зерттейді.', 'Судың қандай қасиеттерін білесің? Судың қайнау және қату температурасы қандай?', 'Какие свойства воды ты знаешь? Каковы температура кипения и замерзания воды?', 'Судың қандай қасиеттерін білесің? Судың қайнау және қату температурасы қандай?', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+су+қасиеттері'),
(37, 'Воздух. Состав воздуха', 'Воздух. Состав воздуха', 'Ауа. Ауаның құрамы', 'Ауа — газдардың қоспасы. Оның құрамында азот (78%), оттегі (21%) және басқа газдар бар. Оқушылар ауаның құрамы мен маңызын біледі.', 'Воздух — смесь газов. В его составе азот (78%), кислород (21%) и другие газы. Учащиеся узнают состав и значение воздуха.', 'Ауа — газдардың қоспасы. Оның құрамында азот (78%), оттегі (21%) және басқа газдар бар. Оқушылар ауаның құрамы мен маңызын біледі.', 'Ауаның құрамында қандай газдар бар? Олардың пайыздық мөлшерін ата.', 'Какие газы входят в состав воздуха? Назови их процентное содержание.', 'Ауаның құрамында қандай газдар бар? Олардың пайыздық мөлшерін ата.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+ауа+құрамы'),
(37, 'Полезные ископаемые', 'Полезные ископаемые', 'Пайдалы қазбалар', 'Пайдалы қазбалар — жер қойнауындағы табиғи ресурстар: мұнай, көмір, металдар, құрылыс материалдары. Оқушылар олардың түрлері мен қолданылуын біледі.', 'Полезные ископаемые — природные ресурсы в недрах земли: нефть, уголь, металлы, стройматериалы. Учащиеся узнают их виды и применение.', 'Пайдалы қазбалар — жер қойнауындағы табиғи ресурстар: мұнай, көмір, металдар, құрылыс материалдары. Оқушылар олардың түрлері мен қолданылуын біледі.', 'Қазақстанда қандай пайдалы қазбалар өндіріледі? 5 мысал келтір.', 'Какие полезные ископаемые добывают в Казахстане? Приведи 5 примеров.', 'Қазақстанда қандай пайдалы қазбалар өндіріледі? 5 мысал келтір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+пайдалы+қазбалар');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(38, 'Разнообразие живых организмов', 'Разнообразие живых организмов', 'Тірі ағзалардың алуантүрлілігі', 'Тірі ағзалар төрт патшалыққа бөлінеді: өсімдіктер, жануарлар, саңырауқұлақтар және микроорганизмдер. Оқушылар әр патшалықтың ерекшеліктерін біледі.', 'Живые организмы делятся на четыре царства: растения, животные, грибы и микроорганизмы. Учащиеся узнают особенности каждого царства.', 'Тірі ағзалар төрт патшалыққа бөлінеді: өсімдіктер, жануарлар, саңырауқұлақтар және микроорганизмдер. Оқушылар әр патшалықтың ерекшеліктерін біледі.', 'Тірі ағзалардың төрт патшалығын атап, әрқайсысына 2 мысал келтір.', 'Назови четыре царства живых организмов, приведи по 2 примера каждого.', 'Тірі ағзалардың төрт патшалығын атап, әрқайсысына 2 мысал келтір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+тірі+ағзалар'),
(38, 'Клетка', 'Клетка', 'Жасуша', 'Жасуша — тірі ағзаның ең кіші құрылымдық бірлігі. Оқушылар жасушаның негізгі бөліктерімен (мембрана, цитоплазма, ядро) танысады.', 'Клетка — наименьшая структурная единица живого организма. Учащиеся знакомятся с основными частями клетки (мембрана, цитоплазма, ядро).', 'Жасуша — тірі ағзаның ең кіші құрылымдық бірлігі. Оқушылар жасушаның негізгі бөліктерімен (мембрана, цитоплазма, ядро) танысады.', 'Жасушаның негізгі үш бөлігін атап, әрқайсысының қызметін түсіндір.', 'Назови три основные части клетки и объясни функцию каждой.', 'Жасушаның негізгі үш бөлігін атап, әрқайсысының қызметін түсіндір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+жасуша+құрылысы'),
(38, 'Экосистемы', 'Экосистемы', 'Экожүйелер', 'Экожүйе — тірі ағзалар мен олардың тіршілік ортасының бірлігі. Оқушылар орман, көл, шөл сияқты экожүйелермен және олардың компоненттерімен танысады.', 'Экосистема — единство живых организмов и среды их обитания. Учащиеся знакомятся с экосистемами (лес, озеро, пустыня) и их компонентами.', 'Экожүйе — тірі ағзалар мен олардың тіршілік ортасының бірлігі. Оқушылар орман, көл, шөл сияқты экожүйелермен және олардың компоненттерімен танысады.', 'Өзіңе белгілі бір экожүйені (мысалы, көл) сипаттап, онда кездесетін тірі ағзаларды жаз.', 'Опиши известную тебе экосистему (например, озеро) и назови живые организмы, которые в ней обитают.', 'Өзіңе белгілі бір экожүйені (мысалы, көл) сипаттап, онда кездесетін тірі ағзаларды жаз.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+экожүйе'),
(39, 'Сила и движение', 'Сила и движение', 'Күш және қозғалыс', 'Күш — денеге әсер етіп, оның қозғалысын өзгертетін шама. Оқушылар күш түрлерімен (тартылыс, үйкеліс, серпімділік) танысады.', 'Сила — величина, воздействуя на тело, изменяющая его движение. Учащиеся знакомятся с видами сил (тяжести, трения, упругости).', 'Күш — денеге әсер етіп, оның қозғалысын өзгертетін шама. Оқушылар күш түрлерімен (тартылыс, үйкеліс, серпімділік) танысады.', 'Күштің қандай түрлерін білесің? Әрқайсысына бір мысал келтір.', 'Какие виды силы ты знаешь? Приведи пример каждого вида.', 'Күштің қандай түрлерін білесің? Әрқайсысына бір мысал келтір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+күш+қозғалыс'),
(39, 'Источники энергии', 'Источники энергии', 'Энергия көздері', 'Энергия көздері — табиғи ресурстардан алынатын қуат. Олар жаңғыртылатын (күн, жел, су) және жаңғыртылмайтын (көмір, мұнай, газ) болып бөлінеді.', 'Источники энергии — мощность, получаемая из природных ресурсов. Они делятся на возобновляемые (солнце, ветер, вода) и невозобновляемые (уголь, нефть, газ).', 'Энергия көздері — табиғи ресурстардан алынатын қуат. Олар жаңғыртылатын (күн, жел, су) және жаңғыртылмайтын (көмір, мұнай, газ) болып бөлінеді.', 'Жаңғыртылатын және жаңғыртылмайтын энергия көздеріне 3 мысалдан келтір.', 'Приведи по 3 примера возобновляемых и невозобновляемых источников энергии.', 'Жаңғыртылатын және жаңғыртылмайтын энергия көздеріне 3 мысалдан келтір.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+энергия+көздері'),
(40, 'Экологические факторы', 'Экологические факторы', 'Экологиялық факторлар', 'Экологиялық факторлар — тірі ағзаларға әсер ететін орта жағдайлары: жарық, температура, су, топырақ. Оқушылар факторлардың маңызын біледі.', 'Экологические факторы — условия среды, влияющие на живые организмы: свет, температура, вода, почва. Учащиеся узнают значение этих факторов.', 'Экологиялық факторлар — тірі ағзаларға әсер ететін орта жағдайлары: жарық, температура, су, топырақ. Оқушылар факторлардың маңызын біледі.', 'Өсімдіктің өсуіне қандай экологиялық факторлар әсер етеді? 4 факторды ата.', 'Какие экологические факторы влияют на рост растения? Назови 4 фактора.', 'Өсімдіктің өсуіне қандай экологиялық факторлар әсер етеді? 4 факторды ата.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+экология+факторлар'),
(40, 'Охрана окружающей среды', 'Охрана окружающей среды', 'Қоршаған ортаны қорғау', 'Қоршаған ортаны қорғау — әр адамның міндеті. Оқушылар қоқысты сұрыптау, суды үнемдеу, ағаш отырғызу сияқты қарапайым әрекеттердің маңызын түсінеді.', 'Охрана окружающей среды — долг каждого человека. Учащиеся понимают важность простых действий: сортировка мусора, экономия воды, посадка деревьев.', 'Қоршаған ортаны қорғау — әр адамның міндеті. Оқушылар қоқысты сұрыптау, суды үнемдеу, ағаш отырғызу сияқты қарапайым әрекеттердің маңызын түсінеді.', 'Қоршаған ортаны қорғау үшін сен не істей аласың? 5 ұсыныс жаз.', 'Что ты можешь сделать для охраны окружающей среды? Напиши 5 предложений.', 'Қоршаған ортаны қорғау үшін сен не істей аласың? 5 ұсыныс жаз.', 'https://www.youtube.com/results?search_query=5+сынып+жаратылыстану+қоршаған+орта+қорғау');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(41, 'Что такое история?', 'Что такое история?', 'Тарих дегеніміз не?', 'Тарих — адамзаттың өткен өмірі туралы ғылым. Оқушылар тарихтың не зерттейтінін және оның маңызын түсінеді.', 'История — наука о прошлом человечества. Учащиеся понимают, что изучает история и каково её значение.', 'Тарих — адамзаттың өткен өмірі туралы ғылым. Оқушылар тарихтың не зерттейтінін және оның маңызын түсінеді.', 'Тарих дегеніміз не? Тарихты білу не үшін қажет? Өз ойыңды жаз.', 'Что такое история? Зачем нужно знать историю? Напиши своё мнение.', 'Тарих дегеніміз не? Тарихты білу не үшін қажет? Өз ойыңды жаз.', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+кіріспе'),
(41, 'Исторические источники и их виды', 'Исторические источники и их виды', 'Тарихи деректер және олардың түрлері', 'Тарихи деректер — өткен заман туралы мәліметтер. Олар жазба, материалдық және ауызша болып бөлінеді. Оқушылар деректердің түрлерін ажыратуды үйренеді.', 'Исторические источники — сведения о прошлом. Они делятся на письменные, вещественные и устные. Учащиеся учатся различать виды источников.', 'Тарихи деректер — өткен заман туралы мәліметтер. Олар жазба, материалдық және ауызша болып бөлінеді. Оқушылар деректердің түрлерін ажыратуды үйренеді.', 'Үш түрлі тарихи дерекке мысал келтір: жазба, материалдық, ауызша.', 'Приведи примеры трёх видов исторических источников: письменный, вещественный, устный.', 'Үш түрлі тарихи дерекке мысал келтір: жазба, материалдық, ауызша.', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+деректер'),
(41, 'Историческая карта и хронология', 'Историческая карта и хронология', 'Тарихи карта және хронология', 'Тарихи карта өткен кезеңдегі аумақтарды көрсетеді, хронология уақыт реттілігін анықтайды. Оқушылар картамен жұмыс істеуді және уақыт белдеуін пайдалануды үйренеді.', 'Историческая карта показывает территории в прошлом, хронология определяет последовательность событий. Учащиеся учатся работать с картой и лентой времени.', 'Тарихи карта өткен кезеңдегі аумақтарды көрсетеді, хронология уақыт реттілігін анықтайды. Оқушылар картамен жұмыс істеуді және уақыт белдеуін пайдалануды үйренеді.', 'Уақыт белдеуіне Қазақстан тарихының 5 маңызды оқиғасын орналастыр.', 'Расположи на ленте времени 5 важных событий истории Казахстана.', 'Уақыт белдеуіне Қазақстан тарихының 5 маңызды оқиғасын орналастыр.', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+хронология');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(42, 'Каменный век в Казахстане', 'Каменный век в Казахстане', 'Тас дәуіріндегі Қазақстан', 'Тас дәуірі — адамзат тарихының ең ұзақ кезеңі. Оқушылар Қазақстан аумағындағы палеолит, мезолит және неолит дәуірлерінің ерекшеліктерімен танысады.', 'Каменный век — самый длительный период в истории человечества. Учащиеся знакомятся с особенностями палеолита, мезолита и неолита на территории Казахстана.', 'Тас дәуірі — адамзат тарихының ең ұзақ кезеңі. Оқушылар Қазақстан аумағындағы палеолит, мезолит және неолит дәуірлерінің ерекшеліктерімен танысады.', 'Тас дәуірінің үш кезеңін атап, әрқайсысына сипаттама бер.', 'Назови три периода каменного века и дай характеристику каждому.', 'Тас дәуірінің үш кезеңін атап, әрқайсысына сипаттама бер.', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+тас+дәуірі'),
(42, 'Эпоха бронзы', 'Эпоха бронзы', 'Қола дәуірі', 'Қола дәуірінде адамдар металл өңдеуді үйренді. Оқушылар Андрон және Беғазы-Дәндібай мәдениеттерінің ерекшеліктерімен танысады.', 'В эпоху бронзы люди научились обрабатывать металл. Учащиеся знакомятся с особенностями андроновской и бегазы-дандыбаевской культур.', 'Қола дәуірінде адамдар металл өңдеуді үйренді. Оқушылар Андрон және Беғазы-Дәндібай мәдениеттерінің ерекшеліктерімен танысады.', 'Қола дәуірінің адамдары қандай металл өңдеуді үйренді? Андрон мәдениетінің ерекшелігі неде?', 'Какой металл научились обрабатывать люди в эпоху бронзы? В чём особенность андроновской культуры?', 'Қола дәуірінің адамдары қандай металл өңдеуді үйренді? Андрон мәдениетінің ерекшелігі неде?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+қола+дәуірі'),
(42, 'Ранний железный век. Саки', 'Ранний железный век. Саки', 'Ерте темір дәуірі. Сақтар', 'Сақтар — ежелгі Қазақстан жерін мекендеген тайпалар. Олар әскери өнерімен және аң стилі өнерімен танымал. Оқушылар сақтардың тұрмысы мен мәдениетін біледі.', 'Саки — племена, населявшие древний Казахстан. Они славились военным искусством и звериным стилем. Учащиеся узнают о быте и культуре саков.', 'Сақтар — ежелгі Қазақстан жерін мекендеген тайпалар. Олар әскери өнерімен және аң стилі өнерімен танымал. Оқушылар сақтардың тұрмысы мен мәдениетін біледі.', 'Сақтардың қоғамдық құрылысы қандай болды? Аң стилі дегеніміз не?', 'Каким было общественное устройство саков? Что такое звериный стиль?', 'Сақтардың қоғамдық құрылысы қандай болды? Аң стилі дегеніміз не?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+сақтар'),
(42, 'Гунны', 'Гунны', 'Ғұндар', 'Ғұндар — көшпелі тайпалар одағы. Олардың әйгілі көсемі Аттила болды. Оқушылар ғұндардың өмірі мен жаулап алу жорықтары туралы біледі.', 'Гунны — союз кочевых племён. Их знаменитым вождём был Аттила. Учащиеся узнают о жизни и завоевательных походах гуннов.', 'Ғұндар — көшпелі тайпалар одағы. Олардың әйгілі көсемі Аттила болды. Оқушылар ғұндардың өмірі мен жаулап алу жорықтары туралы біледі.', 'Ғұндардың әйгілі көсемі кім болды? Ғұндар қандай аумақтарды жаулап алды?', 'Кто был знаменитым вождём гуннов? Какие территории завоевали гунны?', 'Ғұндардың әйгілі көсемі кім болды? Ғұндар қандай аумақтарды жаулап алды?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+ғұндар'),
(42, 'Тюркский каганат', 'Тюркский каганат', 'Түрік қағанаты', 'Түрік қағанаты — VI ғасырда құрылған алғашқы түрік мемлекеті. Оқушылар қағанаттың құрылуы, дамуы және мәдениеті туралы біледі.', 'Тюркский каганат — первое тюркское государство, образованное в VI веке. Учащиеся узнают о создании, развитии и культуре каганата.', 'Түрік қағанаты — VI ғасырда құрылған алғашқы түрік мемлекеті. Оқушылар қағанаттың құрылуы, дамуы және мәдениеті туралы біледі.', 'Түрік қағанаты қашан және қай жерде құрылды? Оның негізін қалаушы кім?', 'Когда и где был образован Тюркский каганат? Кто был его основателем?', 'Түрік қағанаты қашан және қай жерде құрылды? Оның негізін қалаушы кім?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+түрік+қағанаты');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(43, 'Древние города', 'Древние города', 'Көне қалалар', 'Қазақстан аумағында көне қалалар көп болған: Отырар, Тараз, Сайрам, Түркістан. Оқушылар бұл қалалардың тарихы мен маңызын біледі.', 'На территории Казахстана было много древних городов: Отрар, Тараз, Сайрам, Туркестан. Учащиеся узнают историю и значение этих городов.', 'Қазақстан аумағында көне қалалар көп болған: Отырар, Тараз, Сайрам, Түркістан. Оқушылар бұл қалалардың тарихы мен маңызын біледі.', 'Қазақстандағы үш көне қаланы атап, олардың қайда орналасқанын айт.', 'Назови три древних города Казахстана и скажи, где они расположены.', 'Қазақстандағы үш көне қаланы атап, олардың қайда орналасқанын айт.', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+көне+қалалар'),
(43, 'Великий Шелковый путь', 'Великий Шелковый путь', 'Ұлы Жібек жолы', 'Ұлы Жібек жолы — Қытай мен Еуропаны байланыстырған көне сауда жолы. Оқушылар бұл жолдың Қазақстан арқылы өткен бағыттары мен маңызын біледі.', 'Великий Шёлковый путь — древний торговый путь, связывавший Китай и Европу. Учащиеся узнают о маршрутах, проходивших через Казахстан, и значении этого пути.', 'Ұлы Жібек жолы — Қытай мен Еуропаны байланыстырған көне сауда жолы. Оқушылар бұл жолдың Қазақстан арқылы өткен бағыттары мен маңызын біледі.', 'Ұлы Жібек жолы бойында қандай тауарлар тасымалданды? Ол Қазақстан үшін неліктен маңызды болды?', 'Какие товары перевозили по Великому Шёлковому пути? Почему он был важен для Казахстана?', 'Ұлы Жібек жолы бойында қандай тауарлар тасымалданды? Ол Қазақстан үшін неліктен маңызды болды?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+ұлы+жібек+жолы'),
(43, 'Древние ремесла и быт', 'Древние ремесла и быт', 'Көне қолөнер және тұрмыс', 'Көне адамдар әртүрлі қолөнермен айналысты: қыш жасау, ұсталық, тоқыма. Оқушылар ертедегі адамдардың күнделікті тұрмысымен танысады.', 'Древние люди занимались различными ремёслами: гончарное дело, кузнечество, ткачество. Учащиеся знакомятся с повседневным бытом древних людей.', 'Көне адамдар әртүрлі қолөнермен айналысты: қыш жасау, ұсталық, тоқыма. Оқушылар ертедегі адамдардың күнделікті тұрмысымен танысады.', 'Көне адамдардың қандай қолөнер түрлерін білесің? Олардың әрқайсысының маңызын түсіндір.', 'Какие виды ремёсел древних людей ты знаешь? Объясни значение каждого.', 'Көне адамдардың қандай қолөнер түрлерін білесің? Олардың әрқайсысының маңызын түсіндір.', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+қолөнер');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(44, 'Мировоззрение кочевников', 'Мировоззрение кочевников', 'Көшпелілердің дүниетанымы', 'Көшпелілер табиғатпен тығыз байланыста өмір сүрді, аспанға, жерге және ата-баба рухына табынды. Оқушылар көшпелілердің дүниетанымы мен әдет-ғұрыптарын біледі.', 'Кочевники жили в тесной связи с природой, поклонялись небу, земле и духам предков. Учащиеся узнают мировоззрение и обычаи кочевников.', 'Көшпелілер табиғатпен тығыз байланыста өмір сүрді, аспанға, жерге және ата-баба рухына табынды. Оқушылар көшпелілердің дүниетанымы мен әдет-ғұрыптарын біледі.', 'Көшпелілердің қандай наным-сенімдерін білесің? Олар табиғатқа қалай қарады?', 'Какие верования кочевников ты знаешь? Как они относились к природе?', 'Көшпелілердің қандай наным-сенімдерін білесің? Олар табиғатқа қалай қарады?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+көшпелілер'),
(44, 'Звериный стиль', 'Звериный стиль', 'Аң стилі', 'Аң стилі — сақтардың бейнелеу өнеріндегі ерекше бағыт, онда жануарлар бейнелері қолданылды. Оқушылар аң стилінің ерекшеліктерімен танысады.', 'Звериный стиль — особое направление в изобразительном искусстве саков с изображениями животных. Учащиеся знакомятся с особенностями звериного стиля.', 'Аң стилі — сақтардың бейнелеу өнеріндегі ерекше бағыт, онда жануарлар бейнелері қолданылды. Оқушылар аң стилінің ерекшеліктерімен танысады.', 'Аң стилі дегеніміз не? Осы стильде салынған қандай бейнелерді білесің?', 'Что такое звериный стиль? Какие изображения в этом стиле ты знаешь?', 'Аң стилі дегеніміз не? Осы стильде салынған қандай бейнелерді білесің?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+аң+стилі'),
(44, 'Золотой человек', 'Золотой человек', 'Алтын адам', 'Алтын адам — б.з.б. V-IV ғасырлардағы сақ көсемінің киімі, Есік қорғанынан табылған. Ол Қазақстанның ұлттық символы. Оқушылар бұл жаңалықтың маңызын біледі.', 'Золотой человек — одежда сакского вождя V-IV вв. до н.э., найденная в Иссыкском кургане. Он является национальным символом Казахстана.', 'Алтын адам — б.з.б. V-IV ғасырлардағы сақ көсемінің киімі, Есік қорғанынан табылған. Ол Қазақстанның ұлттық символы. Оқушылар бұл жаңалықтың маңызын біледі.', 'Алтын адам қайдан табылды? Ол неліктен Қазақстанның символына айналды?', 'Где был найден Золотой человек? Почему он стал символом Казахстана?', 'Алтын адам қайдан табылды? Ол неліктен Қазақстанның символына айналды?', 'https://www.youtube.com/results?search_query=5+сынып+қазақстан+тарихы+алтын+адам');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(45, 'Первые люди', 'Первые люди', 'Алғашқы адамдар', 'Алғашқы адамдар шамамен 2,5 миллион жыл бұрын пайда болды. Оқушылар адамның эволюциясын, алғашқы еңбек құралдарын және отты игеруді біледі.', 'Первые люди появились около 2,5 миллионов лет назад. Учащиеся узнают об эволюции человека, первых орудиях труда и освоении огня.', 'Алғашқы адамдар шамамен 2,5 миллион жыл бұрын пайда болды. Оқушылар адамның эволюциясын, алғашқы еңбек құралдарын және отты игеруді біледі.', 'Алғашқы адамдардың еңбек құралдары қандай болды? Отты игеру олардың өмірін қалай өзгертті?', 'Какими были орудия труда первых людей? Как изменило их жизнь освоение огня?', 'Алғашқы адамдардың еңбек құралдары қандай болды? Отты игеру олардың өмірін қалай өзгертті?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+алғашқы+адамдар'),
(45, 'Первобытное общество', 'Первобытное общество', 'Алғашқы қауымдық қоғам', 'Алғашқы қауымдық қоғамда адамдар рулар мен тайпаларға бірігіп, ортақ шаруашылық жүргізді. Оқушылар алғашқы адамдардың қоғамдық құрылысын біледі.', 'В первобытном обществе люди объединялись в роды и племена, вели общее хозяйство. Учащиеся узнают общественное устройство первых людей.', 'Алғашқы қауымдық қоғамда адамдар рулар мен тайпаларға бірігіп, ортақ шаруашылық жүргізді. Оқушылар алғашқы адамдардың қоғамдық құрылысын біледі.', 'Рулық қоғам дегеніміз не? Алғашқы адамдар неге бірігіп өмір сүрді?', 'Что такое родовая община? Почему первые люди жили сообща?', 'Рулық қоғам дегеніміз не? Алғашқы адамдар неге бірігіп өмір сүрді?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+алғашқы+қауым');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(46, 'Древний Египет', 'Древний Египет', 'Ежелгі Египет', 'Ежелгі Египет — Ніл өзенінің бойында пайда болған өркениет. Египетті фараондар басқарды, пирамидалар мен иероглифтер сақталған. Оқушылар бұл мәдениеттің ерекшеліктерін біледі.', 'Древний Египет — цивилизация, возникшая на берегах Нила. Египтом правили фараоны, сохранились пирамиды и иероглифы.', 'Ежелгі Египет — Ніл өзенінің бойында пайда болған өркениет. Египетті фараондар басқарды, пирамидалар мен иероглифтер сақталған. Оқушылар бұл мәдениеттің ерекшеліктерін біледі.', 'Ежелгі Египеттің ең әйгілі ескерткіштері қандай? Фараон деген кім?', 'Какие самые известные памятники Древнего Египта? Кто такой фараон?', 'Ежелгі Египеттің ең әйгілі ескерткіштері қандай? Фараон деген кім?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+ежелгі+египет'),
(46, 'Древняя Месопотамия', 'Древняя Месопотамия', 'Ежелгі Месопотамия', 'Месопотамия — Тигр мен Евфрат өзендерінің аралығындағы ежелгі өркениет. Мұнда әлемдегі алғашқы жазу — сына жазуы пайда болды. Оқушылар бұл өркениетпен танысады.', 'Месопотамия — древняя цивилизация между реками Тигр и Евфрат. Здесь появилась первая в мире письменность — клинопись.', 'Месопотамия — Тигр мен Евфрат өзендерінің аралығындағы ежелгі өркениет. Мұнда әлемдегі алғашқы жазу — сына жазуы пайда болды. Оқушылар бұл өркениетпен танысады.', 'Сына жазуы дегеніміз не? Ол қай жерде және қалай пайда болды?', 'Что такое клинопись? Где и как она появилась?', 'Сына жазуы дегеніміз не? Ол қай жерде және қалай пайда болды?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+месопотамия'),
(46, 'Древняя Индия', 'Древняя Индия', 'Ежелгі Үндістан', 'Ежелгі Үндістан — Үнді өзенінің бойында пайда болған өркениет. Үнділер касталарға бөлінді, буддизм діні пайда болды. Оқушылар үнді мәдениетімен танысады.', 'Древняя Индия — цивилизация на берегах реки Инд. Индийцы делились на касты, здесь возник буддизм. Учащиеся знакомятся с индийской культурой.', 'Ежелгі Үндістан — Үнді өзенінің бойында пайда болған өркениет. Үнділер касталарға бөлінді, буддизм діні пайда болды. Оқушылар үнді мәдениетімен танысады.', 'Үндістандағы касталар жүйесі қалай құрылды? Буддизм дінінің негізін қалаушы кім?', 'Как была устроена кастовая система в Индии? Кто был основателем буддизма?', 'Үндістандағы касталар жүйесі қалай құрылды? Буддизм дінінің негізін қалаушы кім?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+ежелгі+үндістан'),
(46, 'Древний Китай', 'Древний Китай', 'Ежелгі Қытай', 'Ежелгі Қытай — Сары өзеннің бойындағы ежелгі өркениет. Қытайлықтар қағаз бен пышақты ойлап тапты, Ұлы Қытай қорғанын салды. Оқушылар қытай өркениетімен танысады.', 'Древний Китай — цивилизация на берегах Жёлтой реки. Китайцы изобрели бумагу и порох, построили Великую Китайскую стену.', 'Ежелгі Қытай — Сары өзеннің бойындағы ежелгі өркениет. Қытайлықтар қағаз бен пышақты ойлап тапты, Ұлы Қытай қорғанын салды. Оқушылар қытай өркениетімен танысады.', 'Қытайлықтар қандай өнертабыстар жасады? Ұлы Қытай қорғаны не үшін салынды?', 'Какие изобретения сделали китайцы? Для чего была построена Великая Китайская стена?', 'Қытайлықтар қандай өнертабыстар жасады? Ұлы Қытай қорғаны не үшін салынды?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+ежелгі+қытай'),
(46, 'Древняя Греция', 'Древняя Греция', 'Ежелгі Грекия', 'Ежелгі Грекия — Еуропа өркениетінің бесігі. Гректер демократияны, олимпиада ойындарын және театрды ойлап тапты. Оқушылар грек мәдениетімен танысады.', 'Древняя Греция — колыбель европейской цивилизации. Греки изобрели демократию, Олимпийские игры и театр.', 'Ежелгі Грекия — Еуропа өркениетінің бесігі. Гректер демократияны, олимпиада ойындарын және театрды ойлап тапты. Оқушылар грек мәдениетімен танысады.', 'Гректердің қандай өнертабыстарын білесің? Олимпиада ойындары қай жерде пайда болды?', 'Какие изобретения греков ты знаешь? Где возникли Олимпийские игры?', 'Гректердің қандай өнертабыстарын білесің? Олимпиада ойындары қай жерде пайда болды?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+ежелгі+грекия');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(47, 'Культурное наследие древних цивилизаций', 'Культурное наследие древних цивилизаций', 'Ежелгі өркениеттердің мәдени мұрасы', 'Ежелгі өркениеттер бізге бай мәдени мұра қалдырды: жазу, сәулет өнері, ғылым, дін. Оқушылар әр өркениеттің әлем мәдениетіне қосқан үлесін біледі.', 'Древние цивилизации оставили богатое культурное наследие: письменность, архитектуру, науку, религию. Учащиеся узнают вклад каждой цивилизации в мировую культуру.', 'Ежелгі өркениеттер бізге бай мәдени мұра қалдырды: жазу, сәулет өнері, ғылым, дін. Оқушылар әр өркениеттің әлем мәдениетіне қосқан үлесін біледі.', 'Қай ежелгі өркениеттің мәдени мұрасы саған көбірек ұнайды? Неліктен?', 'Какое культурное наследие древних цивилизаций тебе нравится больше всего? Почему?', 'Қай ежелгі өркениеттің мәдени мұрасы саған көбірек ұнайды? Неліктен?', 'https://www.youtube.com/results?search_query=5+сынып+дүниежүзі+тарихы+ежелгі+өркениет+мұрасы');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(48, 'Музыкальные жанры', 'Музыкальные жанры', 'Музыкалық жанрлар', 'Музыкалық жанрлар — ән, күй, опера, симфония, марш және т.б. Оқушылар музыкалық жанрлардың ерекшеліктерімен танысып, оларды ажыратуды үйренеді.', 'Музыкальные жанры — песня, кюй, опера, симфония, марш и др. Учащиеся знакомятся с особенностями жанров и учатся их различать.', 'Музыкалық жанрлар — ән, күй, опера, симфония, марш және т.б. Оқушылар музыкалық жанрлардың ерекшеліктерімен танысып, оларды ажыратуды үйренеді.', 'Музыкалық жанрлардың 5 түрін атап, әрқайсысына сипаттама бер.', 'Назови 5 видов музыкальных жанров и дай характеристику каждому.', 'Музыкалық жанрлардың 5 түрін атап, әрқайсысына сипаттама бер.', 'https://www.youtube.com/results?search_query=5+сынып+музыка+жанрлар'),
(48, 'Музыкальные инструменты', 'Музыкальные инструменты', 'Музыкалық аспаптар', 'Музыкалық аспаптар ішекті, үрмелі, ұрмалы және пернелі болып бөлінеді. Оқушылар қазақ ұлттық аспаптарымен (домбыра, қобыз, сырнай) және әлемдік аспаптармен танысады.', 'Музыкальные инструменты делятся на струнные, духовые, ударные и клавишные. Учащиеся знакомятся с казахскими инструментами (домбра, кобыз, сырнай) и мировыми.', 'Музыкалық аспаптар ішекті, үрмелі, ұрмалы және пернелі болып бөлінеді. Оқушылар қазақ ұлттық аспаптарымен (домбыра, қобыз, сырнай) және әлемдік аспаптармен танысады.', 'Қазақтың ұлттық музыкалық аспаптарын атап, олардың қай топқа жататынын айт.', 'Назови казахские национальные музыкальные инструменты и укажи, к какой группе они относятся.', 'Қазақтың ұлттық музыкалық аспаптарын атап, олардың қай топқа жататынын айт.', 'https://www.youtube.com/results?search_query=5+сынып+музыка+аспаптар+домбыра+қобыз');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(49, 'Вокальные навыки', 'Вокальные навыки', 'Ән айту дағдылары', 'Ән айту дағдылары — дұрыс тыныс алу, дыбысты дұрыс шығару, ырғақты сақтау. Оқушылар вокалдық жаттығуларды орындап, ән айту техникасын меңгереді.', 'Вокальные навыки — правильное дыхание, звукоизвлечение, соблюдение ритма. Учащиеся выполняют вокальные упражнения и осваивают технику пения.', 'Ән айту дағдылары — дұрыс тыныс алу, дыбысты дұрыс шығару, ырғақты сақтау. Оқушылар вокалдық жаттығуларды орындап, ән айту техникасын меңгереді.', 'Ән айту алдында қандай жаттығулар жасау керек? Дұрыс тыныс алу техникасын түсіндір.', 'Какие упражнения нужно делать перед пением? Объясни технику правильного дыхания.', 'Ән айту алдында қандай жаттығулар жасау керек? Дұрыс тыныс алу техникасын түсіндір.', 'https://www.youtube.com/results?search_query=5+сынып+музыка+вокал+жаттығулар'),
(50, 'Казахская народная музыка', 'Казахская народная музыка', 'Қазақ халық музыкасы', 'Қазақ халық музыкасы — ұлттық мәдениеттің айнасы. Оқушылар халық әндерінің (жайма, айтыс) және күйлердің ерекшеліктерімен танысады.', 'Казахская народная музыка — зеркало национальной культуры. Учащиеся знакомятся с особенностями народных песен (жайма, айтыс) и кюев.', 'Қазақ халық музыкасы — ұлттық мәдениеттің айнасы. Оқушылар халық әндерінің (жайма, айтыс) және күйлердің ерекшеліктерімен танысады.', 'Қазақ халық музыкасының қандай жанрларын білесің? Айтыс дегеніміз не?', 'Какие жанры казахской народной музыки ты знаешь? Что такое айтыс?', 'Қазақ халық музыкасының қандай жанрларын білесің? Айтыс дегеніміз не?', 'https://www.youtube.com/results?search_query=5+сынып+музыка+қазақ+халық+музыкасы'),
(50, 'Казахские кюи и кюйши', 'Казахские кюи и кюйши', 'Қазақ күйлері мен күйшілері', 'Күй — домбырада орындалатын дәстүрлі қазақ музыкалық шығармасы. Атақты күйшілер: Құрманғазы, Дәулеткерей, Дина Нұрпейісова. Оқушылар олардың шығармашылығын біледі.', 'Кюй — традиционное казахское музыкальное произведение на домбре. Известные кюйши: Курмангазы, Даулеткерей, Дина Нурпеисова.', 'Күй — домбырада орындалатын дәстүрлі қазақ музыкалық шығармасы. Атақты күйшілер: Құрманғазы, Дәулеткерей, Дина Нұрпейісова. Оқушылар олардың шығармашылығын біледі.', 'Қандай күйшілерді білесің? Құрманғазының ең әйгілі күйі қалай аталады?', 'Каких кюйши ты знаешь? Как называется самый известный кюй Курмангазы?', 'Қандай күйшілерді білесің? Құрманғазының ең әйгілі күйі қалай аталады?', 'https://www.youtube.com/results?search_query=5+сынып+музыка+күй+күйшілер'),
(50, 'Казахские композиторы', 'Казахские композиторы', 'Қазақ композиторлары', 'Қазақтың кәсіби композиторлары: Ақан сері, Біржан сал, Мұқан Төлебаев, Ғазиза Жұбанова. Оқушылар олардың өмірі мен шығармаларымен танысады.', 'Казахские профессиональные композиторы: Акан серы, Биржан сал, Мукан Тулебаев, Газиза Жубанова. Учащиеся знакомятся с их жизнью и творчеством.', 'Қазақтың кәсіби композиторлары: Ақан сері, Біржан сал, Мұқан Төлебаев, Ғазиза Жұбанова. Оқушылар олардың өмірі мен шығармаларымен танысады.', 'Қазақстанның Мемлекеттік Гимнінің авторлары кім? Қандай қазақ композиторларын білесің?', 'Кто авторы Государственного гимна Казахстана? Каких казахских композиторов ты знаешь?', 'Қазақстанның Мемлекеттік Гимнінің авторлары кім? Қандай қазақ композиторларын білесің?', 'https://www.youtube.com/results?search_query=5+сынып+музыка+қазақ+композиторлары'),
(51, 'Мировые композиторы', 'Мировые композиторы', 'Әлем композиторлары', 'Әлемге әйгілі композиторлар: Моцарт, Бетховен, Чайковский. Оқушылар олардың атақты шығармаларын тыңдап, музыкалық стильдерін ажыратуды үйренеді.', 'Всемирно известные композиторы: Моцарт, Бетховен, Чайковский. Учащиеся слушают их знаменитые произведения и учатся различать музыкальные стили.', 'Әлемге әйгілі композиторлар: Моцарт, Бетховен, Чайковский. Оқушылар олардың атақты шығармаларын тыңдап, музыкалық стильдерін ажыратуды үйренеді.', 'В.А. Моцарттың қандай шығармасын білесің? Бетховеннің ең әйгілі симфониясының нөмірі қандай?', 'Какое произведение В.А. Моцарта ты знаешь? Какой номер самой известной симфонии Бетховена?', 'В.А. Моцарттың қандай шығармасын білесің? Бетховеннің ең әйгілі симфониясының нөмірі қандай?', 'https://www.youtube.com/results?search_query=5+сынып+музыка+әлем+композиторлар'),
(52, 'Элементарные музыкальные понятия', 'Элементарные музыкальные понятия', 'Музыкалық қарапайым ұғымдар', 'Музыкалық сауаттылық: ноталар, ырғақ, әуен, динамика, темп. Оқушылар музыканың негізгі элементтерін үйренеді және ноталарды оқып, ырғақты қайталауды меңгереді.', 'Музыкальная грамота: ноты, ритм, мелодия, динамика, темп. Учащиеся изучают основные элементы музыки, учатся читать ноты и повторять ритм.', 'Музыкалық сауаттылық: ноталар, ырғақ, әуен, динамика, темп. Оқушылар музыканың негізгі элементтерін үйренеді және ноталарды оқып, ырғақты қайталауды меңгереді.', 'Ноталардың атауларын жаз. Форте және пиано дегеніміз не?', 'Напиши названия нот. Что означают форте и пиано?', 'Ноталардың атауларын жаз. Форте және пиано дегеніміз не?', 'https://www.youtube.com/results?search_query=5+сынып+музыка+ноталар+сауаттылық');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(53, 'Основы живописи', 'Основы живописи', 'Кескіндеме негіздері', 'Кескіндеме — бояулармен сурет салу өнері. Оқушылар кескіндеменің негізгі тәсілдерімен (акварель, гуашь) танысып, қарапайым пейзаждар мен натюрморттар салады.', 'Живопись — искусство рисования красками. Учащиеся знакомятся с основными техниками (акварель, гуашь), рисуют простые пейзажи и натюрморты.', 'Кескіндеме — бояулармен сурет салу өнері. Оқушылар кескіндеменің негізгі тәсілдерімен (акварель, гуашь) танысып, қарапайым пейзаждар мен натюрморттар салады.', 'Акварель бояуымен ''Күзгі орман'' пейзажын сал. Түс ауысуларын көрсетуге тырыс.', 'Нарисуй акварелью пейзаж ''Осенний лес''. Постарайся показать переходы цветов.', 'Акварель бояуымен ''Күзгі орман'' пейзажын сал. Түс ауысуларын көрсетуге тырыс.', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+кескіндеме+негіздері'),
(53, 'Техника рисования', 'Техника рисования', 'Сурет салу техникасы', 'Сурет салу техникасы — қарындашпен, көмірмен, пастельмен салу тәсілдері. Оқушылар штрихтау, көлеңке түсіру, композиция құруды үйренеді.', 'Техника рисования — способы рисования карандашом, углём, пастелью. Учащиеся учатся штриховке, наложению тени, построению композиции.', 'Сурет салу техникасы — қарындашпен, көмірмен, пастельмен салу тәсілдері. Оқушылар штрихтау, көлеңке түсіру, композиция құруды үйренеді.', 'Қарапайым қарындашпен вазаның суретін салып, көлеңке түсіру техникасын қолдан.', 'Нарисуй простым карандашом вазу, используя технику наложения тени.', 'Қарапайым қарындашпен вазаның суретін салып, көлеңке түсіру техникасын қолдан.', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+сурет+салу+техникасы'),
(53, 'Цвет и цветовая гармония', 'Цвет и цветовая гармония', 'Түс және түс үйлесімі', 'Түс үйлесімі — түстердің бір-бірімен үйлесуі. Оқушылар түс дөңгелегімен танысып, жылы және суық түстерді, негізгі және қосымша түстерді ажыратуды үйренеді.', 'Цветовая гармония — сочетание цветов друг с другом. Учащиеся знакомятся с цветовым кругом, учатся различать тёплые и холодные, основные и дополнительные цвета.', 'Түс үйлесімі — түстердің бір-бірімен үйлесуі. Оқушылар түс дөңгелегімен танысып, жылы және суық түстерді, негізгі және қосымша түстерді ажыратуды үйренеді.', 'Түс дөңгелегінен қарама-қарсы түстерді тап. Үш негізгі түсті ата.', 'Найди на цветовом круге противоположные цвета. Назови три основных цвета.', 'Түс дөңгелегінен қарама-қарсы түстерді тап. Үш негізгі түсті ата.', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+түс+үйлесімі');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(54, 'Национальные орнаменты', 'Национальные орнаменты', 'Ұлттық ою-өрнектер', 'Қазақ ұлттық ою-өрнектері — халықтың мәдениетінің көрінісі. Оқушылар ою-өрнектердің түрлерімен (зооморфтық, өсімдік, геометриялық) танысып, оларды салуды үйренеді.', 'Казахские национальные орнаменты — отражение культуры народа. Учащиеся знакомятся с видами орнаментов (зооморфные, растительные, геометрические) и учатся их рисовать.', 'Қазақ ұлттық ою-өрнектері — халықтың мәдениетінің көрінісі. Оқушылар ою-өрнектердің түрлерімен (зооморфтық, өсімдік, геометриялық) танысып, оларды салуды үйренеді.', 'Қазақ ою-өрнектерінің үш түрін салып, олардың атауларын жаз.', 'Нарисуй три вида казахских орнаментов и подпиши их названия.', 'Қазақ ою-өрнектерінің үш түрін салып, олардың атауларын жаз.', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+ұлттық+ою+өрнек'),
(54, 'Казахские ремесла', 'Казахские ремесла', 'Қазақтың қолөнері', 'Қазақтың қолөнері — киіз басу, кесте тігу, тері өңдеу, зергерлік. Оқушылар дәстүрлі қолөнер түрлерімен танысып, қарапайым бұйымдар жасауды үйренеді.', 'Казахские ремёсла — валяние, вышивка, обработка кожи, ювелирное дело. Учащиеся знакомятся с традиционными ремёслами и учатся изготавливать простые изделия.', 'Қазақтың қолөнері — киіз басу, кесте тігу, тері өңдеу, зергерлік. Оқушылар дәстүрлі қолөнер түрлерімен танысып, қарапайым бұйымдар жасауды үйренеді.', 'Қазақ қолөнерінің қандай түрлерін білесің? Киіз басу үшін қандай материал қажет?', 'Какие виды казахских ремёсел ты знаешь? Какой материал нужен для валяния?', 'Қазақ қолөнерінің қандай түрлерін білесің? Киіз басу үшін қандай материал қажет?', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+қазақ+қолөнері'),
(55, 'Работа с пластилином', 'Работа с пластилином', 'Пластилинмен жұмыс', 'Мүсіндеу — пластилиннен әртүрлі пішіндер жасау. Оқушылар пластилинмен жұмыс істеу техникасын меңгеріп, қарапайым мүсіндер мен фигуралар жасайды.', 'Лепка — создание различных форм из пластилина. Учащиеся осваивают технику работы с пластилином, создают простые скульптуры и фигуры.', 'Мүсіндеу — пластилиннен әртүрлі пішіндер жасау. Оқушылар пластилинмен жұмыс істеу техникасын меңгеріп, қарапайым мүсіндер мен фигуралар жасайды.', 'Пластилиннен жануардың (мысалы, аттың) мүсінін жаса. Дененің пропорциясын сақтауға тырыс.', 'Слепи из пластилина фигуру животного (например, лошади). Старайся соблюдать пропорции тела.', 'Пластилиннен жануардың (мысалы, аттың) мүсінін жаса. Дененің пропорциясын сақтауға тырыс.', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+пластилин+мүсіндеу'),
(56, 'Работа с бумагой', 'Работа с бумагой', 'Қағазбен жұмыс', 'Қағазбен жұмыс — аппликация, оригами, квиллинг. Оқушылар қағазды кесу, бүктеу, жапсыру арқылы әдемі бұйымдар жасауды үйренеді.', 'Работа с бумагой — аппликация, оригами, квиллинг. Учащиеся учатся создавать красивые изделия из бумаги с помощью вырезания, складывания и наклеивания.', 'Қағазбен жұмыс — аппликация, оригами, квиллинг. Оқушылар қағазды кесу, бүктеу, жапсыру арқылы әдемі бұйымдар жасауды үйренеді.', 'Түрлі-түсті қағаздан ''Қазақ даласы'' тақырыбында аппликация жаса.', 'Сделай из цветной бумаги аппликацию на тему ''Казахская степь''.', 'Түрлі-түсті қағаздан ''Қазақ даласы'' тақырыбында аппликация жаса.', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+қағаз+аппликация'),
(57, 'Интерьер и оформление', 'Интерьер и оформление', 'Интерьер және безендіру', 'Дизайн интерьера — бөлмені әдемі әрі ыңғайлы етіп безендіру. Оқушылар түс таңдау, жиһазды орналастыру, сәндік бұйымдарды қолдану принциптерімен танысады.', 'Дизайн интерьера — красивое и удобное оформление комнаты. Учащиеся знакомятся с принципами выбора цвета, расстановки мебели, использования декора.', 'Дизайн интерьера — бөлмені әдемі әрі ыңғайлы етіп безендіру. Оқушылар түс таңдау, жиһазды орналастыру, сәндік бұйымдарды қолдану принциптерімен танысады.', 'Өз бөлмеңнің дизайн жобасын қағазға сал: жиһазды қалай орналастырар едің?', 'Нарисуй на бумаге дизайн-проект своей комнаты: как бы ты расставил мебель?', 'Өз бөлмеңнің дизайн жобасын қағазға сал: жиһазды қалай орналастырар едің?', 'https://www.youtube.com/results?search_query=5+сынып+көркем+еңбек+дизайн+интерьер');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(58, 'Бег', 'Бег', 'Жүгіру', 'Жүгіру — жеңіл атлетиканың негізгі түрі. Оқушылар қысқа (30-60 м) және орта (300-600 м) қашықтыққа жүгіру техникасын, дұрыс дем алуды және мәреге жету тәсілдерін үйренеді.', 'Бег — основной вид лёгкой атлетики. Учащиеся осваивают технику бега на короткие (30-60 м) и средние (300-600 м) дистанции, правильное дыхание и финиширование.', 'Жүгіру — жеңіл атлетиканың негізгі түрі. Оқушылар қысқа (30-60 м) және орта (300-600 м) қашықтыққа жүгіру техникасын, дұрыс дем алуды және мәреге жету тәсілдерін үйренеді.', 'Қысқа қашықтыққа жүгіру кезінде қол мен аяқтың қозғалысы қандай болуы керек?', 'Как должны двигаться руки и ноги при беге на короткую дистанцию?', 'Қысқа қашықтыққа жүгіру кезінде қол мен аяқтың қозғалысы қандай болуы керек?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+жүгіру+техникасы'),
(58, 'Прыжки', 'Прыжки', 'Секіру', 'Секіру — алыстыққа және биіктікке секіру түрлері. Оқушылар секірудің дұрыс техникасын, серпілу мен қону ережелерін үйренеді.', 'Прыжки — виды прыжков в длину и высоту. Учащиеся изучают правильную технику прыжка, отталкивания и приземления.', 'Секіру — алыстыққа және биіктікке секіру түрлері. Оқушылар секірудің дұрыс техникасын, серпілу мен қону ережелерін үйренеді.', 'Алыстыққа секіру кезінде серпілу қай аяқпен жасалады? Қону кезінде неге назар аудару керек?', 'С какой ноги выполняется отталкивание при прыжке в длину? На что обратить внимание при приземлении?', 'Алыстыққа секіру кезінде серпілу қай аяқпен жасалады? Қону кезінде неге назар аудару керек?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+секіру'),
(58, 'Метание', 'Метание', 'Лақтыру', 'Лақтыру — допты немесе арнайы снарядты қашықтыққа лақтыру. Оқушылар допты дұрыс ұстау, бұлғау және лақтыру техникасын үйренеді.', 'Метание — бросание мяча или специального снаряда на дальность. Учащиеся осваивают правильный захват, замах и технику броска.', 'Лақтыру — допты немесе арнайы снарядты қашықтыққа лақтыру. Оқушылар допты дұрыс ұстау, бұлғау және лақтыру техникасын үйренеді.', 'Допты лақтыру кезінде дене қалпы қандай болуы керек? Лақтыру қай бағытта жасалады?', 'Каким должно быть положение тела при метании мяча? В каком направлении выполняется бросок?', 'Допты лақтыру кезінде дене қалпы қандай болуы керек? Лақтыру қай бағытта жасалады?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+доп+лақтыру');
INSERT INTO topics (theme_id, title, title_ru, title_kk, summary, summary_ru, summary_kk, examples, examples_ru, examples_kk, youtube_url) VALUES
(59, 'Акробатические упражнения', 'Акробатические упражнения', 'Акробатикалық жаттығулар', 'Акробатикалық жаттығулар: аударылу, түрегеп тұру, дөңгелену. Оқушылар қарапайым акробатикалық элементтерді қауіпсіздік ережелерін сақтай отырып орындауды үйренеді.', 'Акробатические упражнения: кувырки, стойки, перекаты. Учащиеся учатся выполнять простые акробатические элементы с соблюдением правил безопасности.', 'Акробатикалық жаттығулар: аударылу, түрегеп тұру, дөңгелену. Оқушылар қарапайым акробатикалық элементтерді қауіпсіздік ережелерін сақтай отырып орындауды үйренеді.', 'Аударылу жаттығуын орындау кезінде қандай қауіпсіздік ережелерін сақтау керек?', 'Какие правила безопасности нужно соблюдать при выполнении кувырка?', 'Аударылу жаттығуын орындау кезінде қандай қауіпсіздік ережелерін сақтау керек?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+акробатика'),
(59, 'Строевые упражнения', 'Строевые упражнения', 'Саптық жаттығулар', 'Саптық жаттығулар — сапқа тұру, бұрылу, қайта құрылу. Оқушылар дене шынықтыру сабағындағы тәртіп пен ұйымшылдықты сақтауға үйренеді.', 'Строевые упражнения — построение, повороты, перестроение. Учащиеся учатся соблюдать порядок и организованность на уроке физкультуры.', 'Саптық жаттығулар — сапқа тұру, бұрылу, қайта құрылу. Оқушылар дене шынықтыру сабағындағы тәртіп пен ұйымшылдықты сақтауға үйренеді.', 'Оңға! бұйрығы бойынша қандай әрекет жасалады? Саптағы қашықтық қандай болуы керек?', 'Какое действие выполняется по команде ''Направо!''? Каким должно быть расстояние в строю?', 'Оңға! бұйрығы бойынша қандай әрекет жасалады? Саптағы қашықтық қандай болуы керек?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+саптық+жаттығу'),
(60, 'Баскетбол', 'Баскетбол', 'Баскетбол', 'Баскетбол — допты себетке салу арқылы ойналатын командалық ойын. Оқушылар допты алып жүру, пас беру және себетке лақтыру техникасын үйренеді.', 'Баскетбол — командная игра, в которой мяч забрасывают в корзину. Учащиеся осваивают ведение мяча, передачу и бросок в корзину.', 'Баскетбол — допты себетке салу арқылы ойналатын командалық ойын. Оқушылар допты алып жүру, пас беру және себетке лақтыру техникасын үйренеді.', 'Баскетболда допты неше қадам алып жүруге болады? Себетке лақтыру қандай тәсілдермен орындалады?', 'Сколько шагов можно делать с мячом в баскетболе? Какими способами выполняется бросок в корзину?', 'Баскетболда допты неше қадам алып жүруге болады? Себетке лақтыру қандай тәсілдермен орындалады?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+баскетбол'),
(60, 'Волейбол', 'Волейбол', 'Волейбол', 'Волейбол — допты қолмен тор үстінен лақтыратын командалық ойын. Оқушылар допты қабылдау, пас беру және соғу техникасын үйренеді.', 'Волейбол — командная игра с мячом через сетку. Учащиеся осваивают приём мяча, передачу и нападающий удар.', 'Волейбол — допты қолмен тор үстінен лақтыратын командалық ойын. Оқушылар допты қабылдау, пас беру және соғу техникасын үйренеді.', 'Волейболда допты неше рет ұстауға рұқсат етіледі? Ойында қандай негізгі ережелер бар?', 'Сколько касаний мяча разрешено в волейболе? Какие основные правила игры?', 'Волейболда допты неше рет ұстауға рұқсат етіледі? Ойында қандай негізгі ережелер бар?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+волейбол'),
(60, 'Футбол', 'Футбол', 'Футбол', 'Футбол — допты аяқпен қақпаға салу арқылы ойналатын спорттық ойын. Оқушылар допты тебу, беру және тоқтату техникасын үйренеді.', 'Футбол — спортивная игра, в которой мяч забивают в ворота ногой. Учащиеся осваивают технику удара, передачи и остановки мяча.', 'Футбол — допты аяқпен қақпаға салу арқылы ойналатын спорттық ойын. Оқушылар допты тебу, беру және тоқтату техникасын үйренеді.', 'Футболда қақпаға допты қай аяқпен тебу ыңғайлы? Ойында неше ойыншы бар?', 'Какой ногой удобнее бить по воротам в футболе? Сколько игроков в команде?', 'Футболда қақпаға допты қай аяқпен тебу ыңғайлы? Ойында неше ойыншы бар?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+футбол'),
(61, 'Казахские национальные игры', 'Казахские национальные игры', 'Қазақ ұлттық ойындары', 'Қазақ ұлттық ойындары — халықтың спорттық дәстүрлері. Оқушылар бәйге, көкпар, тоғызқұмалақ, асық сияқты ойындардың ережелерімен танысады.', 'Казахские национальные игры — спортивные традиции народа. Учащиеся знакомятся с правилами игр: байга, кокпар, тогызкумалак, асык.', 'Қазақ ұлттық ойындары — халықтың спорттық дәстүрлері. Оқушылар бәйге, көкпар, тоғызқұмалақ, асық сияқты ойындардың ережелерімен танысады.', 'Қандай қазақ ұлттық ойындарын білесің? Бәйге ойынының ережесін түсіндір.', 'Какие казахские национальные игры ты знаешь? Объясни правила игры байга.', 'Қандай қазақ ұлттық ойындарын білесің? Бәйге ойынының ережесін түсіндір.', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+ұлттық+ойындар'),
(62, 'Быстрота, сила, выносливость', 'Быстрота, сила, выносливость', 'Жылдамдық, күш, төзімділік', 'Дене сапасын дамыту — жылдамдық, күш, төзімділік, икемділік және ептілік. Оқушылар осы қасиеттерді дамытатын жаттығулар кешенін орындайды.', 'Развитие физических качеств — быстрота, сила, выносливость, гибкость и ловкость. Учащиеся выполняют комплексы упражнений для развития этих качеств.', 'Дене сапасын дамыту — жылдамдық, күш, төзімділік, икемділік және ептілік. Оқушылар осы қасиеттерді дамытатын жаттығулар кешенін орындайды.', 'Күшті дамытуға арналған 3 жаттығу ата. Төзімділікті қалай дамытуға болады?', 'Назови 3 упражнения для развития силы. Как можно развить выносливость?', 'Күшті дамытуға арналған 3 жаттығу ата. Төзімділікті қалай дамытуға болады?', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+дене+сапасы'),
(63, 'Правила безопасности. ОБЖ', 'Правила безопасности. ОБЖ', 'Қауіпсіздік ережелері. ҚБЖ негіздері', 'Қауіпсіздік ережелері — дене шынықтыру сабағында жарақаттан сақтанудың басты шарты. Оқушылар спорттық жабдықтарды қолдану ережелерімен және сабақтағы тәртіппен танысады.', 'Правила безопасности — главное условие предотвращения травм на уроке физкультуры. Учащиеся знакомятся с правилами использования спортивного инвентаря и поведения на уроке.', 'Қауіпсіздік ережелері — дене шынықтыру сабағында жарақаттан сақтанудың басты шарты. Оқушылар спорттық жабдықтарды қолдану ережелерімен және сабақтағы тәртіппен танысады.', 'Дене шынықтыру сабағында қандай қауіпсіздік ережелерін сақтау керек? 5 ереже жаз.', 'Какие правила безопасности нужно соблюдать на уроке физкультуры? Напиши 5 правил.', 'Дене шынықтыру сабағында қандай қауіпсіздік ережелерін сақтау керек? 5 ереже жаз.', 'https://www.youtube.com/results?search_query=5+сынып+дене+шынықтыру+қауіпсіздік+ережелері');
